"use client";

import React, { useState } from 'react';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { DownloadButton } from '@/components/tools/DownloadButton';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { PageThumbnail } from '@/components/tools/PageThumbnail';
import { pdfjsLib } from '@/lib/pdfjsSetup';
import { loadPdfDocument } from '@/lib/pdf/pdfRenderHelpers';
import { compressPDF } from '@/lib/pdf/pdfHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { readPdfFile } from '@/lib/pdf/readPdfFile';
import { formatFileSize } from '@/lib/fileHelpers';
import { FileText, Percent, AlertCircle, Eye, EyeOff } from 'lucide-react';

export function CompressPdfClient() {
  const [file, setFile] = useState<File | null>(null);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [resultPdfDoc, setResultPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [result, setResult] = useState<{ url: string; originalSize: number; newSize: number } | null>(null);
  const [showPreview, setShowPreview] = useState(true);

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setResult(null);
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    try {
      const buffer = await readPdfFile(selectedFile);
      const isProtected = await checkPdfPasswordProtected(buffer.slice(0));
      if (isProtected) {
        setError('This PDF may be encrypted or password-protected. Please upload an unlocked PDF.');
        return;
      }
      setFile(selectedFile);
      const doc = await loadPdfDocument(selectedFile);
      setPdfDoc(doc);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    }
  };

  const handleCompress = async () => {
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    setResult(null);

    try {
      const compressedBytes = await compressPDF(file);
      const blob = new Blob([compressedBytes.buffer as ArrayBuffer], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const resDoc = await loadPdfDocument(new File([blob], 'compressed.pdf', { type: 'application/pdf' }));
      setResultPdfDoc(resDoc);
      setResult({
        url,
        originalSize: file.size,
        newSize: blob.size
      });
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setPdfDoc(null);
    setResultPdfDoc(null);
    setResult(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Click 'Select PDF' or drag and drop your PDF file into the uploader.",
        "Review the visual preview to compare the original and compressed document structure.",
        "Click 'Compress PDF' to securely reduce the file size within your browser.",
        "Download the optimized, smaller PDF file instantly."
]}
      faqs={[
        {
                "question": "Will compressing my PDF reduce its visual quality?",
                "answer": "Our compression engine optimizes the internal structure and image streams carefully to minimize file size while maintaining excellent visual fidelity."
        },
        {
                "question": "Is my PDF uploaded to any server?",
                "answer": "No, all compression happens locally on your device, ensuring complete data privacy and security."
        }
]}
      
      title="Compress PDF"
      description="Optimize and shrink PDF files to reduce file size in the browser. Processed securely and locally on your device."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to compress"
          subtitle="Choose the PDF document you want to optimize"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm max-w-2xl mx-auto">
          {/* File Header */}
          <div className="flex items-center gap-4 pb-6 border-b border-border mb-6">
            <div className="p-3 bg-primary/10 text-primary rounded-lg">
              <FileText className="w-6 h-6" />
            </div>
            <div className="flex-1 min-w-0">
              <h4 className="font-sans font-bold text-base text-ink truncate">{file.name}</h4>
              <p className="font-sans text-[13px] text-slate mt-0.5">
                Original Size: {formatFileSize(file.size)}
              </p>
            </div>
          </div>

          {/* Compression Note warning */}
          <div className="p-4 bg-yellow-500/5 border border-yellow-500/10 rounded-lg text-yellow-600 dark:text-yellow-500 text-[13px] flex gap-3 mb-8">
            <AlertCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
            <p className="font-sans leading-relaxed font-medium">
              Note: Deep compression depends heavily on the PDF structure. Images inside the PDF are structurally preserved to avoid quality loss.
            </p>
          </div>

          <div className="flex justify-between items-center mb-4">
            <h3 className="font-display font-bold text-[14px] text-ink">Visual Preview</h3>
            <button
              onClick={() => setShowPreview(!showPreview)}
              className="text-[12px] font-sans font-medium text-slate flex items-center gap-1.5 hover:text-ink transition-colors"
            >
              {showPreview ? <><EyeOff className="w-4 h-4" /> Hide Preview</> : <><Eye className="w-4 h-4" /> Show Preview</>}
            </button>
          </div>

          {showPreview && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8 bg-background border border-border rounded-xl p-6">
              {/* Original Preview */}
              <div className="flex flex-col items-center">
                <span className="text-[11px] font-sans font-bold text-slate uppercase tracking-wider mb-3">Original</span>
                <div className="border border-border/50 shadow-sm bg-white p-1 rounded min-h-[300px] flex items-center justify-center">
                  {pdfDoc ? (
                    <PageThumbnail pdfDoc={pdfDoc} pageNumber={1} scale={0.5} />
                  ) : (
                    <span className="text-[12px] text-slate">Loading preview...</span>
                  )}
                </div>
              </div>

              {/* Compressed Preview */}
              <div className="flex flex-col items-center">
                <span className="text-[11px] font-sans font-bold text-slate uppercase tracking-wider mb-3">Compressed</span>
                <div className="border border-border/50 shadow-sm bg-white p-1 rounded min-h-[300px] flex items-center justify-center">
                  {resultPdfDoc ? (
                    <PageThumbnail pdfDoc={resultPdfDoc} pageNumber={1} scale={0.5} />
                  ) : isProcessing ? (
                    <div className="flex flex-col items-center justify-center gap-2">
                      <LoadingSpinner text="" />
                    </div>
                  ) : (
                    <span className="text-[12px] text-slate">Ready to compress</span>
                  )}
                </div>
              </div>
            </div>
          )}

          {isProcessing && <LoadingSpinner text="Optimizing PDF structure..." />}

          {/* Result Stats */}
          {result && (
            <div className="space-y-6 mb-8 animate-in fade-in duration-200">
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-background border border-border rounded-lg text-center">
                  <p className="text-[11px] font-sans text-slate uppercase tracking-wider font-semibold">Original Size</p>
                  <p className="font-mono text-lg font-bold text-ink mt-1">{formatFileSize(result.originalSize)}</p>
                </div>
                <div className="p-4 bg-primary/5 border border-primary/20 rounded-lg text-center relative">
                  <p className="text-[11px] font-sans text-primary uppercase tracking-wider font-semibold">Compressed Size</p>
                  <p className="font-mono text-lg font-bold text-primary mt-1">{formatFileSize(result.newSize)}</p>
                  {result.newSize < result.originalSize && (
                    <span className="absolute top-2 right-2 bg-primary/20 text-primary text-[10px] font-bold px-1.5 py-0.5 rounded-md">
                      -{Math.round((1 - result.newSize / result.originalSize) * 100)}%
                    </span>
                  )}
                </div>
              </div>

              <div className="p-6 bg-primary/5 border border-primary/20 rounded-xl flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                  <h4 className="font-display font-bold text-base text-ink">Optimized PDF Ready!</h4>
                  <p className="font-sans text-[12px] text-slate mt-0.5">
                    Click the button below to download the compressed file.
                  </p>
                </div>
                <DownloadButton href={result.url} download={`singulariti_${file.name.replace(/\.[^/.]+$/, "")}_compressed.pdf`}>
                  Download Compressed PDF
                </DownloadButton>
              </div>
            </div>
          )}

          {/* Action buttons */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Reset
            </Button>
            <Button
              variant="primary"
              size="lg"
              onClick={handleCompress}
              disabled={isProcessing}
            >
              Compress PDF
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState } from 'react';
import { pdfjsLib } from '@/lib/pdfjsSetup';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { DownloadButton } from '@/components/tools/DownloadButton';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { PageThumbnail } from '@/components/tools/PageThumbnail';
import { deletePDFPages } from '@/lib/pdf/pdfHelpers';
import { loadPdfDocument } from '@/lib/pdf/pdfRenderHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { readPdfFile } from '@/lib/pdf/readPdfFile';
import { formatFileSize } from '@/lib/fileHelpers';
import { FileText, Trash2, CheckCircle2 } from 'lucide-react';

export function DeletePdfPagesClient() {
  const [file, setFile] = useState<File | null>(null);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [deletedPages, setDeletedPages] = useState<Set<number>>(new Set());
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [resultBlobUrl, setResultBlobUrl] = useState<string | null>(null);

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setResultBlobUrl(null);
    setDeletedPages(new Set());
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    try {
      const buffer = await readPdfFile(selectedFile);
      const isProtected = await checkPdfPasswordProtected(buffer.slice(0));
      if (isProtected) {
        setError('This PDF may be encrypted or password-protected. Please upload an unlocked PDF.');
        return;
      }

      setFile(selectedFile);
      const doc = await loadPdfDocument(selectedFile);
      setPdfDoc(doc);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    }
  };

  const togglePageDeletion = (pageNum: number) => {
    setDeletedPages(prev => {
      const next = new Set(prev);
      if (next.has(pageNum)) {
        next.delete(pageNum);
      } else {
        next.add(pageNum);
      }
      return next;
    });
    setResultBlobUrl(null);
  };

  const handleDelete = async () => {
    if (!file || !pdfDoc) return;
    if (deletedPages.size === 0) {
      setError('Please select at least one page to delete.');
      return;
    }
    if (deletedPages.size >= pdfDoc.numPages) {
      setError('You cannot delete all pages. At least 1 page must remain.');
      return;
    }

    setIsProcessing(true);
    setError(null);
    setResultBlobUrl(null);

    try {
      const pagesArray = Array.from(deletedPages);
      const bytes = await deletePDFPages(file, pagesArray);
      const blob = new Blob([bytes.buffer as ArrayBuffer], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      setResultBlobUrl(url);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setPdfDoc(null);
    setDeletedPages(new Set());
    setResultBlobUrl(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload your PDF document to the tool.",
        "View all pages as thumbnails and select the ones you wish to delete.",
        "Click 'Delete Selected Pages' to remove them.",
        "Download your newly modified PDF."
]}
      faqs={[
        {
                "question": "Can I delete multiple pages at once?",
                "answer": "Yes, you can click on multiple page thumbnails to select and delete them in one go."
        },
        {
                "question": "Are my files secure?",
                "answer": "Yes, the deletion process runs entirely in your browser. No data is sent to external servers."
        }
]}
      
      title="Delete PDF Pages"
      description="Remove unwanted pages from a PDF document. Select pages to discard and download a new compiled file."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to edit"
          subtitle="Choose the PDF document you want to remove pages from"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-6 border-b border-border mb-6">
            <div className="flex items-center gap-3 min-w-0">
              <div className="p-3 bg-primary/10 text-primary rounded-lg">
                <FileText className="w-6 h-6" />
              </div>
              <div className="min-w-0">
                <h4 className="font-sans font-bold text-base text-ink truncate">{file.name}</h4>
                <p className="font-sans text-[13px] text-slate mt-0.5">
                  {formatFileSize(file.size)} • {pdfDoc?.numPages} pages ({deletedPages.size} marked for deletion)
                </p>
              </div>
            </div>
            <div className="flex gap-2">
              <Button variant="ghost" size="sm" onClick={handleReset}>
                Change File
              </Button>
            </div>
          </div>

          {/* Grid Selection */}
          {pdfDoc && (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6 max-h-[500px] overflow-y-auto p-2 mb-8 bg-background/50 rounded-xl border border-border">
              {Array.from({ length: pdfDoc.numPages }, (_, i) => i + 1).map((pageNum) => {
                const isMarked = deletedPages.has(pageNum);
                return (
                  <div key={pageNum} className="flex flex-col items-center">
                    <div
                      onClick={() => togglePageDeletion(pageNum)}
                      className={`relative group w-full aspect-[3/4] bg-background border rounded-lg overflow-hidden cursor-pointer transition-all flex items-center justify-center p-2 ${
                        isMarked
                          ? 'border-red-500 shadow-md ring-2 ring-red-500/20'
                          : 'border-border hover:border-slate hover:shadow-xs'
                      }`}
                    >
                      <PageThumbnail
                        pdfDoc={pdfDoc}
                        pageNumber={pageNum}
                        scale={0.25}
                        className={isMarked ? 'opacity-40 filter grayscale' : 'transition-opacity duration-200'}
                      />
                      
                      {/* Selection Indicator overlay */}
                      <div className="absolute inset-0 flex items-center justify-center">
                        {isMarked ? (
                          <div className="bg-red-500 text-surface p-2 rounded-full shadow-lg scale-110">
                            <Trash2 className="w-5 h-5" />
                          </div>
                        ) : (
                          <div className="absolute top-2 right-2 bg-slate/60 text-surface opacity-0 group-hover:opacity-100 p-1 rounded-full shadow-xs transition-opacity">
                            <Trash2 className="w-3.5 h-3.5" />
                          </div>
                        )}
                      </div>
                    </div>
                    <span className={`font-sans text-[12px] font-semibold mt-2 ${isMarked ? 'text-red-500 line-through' : 'text-slate'}`}>
                      Page {pageNum}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          {isProcessing && <LoadingSpinner text="Removing selected pages..." />}

          {/* Download split result */}
          {resultBlobUrl && (
            <div className="p-6 bg-primary/5 border border-primary/20 rounded-xl mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in fade-in duration-200">
              <div>
                <h4 className="font-display font-bold text-base text-ink">New Document Ready!</h4>
                <p className="font-sans text-[12px] text-slate mt-0.5">
                  Your PDF was re-compiled successfully. Click the button to download.
                </p>
              </div>
              <DownloadButton href={resultBlobUrl} download={`singulariti_${file.name.replace(/\.[^/.]+$/, "")}_edited.pdf`}>
                Download Edited PDF
              </DownloadButton>
            </div>
          )}

          {/* Control bar */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Reset
            </Button>
            <Button
              variant="primary"
              size="lg"
              onClick={handleDelete}
              disabled={isProcessing || deletedPages.size === 0}
              className={deletedPages.size > 0 ? 'bg-red-500 text-surface hover:bg-red-600' : ''}
              leftIcon={<Trash2 className="w-4 h-4" />}
            >
              Delete Selected Pages
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState } from 'react';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { DownloadButton } from '@/components/tools/DownloadButton';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { mergePDFs, countPDFPages } from '@/lib/pdf/pdfHelpers';
import { downloadBlob } from '@/lib/downloadHelpers';
import { formatFileSize } from '@/lib/fileHelpers';
import { ArrowUp, ArrowDown, Trash2, Plus, FileText } from 'lucide-react';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';

export function MergePdfClient() {
  const [files, setFiles] = useState<File[]>([]);
  const [pageCounts, setPageCounts] = useState<Record<string, number>>({});
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [mergedBlobUrl, setMergedBlobUrl] = useState<string | null>(null);

  const handleFilesSelected = async (selectedFiles: File[]) => {
    setError(null);
    setMergedBlobUrl(null);
    
    // Check for validation and password protection
    const validFiles: File[] = [];
    for (const file of selectedFiles) {
      const validation = validatePdfFile(file);
      if (!validation.isValid) {
        setError(validation.error || `Invalid PDF file: ${file.name}`);
        return;
      }
      try {
        const buffer = await file.arrayBuffer();
        const isProtected = await checkPdfPasswordProtected(buffer);
        if (isProtected) {
          setError(`File "${file.name}": This PDF is encrypted or password-protected. Please upload an unlocked PDF.`);
          return;
        }
        validFiles.push(file);
      } catch (err: any) {
        setError(`File "${file.name}": ${getPdfErrorMessage(err)}`);
        return;
      }
    }

    const updatedFiles = [...files, ...validFiles];
    setFiles(updatedFiles);

    // Set or clear warning based on the updated queue
    const largeFile = updatedFiles.find(f => f.size > 100 * 1024 * 1024);
    if (largeFile) {
      setWarning(`Large file warning: File "${largeFile.name}" is ${(largeFile.size / (1024 * 1024)).toFixed(1)}MB. Processing files between 100MB and 1GB entirely in the browser is supported, but may cause the page to lag or run out of memory depending on your computer's RAM. Keep other tabs closed for best performance.`);
    } else {
      setWarning(null);
    }

    // Load page counts
    try {
      const { counts } = await countPDFPages(validFiles);
      setPageCounts(prev => {
        const next = { ...prev };
        counts.forEach(c => {
          next[c.fileName] = c.pages;
        });
        return next;
      });
    } catch (err) {
      console.error(err);
    }
  };

  const moveFile = (index: number, direction: 'up' | 'down') => {
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= files.length) return;
    
    const updated = [...files];
    const temp = updated[index];
    updated[index] = updated[targetIndex];
    updated[targetIndex] = temp;
    setFiles(updated);
    setMergedBlobUrl(null);
  };

  const removeFile = (index: number) => {
    const updated = files.filter((_, i) => i !== index);
    setFiles(updated);
    setMergedBlobUrl(null);

    // Set or clear warning based on remaining files in the queue
    const largeFile = updated.find(f => f.size > 100 * 1024 * 1024);
    if (largeFile) {
      setWarning(`Large file warning: File "${largeFile.name}" is ${(largeFile.size / (1024 * 1024)).toFixed(1)}MB. Processing files between 100MB and 1GB entirely in the browser is supported, but may cause the page to lag or run out of memory depending on your computer's RAM. Keep other tabs closed for best performance.`);
    } else {
      setWarning(null);
    }
  };

  const handleMerge = async () => {
    if (files.length < 2) {
      setError('Please upload at least 2 PDF files to merge.');
      return;
    }

    setIsProcessing(true);
    setError(null);

    try {
      const mergedBytes = await mergePDFs(files);
      const blob = new Blob([mergedBytes.buffer as ArrayBuffer], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      setMergedBlobUrl(url);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFiles([]);
    setPageCounts({});
    setMergedBlobUrl(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload two or more PDF files you want to combine.",
        "Drag and drop the files in the list to set your preferred order.",
        "Click 'Merge PDFs' to join them together.",
        "Download the combined PDF document."
]}
      faqs={[
        {
                "question": "Is there a file size limit for merging?",
                "answer": "There are no strict size limits since processing is local, though very large files may depend on your device's RAM."
        },
        {
                "question": "Are bookmarks and links preserved?",
                "answer": "Basic structure is preserved, but complex interactive elements like bookmarks may be reset during the merge."
        }
]}
      
      title="Merge PDF"
      description="Combine multiple PDF files into one single PDF document online. Safe, secure, and processed completely inside your browser."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {files.length === 0 ? (
        <FileUploader
          onFilesSelected={handleFilesSelected}
          multiple={true}
          title="Upload PDF files to merge"
          subtitle="Select two or more PDF documents from your device"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          <div className="flex flex-wrap items-center justify-between gap-4 mb-6 pb-4 border-b border-border">
            <div>
              <h3 className="font-display font-bold text-lg text-ink">Merge Queue</h3>
              <p className="font-sans text-[13px] text-slate mt-0.5">
                {files.length} file{files.length > 1 ? 's' : ''} loaded. Drag or use arrows to rearrange order.
              </p>
            </div>
            <div className="flex gap-2">
              <input
                type="file"
                id="add-more-pdf"
                multiple
                accept=".pdf"
                className="hidden"
                onChange={(e) => {
                  if (e.target.files) handleFilesSelected(Array.from(e.target.files));
                }}
              />
              <Button
                variant="outline"
                size="sm"
                leftIcon={<Plus className="w-4 h-4" />}
                onClick={() => document.getElementById('add-more-pdf')?.click()}
              >
                Add More
              </Button>
              <Button variant="ghost" size="sm" onClick={handleReset}>
                Clear All
              </Button>
            </div>
          </div>

          {/* File Queue List */}
          <div className="space-y-3 mb-8">
            {files.map((file, idx) => (
              <div
                key={`${file.name}-${idx}`}
                className="flex items-center gap-4 p-4 bg-background border border-border rounded-lg group hover:border-slate transition-colors"
              >
                <div className="p-2 bg-primary/10 text-primary rounded-md">
                  <FileText className="w-5 h-5" />
                </div>
                
                <div className="flex-1 min-w-0">
                  <h4 className="font-sans font-bold text-sm text-ink truncate">{file.name}</h4>
                  <p className="font-sans text-[12px] text-slate mt-0.5">
                    {formatFileSize(file.size)} • {pageCounts[file.name] !== undefined ? `${pageCounts[file.name]} page${pageCounts[file.name] > 1 ? 's' : ''}` : 'Loading...'}
                  </p>
                </div>

                <div className="flex items-center gap-1">
                  <button
                    onClick={() => moveFile(idx, 'up')}
                    disabled={idx === 0}
                    className="p-1.5 rounded hover:bg-slate/10 text-slate disabled:opacity-30 disabled:pointer-events-none transition-colors"
                    title="Move Up"
                  >
                    <ArrowUp className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => moveFile(idx, 'down')}
                    disabled={idx === files.length - 1}
                    className="p-1.5 rounded hover:bg-slate/10 text-slate disabled:opacity-30 disabled:pointer-events-none transition-colors"
                    title="Move Down"
                  >
                    <ArrowDown className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => removeFile(idx)}
                    className="p-1.5 rounded hover:bg-red-500/10 text-slate hover:text-red-500 transition-colors ml-1"
                    title="Remove"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))}
          </div>

          {/* Processing Indicator */}
          {isProcessing && <LoadingSpinner text="Merging PDF documents..." />}

          {/* Result Action Area */}
          {mergedBlobUrl && (
            <div className="p-6 bg-primary/5 border border-primary/20 rounded-xl mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in fade-in duration-200">
              <div>
                <h4 className="font-display font-bold text-base text-ink">Merged Document Ready!</h4>
                <p className="font-sans text-[12px] text-slate mt-0.5">
                  Your merged PDF has been compiled successfully. Click the button to download.
                </p>
              </div>
              <DownloadButton href={mergedBlobUrl} download="singulariti_merged.pdf">
                Download Merged PDF
              </DownloadButton>
            </div>
          )}

          {/* Merge Actions */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Reset
            </Button>
            <Button
              variant="primary"
              size="lg"
              onClick={handleMerge}
              disabled={files.length < 2 || isProcessing}
            >
              Merge PDFs
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState } from 'react';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { viewPDFMetadata, PDFMetadata } from '@/lib/pdf/pdfHelpers';
import { formatFileSize } from '@/lib/fileHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { FileText, Eye, Info } from 'lucide-react';

export function MetadataViewerClient() {
  const [file, setFile] = useState<File | null>(null);
  const [metadata, setMetadata] = useState<PDFMetadata | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setMetadata(null);
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    setFile(selectedFile);
    setIsProcessing(true);

    try {
      const buffer = await selectedFile.arrayBuffer();
      const isProtected = await checkPdfPasswordProtected(buffer);
      if (isProtected) {
        setError('This PDF is encrypted or password-protected. Please upload an unlocked PDF.');
        setIsProcessing(false);
        return;
      }
      const data = await viewPDFMetadata(selectedFile);
      setMetadata(data);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setMetadata(null);
    setError(null);
    setWarning(null);
  };

  // Helper to format key strings
  const formatKeyLabel = (key: string) => {
    const labels: Record<string, string> = {
      fileName: 'File Name',
      fileSize: 'File Size',
      totalPages: 'Total Pages',
      title: 'Title',
      author: 'Author',
      subject: 'Subject',
      keywords: 'Keywords',
      creator: 'Creator / Application',
      producer: 'PDF Producer',
      creationDate: 'Creation Date',
      modificationDate: 'Modification Date'
    };
    return labels[key] || key;
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload a PDF file to analyze its metadata.",
        "The tool will instantly read and display hidden information like Author, Creator, Producer, and Dates.",
        "Review the extracted information securely on your screen.",
        "No download is needed as this is a viewing tool."
]}
      faqs={[
        {
                "question": "What kind of metadata does this tool reveal?",
                "answer": "It reveals standard document properties including title, author, subject, creation date, modification date, and the software used to create it."
        },
        {
                "question": "Can I edit the metadata here?",
                "answer": "This specific tool is a viewer. Editing capabilities would require a different utility."
        }
]}
      
      title="PDF Metadata Viewer"
      description="View hidden properties and EXIF data of any PDF file locally. Extract author, title, dates, keywords, and creation tools instantly."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to view metadata"
          subtitle="Choose the PDF document you want to inspect"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm max-w-3xl mx-auto">
          {/* Header */}
          <div className="flex items-center justify-between pb-4 border-b border-border mb-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-primary/10 text-primary rounded-lg">
                <FileText className="w-6 h-6" />
              </div>
              <div>
                <h4 className="font-sans font-bold text-base text-ink">{file.name}</h4>
                <p className="font-sans text-[13px] text-slate mt-0.5">
                  Properties Viewer
                </p>
              </div>
            </div>
            <Button variant="outline" size="sm" onClick={handleReset}>
              Reset
            </Button>
          </div>

          {isProcessing && <LoadingSpinner text="Extracting hidden metadata..." />}

          {/* Metadata Display */}
          {metadata && (
            <div className="space-y-6 animate-in fade-in duration-300">
              <div className="border border-border rounded-xl overflow-hidden bg-background/30">
                <table className="w-full text-left font-sans text-sm border-collapse">
                  <thead>
                    <tr className="border-b border-border bg-background">
                      <th className="p-4 font-bold text-[12px] text-slate uppercase tracking-wider w-1/3">Property</th>
                      <th className="p-4 font-bold text-[12px] text-slate uppercase tracking-wider w-2/3">Value</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(metadata).map(([key, val]) => {
                      const displayVal = key === 'fileSize' ? formatFileSize(val as number) : (val ? String(val) : '—');
                      return (
                        <tr key={key} className="border-b border-border/60 hover:bg-surface transition-colors">
                          <td className="p-4 font-semibold text-slate">{formatKeyLabel(key)}</td>
                          <td className="p-4 text-ink font-mono text-[13px] break-all">{displayVal}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
              
              <div className="p-4 bg-primary/5 border border-primary/10 rounded-lg flex gap-3 text-primary text-[13px]">
                <Info className="w-5 h-5 flex-shrink-0" />
                <p className="font-sans leading-relaxed">
                  Metadata extraction runs 100% locally on your machine. We never access, index, or store your documents.
                </p>
              </div>
            </div>
          )}
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState } from 'react';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { countPDFPages } from '@/lib/pdf/pdfHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { formatFileSize } from '@/lib/fileHelpers';
import { FileText, Plus, Hash } from 'lucide-react';

export function PageCounterClient() {
  const [files, setFiles] = useState<File[]>([]);
  const [fileCounts, setFileCounts] = useState<{ fileName: string; pages: number }[]>([]);
  const [totalCount, setTotalCount] = useState<number | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);

  const handleFilesSelected = async (selectedFiles: File[]) => {
    setError(null);
    setWarning(null);
    setIsProcessing(true);

    const validFiles: File[] = [];
    for (const file of selectedFiles) {
      const validation = validatePdfFile(file);
      if (!validation.isValid) {
        setError(validation.error || `Invalid PDF file: ${file.name}`);
        setIsProcessing(false);
        return;
      }
      try {
        const buffer = await file.arrayBuffer();
        const isProtected = await checkPdfPasswordProtected(buffer);
        if (isProtected) {
          setError(`File "${file.name}" is password protected. Password protected files are not supported.`);
          setIsProcessing(false);
          return;
        }
        validFiles.push(file);
      } catch (err: any) {
        setError(`File "${file.name}": ${getPdfErrorMessage(err)}`);
        setIsProcessing(false);
        return;
      }
    }

    const updatedFiles = [...files, ...validFiles];
    setFiles(updatedFiles);

    // Set or clear warning based on the updated queue
    const largeFile = updatedFiles.find(f => f.size > 100 * 1024 * 1024);
    if (largeFile) {
      setWarning(`Large file warning: File "${largeFile.name}" is ${(largeFile.size / (1024 * 1024)).toFixed(1)}MB. Processing files between 100MB and 1GB entirely in the browser is supported, but may cause the page to lag or run out of memory depending on your computer's RAM. Keep other tabs closed for best performance.`);
    } else {
      setWarning(null);
    }

    try {
      const result = await countPDFPages(updatedFiles);
      setFileCounts(result.counts);
      setTotalCount(result.total);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFiles([]);
    setFileCounts([]);
    setTotalCount(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Select one or multiple PDF documents.",
        "The tool will instantly analyze the files and display the page count for each.",
        "View the total combined page count across all uploaded documents."
]}
      faqs={[
        {
                "question": "Do I need to fully upload the PDFs to count them?",
                "answer": "No, the tool reads the file headers locally in your browser to determine the count instantly without full uploads."
        },
        {
                "question": "Is this tool free?",
                "answer": "Yes, completely free and unlimited."
        }
]}
      
      title="PDF Page Counter"
      description="Upload one or multiple PDF documents to count pages and calculate the total count. Safe and processed completely in the browser."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {files.length === 0 ? (
        <FileUploader
          onFilesSelected={handleFilesSelected}
          multiple={true}
          title="Upload PDF files to count pages"
          subtitle="Drag one or multiple PDF documents here"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex flex-wrap items-center justify-between gap-4 pb-6 border-b border-border mb-6">
            <div>
              <h3 className="font-display font-bold text-lg text-ink">Page Counter</h3>
              <p className="font-sans text-[13px] text-slate mt-0.5">
                {files.length} document{files.length > 1 ? 's' : ''} loaded.
              </p>
            </div>
            <div className="flex gap-2">
              <input
                type="file"
                id="add-more-counter"
                multiple
                accept=".pdf"
                className="hidden"
                onChange={(e) => {
                  if (e.target.files) handleFilesSelected(Array.from(e.target.files));
                }}
              />
              <Button
                variant="outline"
                size="sm"
                leftIcon={<Plus className="w-4 h-4" />}
                onClick={() => document.getElementById('add-more-counter')?.click()}
              >
                Add More
              </Button>
              <Button variant="ghost" size="sm" onClick={handleReset}>
                Reset
              </Button>
            </div>
          </div>

          {isProcessing && <LoadingSpinner text="Counting document pages..." />}

          {/* Result Stats dashboard */}
          {totalCount !== null && !isProcessing && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8 animate-in fade-in duration-300">
              <div className="md:col-span-1 p-6 bg-primary/5 border border-primary/20 rounded-xl flex flex-col items-center justify-center text-center">
                <div className="w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center text-primary mb-3">
                  <Hash className="w-6 h-6" />
                </div>
                <h4 className="font-sans font-bold text-slate text-[11px] uppercase tracking-wider">Total Combined Pages</h4>
                <p className="font-display font-black text-5xl text-primary mt-2">{totalCount}</p>
              </div>

              <div className="md:col-span-2 border border-border bg-background/30 rounded-xl p-4 overflow-y-auto max-h-[220px] space-y-2">
                <span className="text-[11px] font-sans text-slate uppercase tracking-wider font-bold block mb-2">
                  Page Breakdown
                </span>
                {fileCounts.map((item, idx) => (
                  <div key={idx} className="flex justify-between items-center bg-surface border border-border/60 p-2.5 rounded-lg text-sm">
                    <span className="font-sans font-medium text-ink truncate max-w-[250px]">{item.fileName}</span>
                    <span className="font-mono font-bold text-primary">{item.pages} pgs</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Action reset */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border mt-8">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Clear Files
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

