"use client";

import React, { useState } from 'react';
import { pdfjsLib } from '@/lib/pdfjsSetup';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { PageThumbnail } from '@/components/tools/PageThumbnail';
import { loadPdfDocument, renderPageToDataUrl } from '@/lib/pdf/pdfRenderHelpers';
import { downloadAllAsZip } from '@/lib/downloadHelpers';
import { downloadBlob } from '@/lib/pdf/downloadBlob';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { readPdfFile } from '@/lib/pdf/readPdfFile';
import { formatFileSize, dataUrlToBlob } from '@/lib/fileHelpers';
import { FileText, Download, FileImage, Image as ImageIcon } from 'lucide-react';

export function PdfToJpgClient() {
  const [file, setFile] = useState<File | null>(null);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [renderedImages, setRenderedImages] = useState<string[]>([]); // Data URLs

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setRenderedImages([]);
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    try {
      const buffer = await readPdfFile(selectedFile);
      const isProtected = await checkPdfPasswordProtected(buffer.slice(0));
      if (isProtected) {
        setError('This PDF may be encrypted or password-protected. Please upload an unlocked PDF.');
        return;
      }

      setFile(selectedFile);
      const doc = await loadPdfDocument(selectedFile);
      setPdfDoc(doc);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    }
  };

  const handleConvertPage = async (pageNum: number): Promise<string> => {
    if (!pdfDoc) throw new Error('PDF not loaded');
    // Scale 2.0 ensures high-quality image output
    return renderPageToDataUrl(pdfDoc, pageNum, 2.0, 'image/jpeg');
  };

  const handleDownloadSingle = async (pageNum: number) => {
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    try {
      const dataUrl = await handleConvertPage(pageNum);
      const blob = dataUrlToBlob(dataUrl);
      const baseName = file.name.replace(/\.[^/.]+$/, "");
      downloadBlob(blob, `${baseName}_page_${pageNum}.jpg`);
    } catch (err: any) {
      console.error(err);
      setError('Failed to convert this page to image.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDownloadAll = async () => {
    if (!file || !pdfDoc) return;
    setIsProcessing(true);
    setError(null);
    setProgress({ current: 0, total: pdfDoc.numPages });

    try {
      const images: { name: string; blob: Blob }[] = [];
      const baseName = file.name.replace(/\.[^/.]+$/, "");

      for (let i = 1; i <= pdfDoc.numPages; i++) {
        setProgress({ current: i, total: pdfDoc.numPages });
        const dataUrl = await handleConvertPage(i);
        const blob = dataUrlToBlob(dataUrl);
        images.push({
          name: `${baseName}_page_${i}.jpg`,
          blob
        });
      }

      await downloadAllAsZip(images, `${baseName}_images`);
    } catch (err: any) {
      console.error(err);
      setError('An error occurred during bulk conversion.');
    } finally {
      setIsProcessing(false);
      setProgress({ current: 0, total: 0 });
    }
  };

  const handleReset = () => {
    setFile(null);
    setPdfDoc(null);
    setRenderedImages([]);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload the PDF you want to convert into images.",
        "The tool will render each page of the PDF into a high-quality JPG image.",
        "Review the image previews.",
        "Download the images individually or as a bulk ZIP file."
]}
      faqs={[
        {
                "question": "What resolution are the JPGs generated at?",
                "answer": "The images are rendered at a high scale to ensure clear, readable text and crisp graphics."
        },
        {
                "question": "Are my documents safe?",
                "answer": "Yes, the conversion from PDF to JPG happens locally using JavaScript, ensuring your files never leave your device."
        }
]}
      
      title="PDF to JPG"
      description="Convert PDF document pages into high-quality JPG images directly inside your browser. Instant conversion, zero server uploads."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to convert"
          subtitle="Choose the PDF document whose pages you want to save as images"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-6 border-b border-border mb-6">
            <div className="flex items-center gap-3 min-w-0">
              <div className="p-3 bg-primary/10 text-primary rounded-lg">
                <FileText className="w-6 h-6" />
              </div>
              <div className="min-w-0">
                <h4 className="font-sans font-bold text-base text-ink truncate">{file.name}</h4>
                <p className="font-sans text-[13px] text-slate mt-0.5">
                  {formatFileSize(file.size)} • {pdfDoc?.numPages} pages available
                </p>
              </div>
            </div>
            <div className="flex gap-2">
              <Button
                variant="primary"
                size="sm"
                onClick={handleDownloadAll}
                disabled={isProcessing}
                leftIcon={<Download className="w-4 h-4" />}
              >
                Download All as ZIP
              </Button>
              <Button variant="ghost" size="sm" onClick={handleReset}>
                Change File
              </Button>
            </div>
          </div>

          {/* Grid display */}
          {pdfDoc && (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6 max-h-[500px] overflow-y-auto p-2 mb-8 bg-background/50 rounded-xl border border-border">
              {Array.from({ length: pdfDoc.numPages }, (_, i) => i + 1).map((pageNum) => (
                <div key={pageNum} className="flex flex-col items-center">
                  <div className="relative group w-full aspect-[3/4] bg-background border border-border rounded-lg overflow-hidden flex items-center justify-center p-2">
                    <PageThumbnail
                      pdfDoc={pdfDoc}
                      pageNumber={pageNum}
                      scale={0.25}
                    />
                    {/* Hover download overlays */}
                    <div className="absolute inset-0 bg-dark/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2 backdrop-blur-xs">
                      <button
                        onClick={() => handleDownloadSingle(pageNum)}
                        className="bg-primary hover:brightness-110 text-dark p-2.5 rounded-full shadow transition-all active:scale-[0.9]"
                        title="Download as JPG"
                      >
                        <Download className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                  
                  <span className="font-sans text-[12px] font-semibold text-slate mt-2">
                    Page {pageNum}
                  </span>
                </div>
              ))}
            </div>
          )}

          {/* Bulk loading progress */}
          {isProcessing && (
            <div className="space-y-4">
              <LoadingSpinner text={progress.total > 0 ? `Converting page ${progress.current} of ${progress.total}...` : 'Converting page...'} />
              {progress.total > 0 && (
                <div className="w-full max-w-md mx-auto bg-border h-2 rounded-full overflow-hidden">
                  <div 
                    className="bg-primary h-full transition-all duration-150"
                    style={{ width: `${(progress.current / progress.total) * 100}%` }}
                  />
                </div>
              )}
            </div>
          )}

          {/* Action buttons */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border mt-8">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Reset
            </Button>
            <Button
              variant="primary"
              size="lg"
              onClick={handleDownloadAll}
              disabled={isProcessing}
              leftIcon={<FileImage className="w-5 h-5" />}
            >
              Convert PDF to JPG
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState } from 'react';
import { pdfjsLib } from '@/lib/pdfjsSetup';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { loadPdfDocument, extractTextFromPdf } from '@/lib/pdf/pdfRenderHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { readPdfFile } from '@/lib/pdf/readPdfFile';
import { formatFileSize } from '@/lib/fileHelpers';
import { downloadBlob } from '@/lib/pdf/downloadBlob';
import { FileText, Copy, Download, Check, Clipboard } from 'lucide-react';

export function PdfToTextClient() {
  const [file, setFile] = useState<File | null>(null);
  const [extractedText, setExtractedText] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setExtractedText(null);
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    try {
      const buffer = await readPdfFile(selectedFile);
      const isProtected = await checkPdfPasswordProtected(buffer.slice(0));
      if (isProtected) {
        setError('This PDF may be encrypted or password-protected. Please upload an unlocked PDF.');
        return;
      }

      setFile(selectedFile);
      setIsProcessing(true);
      
      const doc = await loadPdfDocument(selectedFile);
      setProgress({ current: 0, total: doc.numPages });

      const text = await extractTextFromPdf(doc, (curr, tot) => {
        setProgress({ current: curr, total: tot });
      });

      setExtractedText(text);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
      setProgress({ current: 0, total: 0 });
    }
  };

  const handleCopy = () => {
    if (!extractedText) return;
    navigator.clipboard.writeText(extractedText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    if (!extractedText || !file) return;
    const blob = new Blob([extractedText], { type: 'text/plain;charset=utf-8' });
    const baseName = file.name.replace(/\.[^/.]+$/, "");
    downloadBlob(blob, `${baseName}_extracted.txt`);
  };

  const handleReset = () => {
    setFile(null);
    setExtractedText(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload a PDF containing text.",
        "Wait a moment while the text is extracted locally.",
        "Review the extracted text in the browser.",
        "Copy the text to your clipboard or download it as a .txt file."
]}
      faqs={[
        {
                "question": "Can it extract text from scanned images?",
                "answer": "This tool extracts embedded digital text. If the PDF is purely scanned images without OCR, it will not extract text."
        },
        {
                "question": "Is formatting preserved?",
                "answer": "The tool extracts raw text. Complex layouts, tables, and exact fonts are not preserved."
        }
]}
      
      title="PDF to Text"
      description="Extract readable text content from any PDF file. The text extraction happens entirely inside your browser. No uploads, total privacy."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to extract text"
          subtitle="Choose the PDF document you want to extract text from"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex items-center justify-between pb-4 border-b border-border mb-6">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-primary/10 text-primary rounded-lg">
                <FileText className="w-6 h-6" />
              </div>
              <div>
                <h4 className="font-sans font-bold text-base text-ink">{file.name}</h4>
                <p className="font-sans text-[13px] text-slate mt-0.5">
                  {formatFileSize(file.size)}
                </p>
              </div>
            </div>
            <Button variant="outline" size="sm" onClick={handleReset} disabled={isProcessing}>
              Change File
            </Button>
          </div>

          {/* Progress loader */}
          {isProcessing && (
            <div className="space-y-4 mb-6">
              <LoadingSpinner text={progress.total > 0 ? `Parsing page ${progress.current} of ${progress.total}...` : 'Extracting text...'} />
              {progress.total > 0 && (
                <div className="w-full max-w-md mx-auto bg-border h-2 rounded-full overflow-hidden">
                  <div 
                    className="bg-primary h-full transition-all duration-150"
                    style={{ width: `${(progress.current / progress.total) * 100}%` }}
                  />
                </div>
              )}
            </div>
          )}

          {/* Results Textarea */}
          {extractedText !== null && (
            <div className="space-y-6 animate-in fade-in duration-300">
              <div className="relative">
                <textarea
                  readOnly
                  value={extractedText}
                  className="w-full h-[400px] bg-background border border-border rounded-lg p-4 font-mono text-[13px] text-ink outline-none focus:border-primary resize-none"
                  placeholder="No readable text found in PDF."
                />
                
                <div className="absolute top-4 right-4 flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleCopy}
                    leftIcon={copied ? <Check className="w-4 h-4 text-green-500" /> : <Clipboard className="w-4 h-4" />}
                  >
                    {copied ? 'Copied' : 'Copy'}
                  </Button>
                  <Button
                    variant="primary"
                    size="sm"
                    onClick={handleDownload}
                    leftIcon={<Download className="w-4 h-4" />}
                  >
                    Download .TXT
                  </Button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </ToolLayout>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { pdfjsLib } from '@/lib/pdfjsSetup';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { Button } from '@/components/ui/Button';
import { DownloadButton } from '@/components/tools/DownloadButton';
import { LoadingSpinner } from '@/components/tools/LoadingSpinner';
import { PageThumbnail } from '@/components/tools/PageThumbnail';
import { rotatePDF } from '@/lib/pdf/pdfHelpers';
import { loadPdfDocument } from '@/lib/pdf/pdfRenderHelpers';
import { checkPdfPasswordProtected, validatePdfFile, getPdfErrorMessage } from '@/lib/pdf/pdfValidation';
import { readPdfFile } from '@/lib/pdf/readPdfFile';
import { formatFileSize } from '@/lib/fileHelpers';
import { FileText, RotateCw, RefreshCw } from 'lucide-react';

export function RotatePdfClient() {
  const [file, setFile] = useState<File | null>(null);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [pageRotations, setPageRotations] = useState<Record<number, number>>({});
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [rotatedBlobUrl, setRotatedBlobUrl] = useState<string | null>(null);

  const handleFileSelected = async (selectedFiles: File[]) => {
    if (selectedFiles.length === 0) return;
    setError(null);
    setWarning(null);
    setRotatedBlobUrl(null);
    const selectedFile = selectedFiles[0];

    const validation = validatePdfFile(selectedFile);
    if (!validation.isValid) {
      setError(validation.error || 'Invalid PDF file.');
      return;
    }
    if (validation.warning) {
      setWarning(validation.warning);
    }

    try {
      const buffer = await readPdfFile(selectedFile);
      const isProtected = await checkPdfPasswordProtected(buffer.slice(0));
      if (isProtected) {
        setError('This PDF may be encrypted or password-protected. Please upload an unlocked PDF.');
        return;
      }

      setFile(selectedFile);
      const doc = await loadPdfDocument(selectedFile);
      setPdfDoc(doc);
      
      // Initialize rotations
      const initialRotations: Record<number, number> = {};
      for (let i = 1; i <= doc.numPages; i++) {
        initialRotations[i] = 0;
      }
      setPageRotations(initialRotations);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    }
  };

  const handleRotatePage = (pageNum: number) => {
    setPageRotations(prev => ({
      ...prev,
      [pageNum]: (prev[pageNum] + 90) % 360
    }));
    setRotatedBlobUrl(null);
  };

  const handleRotateAll = (degrees: number) => {
    if (!pdfDoc) return;
    setPageRotations(prev => {
      const next = { ...prev };
      for (let i = 1; i <= pdfDoc.numPages; i++) {
        next[i] = (next[i] + degrees) % 360;
      }
      return next;
    });
    setRotatedBlobUrl(null);
  };

  const handleSave = async () => {
    if (!file || !pdfDoc) return;
    setIsProcessing(true);
    setError(null);
    setRotatedBlobUrl(null);

    try {
      // Filter out pages that have rotation changes (multiples of 90)
      const rotationsToApply: Record<number, number> = {};
      Object.entries(pageRotations).forEach(([pageNumStr, rot]) => {
        if (rot !== 0) {
          rotationsToApply[parseInt(pageNumStr, 10)] = rot;
        }
      });

      const rotatedBytes = await rotatePDF(file, rotationsToApply);
      const blob = new Blob([rotatedBytes.buffer as ArrayBuffer], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      setRotatedBlobUrl(url);
    } catch (err: any) {
      console.error(err);
      setError(getPdfErrorMessage(err));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleReset = () => {
    setFile(null);
    setPdfDoc(null);
    setPageRotations({});
    setRotatedBlobUrl(null);
    setError(null);
    setWarning(null);
  };

  return (
    <ToolLayout
      howToUse={[
        "Upload a PDF with incorrectly oriented pages.",
        "Click the rotate buttons on individual page thumbnails, or rotate all pages at once.",
        "Click 'Apply Rotation' to save the orientation.",
        "Download the corrected PDF."
]}
      faqs={[
        {
                "question": "Is the rotation permanent?",
                "answer": "Yes, the downloaded PDF will have the new rotation embedded in its structure."
        },
        {
                "question": "Can I rotate only specific pages?",
                "answer": "Absolutely. You can rotate individual pages 90, 180, or 270 degrees."
        }
]}
      
      title="Rotate PDF"
      description="Rotate individual pages or all pages of a PDF document visually. Completely secure, offline in-browser processing."
      categoryName="PDF Tools"
      categoryHref="/tools/pdf"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {!file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          title="Upload a PDF file to rotate"
          subtitle="Choose the PDF document whose pages you want to rotate"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* File header */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-6 border-b border-border mb-6">
            <div className="flex items-center gap-3 min-w-0">
              <div className="p-3 bg-primary/10 text-primary rounded-lg">
                <FileText className="w-6 h-6" />
              </div>
              <div className="min-w-0">
                <h4 className="font-sans font-bold text-base text-ink truncate">{file.name}</h4>
                <p className="font-sans text-[13px] text-slate mt-0.5">
                  {formatFileSize(file.size)} • {pdfDoc?.numPages} pages
                </p>
              </div>
            </div>
            
            {/* Quick Rotate All controls */}
            <div className="flex flex-wrap items-center gap-2">
              <Button variant="outline" size="sm" onClick={() => handleRotateAll(90)} leftIcon={<RotateCw className="w-4 h-4" />}>
                Rotate All +90°
              </Button>
              <Button variant="outline" size="sm" onClick={() => handleRotateAll(180)} leftIcon={<RotateCw className="w-4 h-4" />}>
                Flip All 180°
              </Button>
              <Button variant="ghost" size="sm" onClick={handleReset}>
                Change File
              </Button>
            </div>
          </div>

          {/* Page Grid */}
          {pdfDoc && (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6 max-h-[500px] overflow-y-auto p-2 mb-8 bg-background/50 rounded-xl border border-border">
              {Array.from({ length: pdfDoc.numPages }, (_, i) => i + 1).map((pageNum) => {
                const rotation = pageRotations[pageNum] || 0;
                return (
                  <div key={pageNum} className="flex flex-col items-center">
                    <div className="relative group w-full aspect-[3/4] bg-background border border-border rounded-lg overflow-hidden hover:border-slate hover:shadow-xs transition-all flex items-center justify-center p-2">
                      <PageThumbnail
                        pdfDoc={pdfDoc}
                        pageNumber={pageNum}
                        scale={0.25}
                        className="transition-transform duration-200"
                        style={{ transform: `rotate(${rotation}deg)` }}
                      />
                      {/* Hover controls overlay */}
                      <div className="absolute inset-0 bg-dark/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-xs">
                        <button
                          onClick={() => handleRotatePage(pageNum)}
                          className="bg-primary hover:brightness-110 text-dark p-2.5 rounded-full shadow transition-all active:scale-[0.9]"
                          title="Rotate 90° Clockwise"
                        >
                          <RotateCw className="w-5 h-5" />
                        </button>
                      </div>
                      
                      {/* Current Rotation Tag */}
                      {rotation !== 0 && (
                        <div className="absolute top-2 right-2 bg-primary text-dark text-[10px] font-bold px-1.5 py-0.5 rounded shadow">
                          +{rotation}°
                        </div>
                      )}
                    </div>
                    <span className="font-sans text-[12px] font-semibold text-slate mt-2">
                      Page {pageNum}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          {isProcessing && <LoadingSpinner text="Rotating pages..." />}

          {/* Download rotated PDF result */}
          {rotatedBlobUrl && (
            <div className="p-6 bg-primary/5 border border-primary/20 rounded-xl mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in fade-in duration-200">
              <div>
                <h4 className="font-display font-bold text-base text-ink">Rotated Document Ready!</h4>
                <p className="font-sans text-[12px] text-slate mt-0.5">
                  Your PDF was rotated successfully. Click the button to download.
                </p>
              </div>
              <DownloadButton href={rotatedBlobUrl} download={`singulariti_${file.name.replace(/\.[^/.]+$/, "")}_rotated.pdf`}>
                Download Rotated PDF
              </DownloadButton>
            </div>
          )}

          {/* Action buttons */}
          <div className="flex items-center justify-end gap-3 pt-6 border-t border-border">
            <Button variant="outline" size="lg" onClick={handleReset}>
              Reset
            </Button>
            <Button
              variant="primary"
              size="lg"
              onClick={handleSave}
              disabled={isProcessing}
              leftIcon={<RefreshCw className="w-4 h-4" />}
            >
              Apply Rotations
            </Button>
          </div>
        </div>
      )}
    </ToolLayout>
  );
}

