                        />
                      </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1.5">
                        <label className="block text-[11px] text-slate font-bold uppercase tracking-wider">Amount (INR) (Optional)</label>
                        <input
                          type="number"
