                          <button onClick={() => setLogoDataUrl(undefined)} className="text-red-500 hover:underline">Remove</button>
                        </div>
                        <input
                          type="range"
                          min="10"
                          max="25"
                          value={logoSizePercent}
                          onChange={(e) => setLogoSizePercent(Number(e.target.value))}
