'use client';

import React, { useState, useEffect, useRef } from 'react';
import { Search, ArrowRight } from 'lucide-react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { toolRegistry } from '@/content/tools/toolRegistry';
import { getAllPosts } from '@/lib/blog';

export function BlogSearchAutocomplete() {
  const [query, setQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const router = useRouter();
  const wrapperRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      router.push(`/blog/search?q=${encodeURIComponent(query)}`);
      setIsOpen(false);
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);
    setIsOpen(e.target.value.trim().length > 0);
  };

  // Get matching tools (for dynamic guides)
  const matchingTools = toolRegistry
    .filter(tool => 
      tool.name.toLowerCase().includes(query.toLowerCase()) || 
      tool.shortDescription.toLowerCase().includes(query.toLowerCase())
    )
    .slice(0, 3); // Max 3 tools

  // Get matching manual blog posts
  const allPosts = getAllPosts();
  const matchingPosts = allPosts
    .filter(post => 
      post.title.toLowerCase().includes(query.toLowerCase()) || 
      (post.metaDescription && post.metaDescription.toLowerCase().includes(query.toLowerCase()))
    )
    .slice(0, 3); // Max 3 posts

  const hasResults = matchingTools.length > 0 || matchingPosts.length > 0;

  return (
    <div className="relative w-full" ref={wrapperRef}>
      <form onSubmit={handleSubmit} className="relative flex gap-3">
        <div className="relative flex-1">
          <span className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
            <Search className="h-4.5 w-4.5 text-slate" />
          </span>
          <input
            suppressHydrationWarning
            type="text"
            name="q"
            value={query}
            onChange={handleInputChange}
            onFocus={() => { if (query.trim()) setIsOpen(true); }}
            placeholder="Enter JSON, PDF, word counter, or calculation formulas..."
            required
            autoComplete="off"
            className="w-full font-sans text-xs text-ink bg-background border border-border rounded-xl pl-10 pr-4 py-3.5 focus:border-primary focus:outline-none transition-colors"
          />
        </div>
        <button
          suppressHydrationWarning
          type="submit"
          className="bg-primary hover:bg-primary/95 text-white font-sans font-bold text-xs px-5 py-3.5 rounded-xl transition-colors shadow-sm"
        >
          Search
        </button>
      </form>

      {/* Autocomplete Dropdown */}
      {isOpen && query.trim() && (
        <div className="absolute top-full left-0 right-0 mt-2 bg-surface border border-border rounded-2xl shadow-xl overflow-hidden z-50 animate-in fade-in slide-in-from-top-2">
          {hasResults ? (
            <div className="max-h-[300px] overflow-y-auto p-2">

              {matchingPosts.length > 0 && (
                <div className="mb-2">
                  <div className="px-3 py-1.5 text-[10px] font-bold text-slate uppercase tracking-wider">
                    Manual Guides
                  </div>
                  {matchingPosts.map(post => (
                    <Link
                      key={post.slug}
                      href={`/blog/guides/${post.slug}`}
                      onClick={() => setIsOpen(false)}
                      className="block px-3 py-2.5 rounded-xl hover:bg-primary/5 hover:text-primary transition-colors"
                    >
                      <div className="font-display font-bold text-[13px] text-ink mb-0.5">
                        {post.title}
                      </div>
                      <div className="font-sans text-[11px] text-slate line-clamp-1">
                        {post.metaDescription}
                      </div>
                    </Link>
                  ))}
                </div>
              )}

              {matchingTools.length > 0 && (
                <div>
                  <div className="px-3 py-1.5 text-[10px] font-bold text-slate uppercase tracking-wider">
                    Utility Guides
                  </div>
                  {matchingTools.map(tool => (
                    <Link
                      key={tool.id}
                      href={`/blog/guides/${tool.guideSlug}`}
                      onClick={() => setIsOpen(false)}
                      className="block px-3 py-2.5 rounded-xl hover:bg-primary/5 hover:text-primary transition-colors"
                    >
                      <div className="font-display font-bold text-[13px] text-ink mb-0.5 flex justify-between">
                        <span>{tool.name} Guide</span>
                        <ArrowRight className="w-3.5 h-3.5 opacity-50" />
                      </div>
                      <div className="font-sans text-[11px] text-slate line-clamp-1">
                        {tool.shortDescription}
                      </div>
                    </Link>
                  ))}
                </div>
              )}

              <div className="pt-2 mt-2 border-t border-border/50">
                <button
                  type="button"
                  onClick={handleSubmit}
                  className="w-full px-3 py-2 text-center text-[12px] font-semibold text-primary hover:bg-primary/5 rounded-xl transition-colors"
                >
                  View all results for "{query}"
                </button>
              </div>

            </div>
          ) : (
            <div className="p-6 text-center text-slate text-xs font-sans">
              No matching guides found for "{query}".
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Play, Pause, RotateCcw, CheckCircle2, Circle, Plus, Trash2, Flame } from 'lucide-react';
import { PomodoroMode, Task, PomodoroStats } from '@/hooks/usePomodoroEngine';

export function TimerDisplay({ timeLeft, totalTime }: { timeLeft: number, totalTime: number }) {
  const minutes = Math.floor(timeLeft / 60);
  const seconds = timeLeft % 60;

  const percentage = (timeLeft / totalTime) * 100;
  const radius = 120;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (percentage / 100) * circumference;

  return (
    <div className="relative flex items-center justify-center w-64 h-64 md:w-96 md:h-96 mx-auto mb-12">
      <svg className="absolute inset-0 w-full h-full -rotate-90 transform" viewBox="0 0 256 256">
        <circle 
          cx="128" cy="128" r={radius}
          fill="none" 
          stroke="currentColor" 
          strokeWidth="4" 
          className="text-surface"
        />
        <motion.circle 
          cx="128" cy="128" r={radius}
          fill="none" 
          stroke="currentColor" 
          strokeWidth="6" 
          strokeLinecap="round"
          className="text-primary"
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset }}
          transition={{ duration: 1, ease: "linear" }}
          style={{ strokeDasharray: circumference }}
        />
      </svg>
      <div className="z-10 flex flex-col items-center">
        <motion.div 
          className="text-6xl md:text-8xl font-display font-bold tracking-tighter tabular-nums"
          key={`${minutes}:${seconds}`}
          initial={{ opacity: 0.5, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3 }}
        >
          {String(minutes).padStart(2, '0')}:{String(seconds).padStart(2, '0')}
        </motion.div>
      </div>
    </div>
  );
}

export function TimerControls({ 
  mode, isRunning, toggleTimer, changeMode, resetTimer, setCustomTime 
}: {
  mode: PomodoroMode,
  isRunning: boolean,
  toggleTimer: () => void,
  changeMode: (m: PomodoroMode) => void,
  resetTimer: () => void,
  setCustomTime: (m: number) => void
}) {
  const modes = [
    { id: 'pomodoro', label: 'Pomodoro' },
    { id: 'short_break', label: 'Short Break' },
    { id: 'long_break', label: 'Long Break' }
  ];

  return (
    <div className="flex flex-col items-center space-y-8 z-20">
      <div className="flex bg-surface/50 p-1 rounded-full space-x-1 border border-border/50">
        {modes.map(m => (
          <button
            key={m.id}
            onClick={() => changeMode(m.id as PomodoroMode)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-300 ${
              mode === m.id ? 'bg-primary text-primary-foreground shadow-sm' : 'text-slate hover:text-foreground hover:bg-surface'
            }`}
          >
            {m.label}
          </button>
        ))}
      </div>

      <div className="flex items-center space-x-6">
        <button 
          onClick={resetTimer}
          className="p-3 text-slate hover:text-foreground hover:bg-surface rounded-full transition-colors"
          title="Reset Timer (R)"
        >
          <RotateCcw size={24} />
        </button>

        <button 
          onClick={toggleTimer}
          className={`flex items-center justify-center w-20 h-20 rounded-full text-white shadow-lg transition-transform hover:scale-105 active:scale-95 ${
            isRunning ? 'bg-red-500 hover:bg-red-600 shadow-red-500/25' : 'bg-primary hover:bg-primary/90 shadow-primary/25'
          }`}
          title={isRunning ? "Pause (Space)" : "Start (Space)"}
        >
          {isRunning ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-2" />}
        </button>

        <div className="w-12 h-12" /> {/* Empty space for balance */}
      </div>
    </div>
  );
}

export function TaskManagement({
  tasks, addTask, toggleTask, deleteTask
}: {
  tasks: Task[], addTask: (t: string) => void, toggleTask: (id: string) => void, deleteTask: (id: string) => void
}) {
  const [input, setInput] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    addTask(input);
    setInput('');
  };

  return (
    <div className="w-full max-w-md mx-auto bg-surface/30 backdrop-blur-sm rounded-2xl p-6 border border-border/50 shadow-sm">
      <h3 className="font-display font-semibold mb-4 text-lg">Focus Tasks</h3>

      <form onSubmit={handleAdd} className="flex space-x-2 mb-6">
        <input 
          type="text" 
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="What are you working on?"
          className="flex-1 bg-background border border-border rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all"
        />
        <button 
          type="submit"
          disabled={!input.trim()}
          className="p-2 bg-primary text-primary-foreground rounded-lg disabled:opacity-50 transition-opacity"
        >
          <Plus size={20} />
        </button>
      </form>

      <div className="space-y-2 max-h-[200px] overflow-y-auto pr-2 custom-scrollbar">
        <AnimatePresence>
          {tasks.length === 0 && (
            <motion.p 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="text-center text-slate text-sm py-4"
            >
              No tasks added yet. Add one above!
            </motion.p>
          )}
          {tasks.map(t => (
            <motion.div 
              key={t.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className={`flex items-center justify-between p-3 rounded-lg border transition-all ${
                t.completed ? 'bg-surface/50 border-transparent opacity-60' : 'bg-background border-border shadow-sm'
              }`}
            >
              <div className="flex items-center space-x-3 overflow-hidden">
                <button aria-label="Toggle task completion" onClick={() => toggleTask(t.id)} className="text-primary flex-shrink-0">
                  {t.completed ? <CheckCircle2 size={20} /> : <Circle size={20} />}
                </button>
                <span className={`text-sm truncate ${t.completed ? 'line-through text-slate' : ''}`}>
                  {t.title}
                </span>
              </div>
              <button 
                onClick={() => deleteTask(t.id)}
                className="text-slate hover:text-red-500 transition-colors p-1"
              >
                <Trash2 size={16} />
              </button>
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
}

export function StatsDisplay({ stats }: { stats: PomodoroStats }) {
  return (
    <div className="grid grid-cols-3 gap-2 sm:gap-4 w-full max-w-md mx-auto">
      <div className="bg-surface/30 rounded-xl p-3 sm:p-4 text-center border border-border/50">
        <div className="text-2xl font-display font-bold text-foreground">{stats.sessionsCompleted}</div>
        <div className="text-xs text-slate uppercase tracking-wider mt-1">Sessions</div>
      </div>
      <div className="bg-surface/30 rounded-xl p-3 sm:p-4 text-center border border-border/50">
        <div className="text-2xl font-display font-bold text-foreground">{Math.round(stats.totalFocusSeconds / 3600)}</div>
        <div className="text-xs text-slate uppercase tracking-wider mt-1">Hours</div>
      </div>
      <div className="bg-primary/10 rounded-xl p-3 sm:p-4 text-center border border-primary/20">
        <div className="text-2xl font-display font-bold text-primary flex items-center justify-center space-x-1">
          <span>{stats.currentStreak}</span>
          <Flame size={20} className="text-orange-500" />
        </div>
        <div className="text-xs text-primary/80 uppercase tracking-wider mt-1">Day Streak</div>
      </div>
    </div>
  );
}

