"use client";

import React, { useState, useRef, useEffect } from 'react';
import { UploadCloud, Download, Loader2, ArrowRight, Settings2, Image as ImageIcon, EyeOff, Eye } from 'lucide-react';
import { useCompression } from '../../hooks/useCompression';
import { useConversion } from '../../hooks/useConversion';
import { ToolRegistryItem } from '../../registry/types';
import { Button } from '../ui/Button';
import { Dropzone } from '../ui/Dropzone';

interface ToolEngineProps {
  tool: ToolRegistryItem;
}

export function ToolEngine({ tool }: ToolEngineProps) {
  const [file, setFile] = useState<File | null>(null);
  const [dragOver, setDragOver] = useState(false);
  const [result, setResult] = useState<{ url: string; originalSize: number; newSize: number; type?: string } | null>(null);

  // Advanced UI State
  const [mode, setMode] = useState<'default' | 'custom'>('default');
  const [compressionLevel, setCompressionLevel] = useState<number>(70); // 70% compression = 30% quality
  const [showPreview, setShowPreview] = useState(true);
  const [originalPreviewUrl, setOriginalPreviewUrl] = useState<string | null>(null);

  const { compress, isProcessing: isCompressing, error: compressError } = useCompression();
  const { convert, isProcessing: isConverting, error: convertError } = useConversion();

  const fileInputRef = useRef<HTMLInputElement>(null);

  const isProcessing = isCompressing || isConverting;
  const error = compressError || convertError;

  // Store URLs in a ref to properly clean them up on unmount without breaking Strict Mode
  const urlsRef = useRef<{ original: string | null; result: string | null }>({ original: null, result: null });

  useEffect(() => {
    return () => {
      if (urlsRef.current.original) URL.revokeObjectURL(urlsRef.current.original);
      if (urlsRef.current.result) URL.revokeObjectURL(urlsRef.current.result);
    };
  }, []);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
  };

  const executeProcessing = async (selectedFile: File, compLevel: number = 70) => {
    setResult(null);
    try {
      if (tool.engine === 'compression') {
        // Convert compression level (1-100) to quality (1-100) where higher compression = lower quality
        const quality = Math.max(1, 100 - compLevel);
        const res = await compress(selectedFile, quality / 100);
        if (urlsRef.current.result) URL.revokeObjectURL(urlsRef.current.result);
        urlsRef.current.result = res.url;
        setResult({ url: res.url, originalSize: res.originalSize, newSize: res.compressedSize, type: res.blob.type });
      } else if (tool.engine === 'conversion') {
        const toFormat = tool.options?.to || 'image/jpeg';
        const res = await convert(selectedFile, toFormat);
        if (urlsRef.current.result) URL.revokeObjectURL(urlsRef.current.result);
        urlsRef.current.result = res.url;
        setResult({ url: res.url, originalSize: res.originalSize, newSize: res.newSize });
      }
    } catch (err) {
      console.error(err);
    }
  };

  const processFile = (selectedFile: File) => {
    setFile(selectedFile);
    if (urlsRef.current.original) URL.revokeObjectURL(urlsRef.current.original);

    const newOriginalUrl = URL.createObjectURL(selectedFile);
    urlsRef.current.original = newOriginalUrl;
    setOriginalPreviewUrl(newOriginalUrl);

    // Initial process
    executeProcessing(selectedFile, compressionLevel);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      processFile(e.target.files[0]);
    }
  };

  const applyCompressionPreset = (level: number) => {
    setCompressionLevel(level);
    if (file) executeProcessing(file, level);
  };

  const handleCompressionChange = (val: number) => {
    setCompressionLevel(val);
  };

  const handleCompressionCommit = () => {
    if (file) executeProcessing(file, compressionLevel);
  };

  const formatSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    else if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    else return (bytes / 1048576).toFixed(2) + ' MB';
  };

  return (
    <div className="w-full max-w-5xl mx-auto my-12">
      {!file ? (
        <Dropzone 
          onFileSelect={processFile} 
          title={`Drop ${tool.engine === 'compression' ? 'image' : 'file'} here`}
          accept="image/*, .svg"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 pb-6 border-b border-border">
            <div>
              <p className="font-sans text-[13px] text-slate mb-1">Processing file</p>
              <h4 className="font-display font-bold text-lg text-ink truncate max-w-md">{file.name}</h4>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={() => setShowPreview(!showPreview)}
                className="flex items-center text-[13px] font-medium text-slate hover:text-ink transition-colors px-3 py-1.5 bg-background rounded-md"
              >
                {showPreview ? <><EyeOff className="w-4 h-4 mr-2"/> Hide Preview</> : <><Eye className="w-4 h-4 mr-2"/> Show Preview</>}
              </button>
              {isProcessing ? (
                <div className="flex items-center text-primary font-medium bg-primary/10 px-4 py-2 rounded-full text-sm">
                  <Loader2 className="w-4 h-4 animate-spin mr-2" /> Working...
                </div>
              ) : error ? (
                <div className="text-red-500 font-medium text-sm">Error</div>
              ) : result && (
                <div className="flex items-center text-green-600 font-medium bg-green-500/10 px-4 py-2 rounded-full text-sm">
                  Ready
                </div>
              )}
            </div>
          </div>

          {/* Tool Settings (Compression only) */}
          {tool.engine === 'compression' && (
            <div className="mb-8 p-6 bg-background rounded-xl border border-border">
              <div className="flex items-center gap-2 mb-6">
                <Settings2 className="w-5 h-5 text-slate" />
                <h3 className="font-display font-bold text-[15px] text-ink">Compression Settings</h3>
              </div>

              <div className="flex flex-wrap gap-2 mb-6">
                <button 
                  onClick={() => { setMode('default'); applyCompressionPreset(70); }}
                  className={`px-4 py-2 rounded-md text-[13px] font-medium transition-colors ${mode === 'default' ? 'bg-ink text-surface' : 'bg-surface border border-border text-slate hover:border-slate'}`}
                >
                  Default (Auto)
                </button>
                <button 
                  onClick={() => setMode('custom')}
                  className={`px-4 py-2 rounded-md text-[13px] font-medium transition-colors ${mode === 'custom' ? 'bg-ink text-surface' : 'bg-surface border border-border text-slate hover:border-slate'}`}
                >
                  Custom
                </button>
              </div>

              {mode === 'custom' && (
                <div className="space-y-6 animate-in fade-in slide-in-from-top-2 duration-200">
                  <div className="flex flex-wrap gap-2">
                    <button onClick={() => applyCompressionPreset(20)} className="px-3 py-1.5 rounded bg-surface border border-border text-[12px] text-slate hover:border-primary transition-colors">Low Compression</button>
                    <button onClick={() => applyCompressionPreset(50)} className="px-3 py-1.5 rounded bg-surface border border-border text-[12px] text-slate hover:border-primary transition-colors">Medium Compression</button>
                    <button onClick={() => applyCompressionPreset(80)} className="px-3 py-1.5 rounded bg-surface border border-border text-[12px] text-slate hover:border-primary transition-colors">High Compression</button>
                  </div>

                  <div className="flex items-center gap-4">
                    <div className="flex-1">
                      <div className="flex justify-between text-[11px] text-slate mb-2 font-medium uppercase tracking-wider">
                        <span>Low</span>
                        <span>High</span>
                      </div>
                      <input 
                        type="range" 
                        min="1" max="99" 
                        value={compressionLevel} 
                        onChange={(e) => handleCompressionChange(Number(e.target.value))}
                        onMouseUp={handleCompressionCommit}
                        onTouchEnd={handleCompressionCommit}
                        className="w-full accent-primary"
                      />
                    </div>
                    <div className="w-20 pt-5">
                      <div className="flex items-center border border-border bg-surface rounded-md overflow-hidden">
                        <input 
                          type="number" 
                          min="1" max="99"
                          value={compressionLevel}
                          onChange={(e) => handleCompressionChange(Number(e.target.value))}
                          onBlur={handleCompressionCommit}
                          className="w-full bg-transparent text-center text-[13px] font-mono py-1.5 outline-none"
                        />
                        <span className="text-[12px] text-slate pr-2">%</span>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Results Area */}
          {!isProcessing && result && (
            <div className="space-y-8 mb-8">
              {/* Size Stats */}
              <div className="flex flex-col md:flex-row items-center justify-between gap-4">
                <div className="flex-1 w-full bg-background border border-border rounded-lg p-5 text-center flex items-center justify-center gap-4">
                  <div className="text-left">
                    <p className="text-slate text-[12px] font-sans mb-1 uppercase tracking-wider">Original</p>
                    <p className="font-mono text-xl text-ink">{formatSize(result.originalSize)}</p>
                  </div>
                </div>
                <div className="text-slate">
                  <ArrowRight className="w-5 h-5" />
                </div>
                <div className="flex-1 w-full bg-primary/5 border border-primary/20 rounded-lg p-5 text-center flex items-center justify-center gap-4 relative">
                  <div className="text-left">
                    <p className="text-primary text-[12px] font-sans mb-1 uppercase tracking-wider">New Size</p>
                    <p className="font-mono font-bold text-xl text-primary">{formatSize(result.newSize)}</p>
                  </div>
                  {tool.engine === 'compression' && result.newSize <= result.originalSize && (
                    <div className="absolute top-2 right-2 bg-primary/20 text-primary text-[10px] font-bold px-2 py-0.5 rounded">
                      {result.newSize === result.originalSize ? '0% (Maxed)' : `-${Math.round((1 - result.newSize / result.originalSize) * 100)}%`}
                    </div>
                  )}
                </div>
              </div>

              {/* Visual Preview */}
              {showPreview && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="relative rounded-lg border border-border bg-background overflow-hidden aspect-video flex items-center justify-center">
                    {originalPreviewUrl ? (
                      // eslint-disable-next-line @next/next/no-img-element
                      <img src={originalPreviewUrl} alt="Original" className="max-w-full max-h-full object-contain" />
                    ) : <ImageIcon className="text-slate/20 w-12 h-12" />}
                    <div className="absolute top-2 left-2 bg-dark/70 backdrop-blur-sm text-surface text-[11px] px-2 py-1 rounded">Original</div>
                  </div>
                  <div className="relative rounded-lg border border-primary/20 bg-primary/5 overflow-hidden aspect-video flex items-center justify-center">
                    {result.url ? (
                      // eslint-disable-next-line @next/next/no-img-element
                      <img src={result.url} alt="Result" className="max-w-full max-h-full object-contain" />
                    ) : <Loader2 className="animate-spin text-primary w-8 h-8" />}
                    <div className="absolute top-2 left-2 bg-primary text-dark font-medium text-[11px] px-2 py-1 rounded">Result</div>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Actions */}
          <div className="flex flex-col-reverse md:flex-row items-stretch md:items-center justify-center gap-3 md:gap-4 pt-6 border-t border-border">
            <Button variant="outline" size="lg" className="w-full md:w-auto" onClick={() => {
              setFile(null);
              setResult(null);
            }}>
              Start Over
            </Button>
            {result && (
              <a 
                href={result.url} 
                download={`singulariti_${file.name.replace(/\.[^/.]+$/, "")}.${(tool.options?.to || result.type || '').includes('svg') ? 'svg' : (tool.options?.to ? tool.options.to.split('/')[1] : (result.type ? result.type.split('/')[1] : file.name.split('.').pop()))}`}
                className="w-full md:w-auto"
              >
                <Button variant="primary" size="lg" className="w-full" leftIcon={<Download className="w-5 h-5" />}>
                  Download {tool.engine === 'compression' ? 'Compressed' : 'Converted'} Image
                </Button>
              </a>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect } from 'react';
import { ToolRegistryItem } from '../../registry/types';
import { Dropzone } from '../ui/Dropzone';
import { Button } from '../ui/Button';
import { Info, Maximize, FileCode2, Droplet, Palette as PaletteIcon, Copy, CheckCircle2, MousePointer2, Download } from 'lucide-react';

interface UtilityEngineProps {
  tool: ToolRegistryItem;
}

export function UtilityEngine({ tool }: UtilityEngineProps) {
  const [file, setFile] = useState<File | null>(null);
  const [imageUrl, setImageUrl] = useState<string | null>(null);

  // States for different tools
  const [dimensions, setDimensions] = useState<{w: number, h: number, ratio: string} | null>(null);
  const [realFormat, setRealFormat] = useState<{hex: string, mime: string} | null>(null);

  const [pickedColor, setPickedColor] = useState<{hex: string, rgb: string} | null>(null);
  const [hoverColor, setHoverColor] = useState<{hex: string, rgb: string} | null>(null);
  const [palette, setPalette] = useState<{hex: string, rgb: string}[]>(([]));
  const [paletteCount, setPaletteCount] = useState<number>(6);

  const [copied, setCopied] = useState<string | null>(null);

  const imgRef = useRef<HTMLImageElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    return () => {
      if (imageUrl) URL.revokeObjectURL(imageUrl);
    };
  }, [imageUrl]);

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(text);
    setTimeout(() => setCopied(null), 2000);
  };

  const exportPalette = () => {
    if (palette.length === 0) return;
    const csv = 'HEX,RGB\n' + palette.map(p => `${p.hex},"${p.rgb}"`).join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `singulariti_palette_${file?.name || 'export'}.csv`;
    a.click();
  };

  const processFile = async (selectedFile: File) => {
    setFile(selectedFile);
    if (imageUrl) URL.revokeObjectURL(imageUrl);

    const url = URL.createObjectURL(selectedFile);
    setImageUrl(url);

    // If format detector, read magic numbers
    if (tool.id === 'image-format-detector') {
      const buffer = await selectedFile.slice(0, 4).arrayBuffer();
      const arr = new Uint8Array(buffer);
      const hex = Array.from(arr).map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase();

      let mime = 'Unknown';
      if (hex.startsWith('FFD8FF')) mime = 'image/jpeg';
      else if (hex.startsWith('89504E47')) mime = 'image/png';
      else if (hex.startsWith('47494638')) mime = 'image/gif';
      else if (hex.startsWith('52494646')) mime = 'image/webp (RIFF header)';
      else if (hex.startsWith('49492A00') || hex.startsWith('4D4D002A')) mime = 'image/tiff';
      else if (hex.startsWith('00000100')) mime = 'image/x-icon';

      setRealFormat({ hex, mime });
    }
  };

  const extractPaletteData = (img: HTMLImageElement, count: number) => {
    try {
      const tempCanvas = document.createElement('canvas');
      const tempCtx = tempCanvas.getContext('2d');
      if (!tempCtx) return;
      tempCanvas.width = 100;
      tempCanvas.height = 100;
      tempCtx.drawImage(img, 0, 0, 100, 100);
      const data = tempCtx.getImageData(0, 0, 100, 100).data;

      const colorMap = new Map<string, {count: number, r: number, g: number, b: number}>();
      for (let i = 0; i < data.length; i += 4) {
        if (data[i+3] < 128) continue; // ignore transparent
        const r = data[i], g = data[i+1], b = data[i+2];
        const qR = Math.round(r / 32) * 32;
        const qG = Math.round(g / 32) * 32;
        const qB = Math.round(b / 32) * 32;
        const key = `${qR},${qG},${qB}`;

        if (!colorMap.has(key)) colorMap.set(key, { count: 1, r, g, b });
        else colorMap.get(key)!.count++;
      }

      const sorted = Array.from(colorMap.values()).sort((a, b) => b.count - a.count).slice(0, count);
      const formatPalette = sorted.map(c => {
        const rgb = `rgb(${c.r}, ${c.g}, ${c.b})`;
        const hex = '#' + [c.r, c.g, c.b].map(x => x.toString(16).padStart(2, '0')).join('');
        return { hex, rgb };
      });
      setPalette(formatPalette);
    } catch (err) {
      console.error("Extraction failed", err);
    }
  };

  useEffect(() => {
    if (tool.id === 'image-color-palette-extractor' && imgRef.current && imgRef.current.complete) {
      const t = setTimeout(() => {
        extractPaletteData(imgRef.current!, paletteCount);
      }, 150);
      return () => clearTimeout(t);
    }
  }, [paletteCount, tool.id, imageUrl]);

  const onImageLoad = async (e: React.SyntheticEvent<HTMLImageElement>) => {
    const img = e.currentTarget;
    const w = img.naturalWidth;
    const h = img.naturalHeight;

    // Calculate simplified aspect ratio
    const gcd = (a: number, b: number): number => b === 0 ? a : gcd(b, a % b);
    const divisor = gcd(w, h);
    setDimensions({ w, h, ratio: `${w/divisor}:${h/divisor}` });

    if (tool.id === 'image-color-palette-extractor') {
      extractPaletteData(img, paletteCount);
    }

    if (tool.id === 'color-picker-from-image' || tool.id === 'image-color-palette-extractor') {
      // Draw to canvas for picking
      const canvas = canvasRef.current;
      if (canvas && img) {
        canvas.width = img.naturalWidth;
        canvas.height = img.naturalHeight;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0);
        }
      }
    }
  };

  const getCanvasColor = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return null;
    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const pixel = ctx.getImageData(x, y, 1, 1).data;
    const r = pixel[0], g = pixel[1], b = pixel[2];
    const rgb = `rgb(${r}, ${g}, ${b})`;
    const hex = '#' + [r, g, b].map(val => val.toString(16).padStart(2, '0')).join('');

    return { rgb, hex };
  };

  const handleCanvasClick = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (tool.id !== 'color-picker-from-image' && tool.id !== 'image-color-palette-extractor') return;
    const color = getCanvasColor(e);
    if (color) setPickedColor(color);
  };

  const handleCanvasMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (tool.id !== 'color-picker-from-image' && tool.id !== 'image-color-palette-extractor') return;
    const color = getCanvasColor(e);
    if (color) setHoverColor(color);
  };

  const formatSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    else if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
    else return (bytes / 1048576).toFixed(2) + ' MB';
  };

  const InfoCard = ({ label, value, interactive = false }: { label: string, value: React.ReactNode, interactive?: boolean }) => (
    <div className={`bg-background border border-border p-4 rounded-lg flex flex-col items-center text-center justify-center min-w-0 ${interactive ? 'group cursor-pointer' : ''}`}>
      <span className="text-[12px] font-medium text-slate uppercase tracking-wider mb-1 flex-shrink-0">{label}</span>
      <div className={`text-lg font-mono text-ink font-bold w-full transition-all duration-200 ${interactive ? 'truncate group-hover:whitespace-normal group-hover:break-all group-active:whitespace-normal group-active:break-all' : 'truncate'}`}>
        {value}
      </div>
    </div>
  );

  return (
    <div className="w-full max-w-5xl mx-auto my-12">
      {!file ? (
        <Dropzone 
          onFileSelect={processFile} 
          title="Drop image to analyze"
        />
      ) : (
        <div className="bg-surface border border-border rounded-xl p-6 md:p-8 shadow-sm">
          {/* Header */}
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 pb-6 border-b border-border">
            <div>
              <p className="font-sans text-[13px] text-slate mb-1">Analyzing file</p>
              <h4 className="font-display font-bold text-lg text-ink truncate max-w-md">{file.name}</h4>
            </div>
            <div className="flex items-center gap-3">
              <Button variant="outline" size="sm" onClick={() => {
                setFile(null);
                setPickedColor(null);
                setPalette([]);
              }}>
                Start Over
              </Button>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left: Tools / Results */}
            <div className="lg:col-span-1 space-y-6">

              {tool.id === 'image-metadata-viewer' && (
                <div className="space-y-4">
                  <h3 className="font-display font-bold flex items-center text-ink"><Info className="w-5 h-5 mr-2" /> File Metadata</h3>
                  <InfoCard label="File Name (Hover to expand)" value={file.name} interactive={true} />
                  <InfoCard label="File Size" value={formatSize(file.size)} />
                  <InfoCard label="MIME Type" value={file.type || 'Unknown'} />
                  <InfoCard label="Last Modified" value={<span className="text-sm">{new Date(file.lastModified).toLocaleString()}</span>} />
                </div>
              )}

              {tool.id === 'image-dimension-checker' && dimensions && (
                <div className="space-y-4">
                  <h3 className="font-display font-bold flex items-center text-ink"><Maximize className="w-5 h-5 mr-2" /> Dimensions</h3>
                  <InfoCard label="Width" value={`${dimensions.w} px`} />
                  <InfoCard label="Height" value={`${dimensions.h} px`} />
                  <InfoCard label="Aspect Ratio" value={dimensions.ratio} />
                </div>
              )}

              {tool.id === 'image-format-detector' && realFormat && (
                <div className="space-y-4">
                  <h3 className="font-display font-bold flex items-center text-ink"><FileCode2 className="w-5 h-5 mr-2" /> Format Analysis</h3>
                  <p className="text-[13px] text-slate mb-4">We read the magic numbers (file signature) at the start of the file to determine its true format, ignoring the extension.</p>
                  <InfoCard label="Extension" value={file.name.split('.').pop()?.toUpperCase() || 'NONE'} />
                  <InfoCard label="True Format" value={<span className={realFormat.mime !== 'Unknown' ? 'text-primary' : 'text-amber-500'}>{realFormat.mime}</span>} />
                  <InfoCard label="Hex Signature" value={realFormat.hex} />
                </div>
              )}

              {(tool.id === 'color-picker-from-image' || tool.id === 'image-color-palette-extractor') && (
                <div className="space-y-4">
                  <h3 className="font-display font-bold flex items-center text-ink"><Droplet className="w-5 h-5 mr-2" /> Color Picker</h3>
                  <p className="text-[13px] text-slate mb-4">Click anywhere on the image preview to extract the exact pixel color.</p>

                  {pickedColor || hoverColor ? (
                    <div className="space-y-3">
                      <div className="w-full h-24 rounded-lg border border-border shadow-inner transition-colors flex items-end p-2" style={{ backgroundColor: hoverColor ? hoverColor.hex : pickedColor ? pickedColor.hex : 'transparent' }}>
                         {hoverColor && <span className="bg-ink/60 text-background text-[11px] px-2 py-1 rounded backdrop-blur-sm shadow-sm flex items-center"><MousePointer2 className="w-3 h-3 mr-1" /> {hoverColor.hex.toUpperCase()}</span>}
