"use client";

import React, { useEffect, useRef, useState } from 'react';
import { pdfjsLib } from '@/lib/pdfjsSetup';
// import { renderPageToCanvas } from '../../lib/pdf/pdfRenderHelpers';
import { Loader2 } from 'lucide-react';

interface PageThumbnailProps {
  pdfDoc: pdfjsLib.PDFDocumentProxy;
  pageNumber: number;
  scale?: number;
  className?: string;
  style?: React.CSSProperties;
  onRenderSuccess?: () => void;
}

export function PageThumbnail({
  pdfDoc,
  pageNumber,
  scale = 0.3,
  className = '',
  style,
  onRenderSuccess
}: PageThumbnailProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [dimensions, setDimensions] = useState<{ width: number; height: number } | null>(null);

  useEffect(() => {
    let active = true;
    let renderTask: any = null;

    async function draw() {
      if (!canvasRef.current) return;
      setLoading(true);
      setError(null);

      try {
        const page = await pdfDoc.getPage(pageNumber);
        const viewport = page.getViewport({ scale });
        
        if (!active || !canvasRef.current) return;
        
        canvasRef.current.height = viewport.height;
        canvasRef.current.width = viewport.width;
        
        const canvasContext = canvasRef.current.getContext('2d');
        if (!canvasContext) {
          throw new Error('Could not get 2D context from canvas');
        }
        
        const renderContext = {
          canvasContext,
          viewport,
          canvas: canvasRef.current,
        };
        
        renderTask = page.render(renderContext);
        await renderTask.promise;
        
        if (active) {
          setDimensions({ width: viewport.width, height: viewport.height });
          setLoading(false);
          if (onRenderSuccess) onRenderSuccess();
        }
      } catch (err: any) {
        if (err && err.name === 'RenderingCancelledException') {
          return;
        }
        console.error('Error rendering thumbnail: ', err);
        if (active) {
          setError(err.message || 'Render failed');
          setLoading(false);
        }
      }
    }

    draw();

    return () => {
      active = false;
      if (renderTask) {
        try {
          renderTask.cancel();
        } catch (e) {}
      }
      // memory cleanup
      if (canvasRef.current) {
        canvasRef.current.width = 0;
        canvasRef.current.height = 0;
      }
    };
  }, [pdfDoc, pageNumber, scale, onRenderSuccess]);

  return (
    <div 
      className={`relative inline-flex items-center justify-center bg-background border border-border rounded-lg overflow-hidden select-none max-w-full ${className}`}
      style={{
        ...style,
        aspectRatio: dimensions ? `${dimensions.width} / ${dimensions.height}` : undefined,
        width: dimensions ? `${dimensions.width}px` : undefined,
        height: 'auto',
      }}
    >
      <canvas ref={canvasRef} className="w-full h-full block" />
      
      {loading && (
        <div className="absolute inset-0 flex items-center justify-center bg-surface/50 backdrop-blur-xs">
          <Loader2 className="w-5 h-5 animate-spin text-primary" />
        </div>
      )}
      
      {error && (
        <div className="absolute inset-0 flex items-center justify-center bg-red-500/10 p-2 text-center">
          <span className="text-[10px] text-red-500 font-sans leading-tight">Error rendering page</span>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState } from 'react';
import { Copy, ExternalLink, Download, Check, Clipboard } from 'lucide-react';
import { Button } from '../ui/Button';
import { downloadBlob } from '../../lib/downloadHelpers';
import { QRScanResult } from '../../lib/qr/qrHelpers';

interface QRScannerResultProps {
  result: QRScanResult;
  onClear?: () => void;
}

export function QRScannerResult({ result, onClear }: QRScannerResultProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(result.rawText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const blob = new Blob([result.rawText], { type: 'text/plain;charset=utf-8' });
    const safeName = result.rawText.substring(0, 15).replace(/[^a-zA-Z0-9]/g, '_') || 'qr_result';
    downloadBlob(blob, `${safeName}_qr_result.txt`);
  };

  const isUrl = result.type === 'url' || result.rawText.startsWith('http://') || result.rawText.startsWith('https://');

  return (
    <div className="bg-surface border border-border rounded-xl p-6 shadow-sm max-w-2xl mx-auto w-full animate-in fade-in slide-in-from-top-4 duration-300">
      <div className="flex items-center justify-between pb-4 border-b border-border mb-4">
        <div>
          <span className="text-[10px] font-sans font-bold uppercase tracking-wider text-primary bg-primary/10 px-2 py-1 rounded-full">
            Detected: {result.type}
          </span>
          <h4 className="font-display font-bold text-lg text-ink mt-2">Scan Result</h4>
        </div>
        {onClear && (
          <Button variant="ghost" size="sm" onClick={onClear}>
            Clear
          </Button>
        )}
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-[11px] font-sans text-slate uppercase tracking-wider font-semibold mb-1">
            Formatted Description
          </label>
          <div className="p-3 bg-background border border-border rounded-lg text-sm text-ink font-sans leading-relaxed">
            {result.formattedOutput}
          </div>
        </div>

        <div>
          <label className="block text-[11px] font-sans text-slate uppercase tracking-wider font-semibold mb-1">
            Raw Content
          </label>
          <pre className="p-3 bg-background border border-border rounded-lg text-[12px] text-slate font-mono whitespace-pre-wrap break-all max-h-[150px] overflow-y-auto">
            {result.rawText}
          </pre>
        </div>

        {/* Action Controls */}
        <div className="flex flex-wrap items-center gap-3 pt-4 border-t border-border">
          <Button
            variant="outline"
            size="sm"
            onClick={handleCopy}
            leftIcon={copied ? <Check className="w-4 h-4 text-green-500" /> : <Clipboard className="w-4 h-4" />}
          >
            {copied ? 'Copied' : 'Copy'}
          </Button>

          {isUrl && (
            <a
              href={result.rawText.startsWith('http') ? result.rawText : `https://${result.rawText}`}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-block"
            >
              <Button
                variant="outline"
                size="sm"
                leftIcon={<ExternalLink className="w-4 h-4" />}
              >
                Open Link
              </Button>
            </a>
          )}

          <Button
            variant="outline"
            size="sm"
            onClick={handleDownload}
            leftIcon={<Download className="w-4 h-4" />}
          >
            Download Text
          </Button>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { 
  // Compressors
  Minimize, Shrink,
  // Converters
  ArrowRightLeft, FileImage, FileText, FileCode2, Binary, Frame, CodeXml, Combine, Replace,
  // Editing
  Crop, Maximize, RotateCw, FlipHorizontal, Wand2, Filter, Sun, Palette, Blend, Stamp, Type as TypeIcon, Search, Pipette, Droplets, Zap, Image as ImageIcon,
  // PDF
  SplitSquareHorizontal, FileMinus, FileOutput, FileLock2, LockOpen, PenTool, FileDigit, FileText as PdfFile, FileWarning,
  // Dev
  Braces, ListTree, Database, KeyRound, Link, Regex, Hash, CheckCircle2, Minimize2, Code, ShieldCheck, Bug, BoxSelect,
  // Calculators
  Calculator, Landmark, TrendingUp, Banknote, CalendarClock, Activity, Tag, Percent, Fuel, Zap as ZapIcon, Coins, LineChart, Wallet,
  // SEO
  Globe2, Waypoints, BotMessageSquare, BarChart2, ScanSearch, LineChart as ChartLine, MonitorSmartphone,
  // Text
  BookType, CaseSensitive, ArrowDownAZ, WrapText, MailSearch, TextQuote, SpellCheck, RefreshCw, FileDiff,
  // Unit Conversion
  Ruler, Weight, Thermometer, SquareDashed, Beaker, Hourglass, Scale, Compass, Gauge,
  // QR
  QrCode, ScanLine, Wifi, Smartphone, Mail, Briefcase, Globe
} from 'lucide-react';

interface ToolIconProps {
  toolId: string;
  className?: string; 
  fallback?: React.ReactNode;
}

export function ToolIcon({ toolId, className = "w-14 h-14" }: ToolIconProps) {
  const id = toolId.toLowerCase();

  // Determine the single most relevant icon for the tool
  let IconComponent: React.ElementType = Code;

  // ==========================================
  // IMAGE TOOLS
  // ==========================================
  if (id.includes('compressor') || id.includes('compress')) IconComponent = Minimize;
  else if (id.includes('crop')) IconComponent = Crop;
  else if (id.includes('resize')) IconComponent = Maximize;
  else if (id.includes('rotate')) IconComponent = RotateCw;
  else if (id.includes('flip')) IconComponent = FlipHorizontal;
  else if (id.includes('upscaler') || id.includes('enhance')) IconComponent = Wand2;
  else if (id.includes('blur')) IconComponent = Droplets;
  else if (id.includes('sharpen')) IconComponent = Zap;
  else if (id.includes('denoise') || id.includes('pixelate') || id.includes('filter')) IconComponent = Filter;
  else if (id.includes('brightness')) IconComponent = Sun;
  else if (id.includes('color-adjuster') || id.includes('palette')) IconComponent = Palette;
  else if (id.includes('grayscale') || id.includes('black-and-white')) IconComponent = Blend;
  else if (id.includes('watermark') || id.includes('stamp')) IconComponent = Stamp;
  else if (id.includes('add-text')) IconComponent = TypeIcon;
  else if (id.includes('metadata')) IconComponent = Search;
  else if (id.includes('dimension')) IconComponent = BoxSelect;
  else if (id.includes('color-picker')) IconComponent = Pipette;
  else if (id.includes('to-pdf')) IconComponent = PdfFile;
  else if (id.includes('to-jpg') || id.includes('to-png') || id.includes('to-webp')) IconComponent = FileImage;
  else if (id.includes('to-svg')) IconComponent = FileCode2;
  else if (id.includes('to-text')) IconComponent = FileText;
  else if (id.includes('base64')) IconComponent = Binary;

  // ==========================================
  // PDF TOOLS
  // ==========================================
  else if (id.includes('pdf')) {
    if (id === 'merge-pdf') IconComponent = Combine;
    else if (id === 'split-pdf') IconComponent = SplitSquareHorizontal;
    else if (id === 'rotate-pdf') IconComponent = RotateCw;
    else if (id === 'delete-pdf-pages') IconComponent = FileMinus;
    else if (id === 'rearrange-pdf-pages') IconComponent = ArrowRightLeft;
    else if (id === 'extract-pdf-pages') IconComponent = FileOutput;
    else if (id === 'compress-pdf') IconComponent = Minimize;
    else if (id === 'protect-pdf') IconComponent = FileLock2;
    else if (id === 'unlock-pdf') IconComponent = LockOpen;
    else if (id === 'sign-pdf') IconComponent = PenTool;
    else if (id === 'watermark-pdf') IconComponent = Stamp;
    else if (id === 'metadata-viewer') IconComponent = Search;
