'use client';

import React, { useState } from 'react';
import { CalculatorLayout } from '../CalculatorLayout';
import { Button } from '@/components/ui/Button';

interface BasicCalculatorViewProps {
  toolId: string;
  title: string;
  description: string;
}

export function BasicCalculatorView({ toolId, title, description }: BasicCalculatorViewProps) {
  const [display, setDisplay] = useState('0');
  const [equation, setEquation] = useState('');
  const [isFinished, setIsFinished] = useState(false);

  const handleDigit = (digit: string) => {
    if (isFinished) {
      setDisplay(digit);
      setEquation(digit);
      setIsFinished(false);
      return;
    }
    if (display === '0') {
      setDisplay(digit);
      setEquation(digit);
    } else {
      setDisplay(display + digit);
      setEquation(equation + digit);
    }
  };

  const handleOperator = (op: string) => {
    if (isFinished) {
      setEquation(display + ' ' + op + ' ');
      setDisplay('0');
      setIsFinished(false);
      return;
    }
    // Avoid double operators
    const trimmed = equation.trim();
    if (['+', '-', '*', '/'].includes(trimmed.slice(-1))) {
      setEquation(trimmed.slice(0, -1) + ' ' + op + ' ');
    } else {
      setEquation(equation + ' ' + op + ' ');
    }
    setDisplay('0');
  };

  const handleDecimal = () => {
    if (isFinished) {
      setDisplay('0.');
      setEquation('0.');
      setIsFinished(false);
      return;
    }
    if (!display.includes('.')) {
      setDisplay(display + '.');
      setEquation(equation + '.');
    }
  };

  const handleClear = () => {
    setDisplay('0');
    setEquation('');
    setIsFinished(false);
  };

  const handleBackspace = () => {
    if (isFinished) {
      handleClear();
      return;
    }
    if (display.length > 1) {
      setDisplay(display.slice(0, -1));
      setEquation(equation.slice(0, -1));
    } else {
      setDisplay('0');
      setEquation(equation.slice(0, -1) || '0');
    }
  };

  const handlePercentage = () => {
    try {
      const value = parseFloat(display);
      if (isNaN(value)) return;
      const pct = (value / 100).toString();
      setDisplay(pct);
      setEquation(equation.slice(0, -display.length) + pct);
    } catch {
      // ignore
    }
  };

  const handleEquals = () => {
    try {
      // Safe client side evaluation
      // Replace display operations
      const sanitized = equation.replace(/×/g, '*').replace(/÷/g, '/');
      if (!sanitized.trim()) return;

      // Evaluate equation safely
      // A regex check to ensure only mathematical characters are allowed
      if (!/^[0-9.+\-*/\s()]+$/.test(sanitized)) {
        throw new Error("Invalid character");
      }

      // Safe eval
      const result = Function(`"use strict"; return (${sanitized})`)();
      const resultStr = Number.isInteger(result) ? result.toString() : result.toFixed(6).replace(/\.?0+$/, '');
      
      setDisplay(resultStr);
      setEquation(equation + ' = ' + resultStr);
      setIsFinished(true);
    } catch {
      setDisplay('Error');
      setEquation('');
      setIsFinished(true);
    }
  };

  const buttons = [
    { label: 'C', onClick: handleClear, type: 'clear' },
    { label: '⌫', onClick: handleBackspace, type: 'action' },
    { label: '%', onClick: handlePercentage, type: 'action' },
    { label: '/', onClick: () => handleOperator('/'), type: 'operator' },
    
    { label: '7', onClick: () => handleDigit('7'), type: 'num' },
    { label: '8', onClick: () => handleDigit('8'), type: 'num' },
    { label: '9', onClick: () => handleDigit('9'), type: 'num' },
    { label: '*', onClick: () => handleOperator('*'), type: 'operator' },
    
    { label: '4', onClick: () => handleDigit('4'), type: 'num' },
    { label: '5', onClick: () => handleDigit('5'), type: 'num' },
    { label: '6', onClick: () => handleDigit('6'), type: 'num' },
    { label: '-', onClick: () => handleOperator('-'), type: 'operator' },
    
    { label: '1', onClick: () => handleDigit('1'), type: 'num' },
    { label: '2', onClick: () => handleDigit('2'), type: 'num' },
    { label: '3', onClick: () => handleDigit('3'), type: 'num' },
    { label: '+', onClick: () => handleOperator('+'), type: 'operator' },
    
    { label: '0', onClick: () => handleDigit('0'), type: 'num', className: 'col-span-2' },
    { label: '.', onClick: handleDecimal, type: 'num' },
    { label: '=', onClick: handleEquals, type: 'equals' },
  ];

  return (
    <CalculatorLayout
      toolId={toolId}
      title={title}
      description={description}
      onCalculate={(e) => e.preventDefault()}
      onReset={handleClear}
      formula="Basic arithmetic follows algebraic precedence: Addition (+), Subtraction (-), Multiplication (×), and Division (÷)."
      example="Expression: 12 + 8 × 3 = 36 (Multiplication occurs before addition)"
      inputs={
        <div className="flex flex-col gap-4 w-full">
          <div className="bg-background border border-border rounded-xl p-4 flex flex-col items-end min-h-24 justify-between font-mono">
            <span className="text-sm text-slate select-all truncate max-w-full">{equation || '\u00A0'}</span>
            <span className="text-3xl font-bold text-primary truncate max-w-full">{display}</span>
          </div>
          <div className="grid grid-cols-4 gap-2.5">
            {buttons.map((btn, idx) => {
              let btnClass = 'p-4 rounded-xl text-center font-mono font-bold text-lg transition-colors cursor-pointer ';
              if (btn.type === 'clear') {
                btnClass += 'bg-red-500/10 text-red-500 hover:bg-red-500/20';
              } else if (btn.type === 'operator' || btn.type === 'action') {
                btnClass += 'bg-primary/10 text-primary hover:bg-primary/20';
              } else if (btn.type === 'equals') {
                btnClass += 'bg-primary text-white hover:bg-primary/95';
              } else {
                btnClass += 'bg-surface border border-border text-ink hover:bg-surface/80';
              }
              return (
                <button
                  key={idx}
                  onClick={btn.onClick}
                  className={`${btnClass} ${btn.className || ''}`}
                >
                  {btn.label}
                </button>
              );
            })}
          </div>
        </div>
      }
      results={
        <div className="bg-surface/50 border border-border rounded-xl p-5 text-center text-slate font-sans text-sm h-full flex items-center justify-center">
          Interactive digital pocket calculator. Click key buttons on screen to evaluate numbers.
        </div>
      }
    />
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { CalculatorLayout } from '../CalculatorLayout';
import { CalculatorInput } from '../CalculatorInput';
import { CalculatorSelect } from '../CalculatorSelect';
import { CalculatorResult } from '../CalculatorResult';
import { validatePositiveNumber } from '@/lib/calculators/calculatorValidation';

interface CurrencyConverterViewProps {
  toolId: string;
  title: string;
  description: string;
}

const STATIC_RATES: Record<string, number> = {
  USD: 1.0,
  INR: 83.50,
  EUR: 0.92,
  GBP: 0.79,
  JPY: 156.2,
  AUD: 1.51,
  CAD: 1.37,
  SGD: 1.35,
  AED: 3.67,
  CNY: 7.24
};

const CURRENCY_LABELS: Record<string, string> = {
  USD: 'USD - US Dollar ($)',
  INR: 'INR - Indian Rupee (₹)',
  EUR: 'EUR - Euro (€)',
  GBP: 'GBP - British Pound (£)',
  JPY: 'JPY - Japanese Yen (¥)',
  AUD: 'AUD - Australian Dollar (A$)',
  CAD: 'CAD - Canadian Dollar (C$)',
  SGD: 'SGD - Singapore Dollar (S$)',
  AED: 'AED - UAE Dirham (د.إ)',
  CNY: 'CNY - Chinese Yuan (¥)'
};

export function CurrencyConverterView({ toolId, title, description }: CurrencyConverterViewProps) {
  const [amount, setAmount] = useState<number>(100);
  const [fromCurrency, setFromCurrency] = useState<string>('USD');
  const [toCurrency, setToCurrency] = useState<string>('INR');
  const [customRate, setCustomRate] = useState<number>(83.50);
  const [isManualRate, setIsManualRate] = useState<boolean>(false);
  const [rates, setRates] = useState<Record<string, number>>(STATIC_RATES);
  const [isLoadingRates, setIsLoadingRates] = useState<boolean>(true);
  const [result, setResult] = useState<{
    convertedAmount: number;
    rateUsed: number;
  } | null>(null);

  const [errors, setErrors] = useState<{
    amount?: string | null;
    customRate?: string | null;
  }>({});

  // Fetch live exchange rates on mount and every 1 hour
  useEffect(() => {
    const fetchRates = () => {
      setIsLoadingRates(true);
      fetch('https://open.er-api.com/v6/latest/USD')
        .then(res => res.json())
        .then(data => {
          if (data && data.rates) {
            setRates(data.rates);
          }
        })
        .catch(err => console.error('Failed to fetch live currency rates:', err))
        .finally(() => setIsLoadingRates(false));
    };

    fetchRates();
    const interval = setInterval(fetchRates, 3600000);
    return () => clearInterval(interval);
  }, []);

  // Recalculate rate when currencies change (if not in manual edit mode)
  useEffect(() => {
    if (!isManualRate) {
      const fromRate = rates[fromCurrency] || 1.0;
      const toRate = rates[toCurrency] || 1.0;
      const rate = (1 / fromRate) * toRate;
      setCustomRate(parseFloat(rate.toFixed(4)));
    }
  }, [fromCurrency, toCurrency, isManualRate, rates]);

  // Auto-calculate on changes
  useEffect(() => {
    if (amount >= 0 && customRate >= 0) {
      const convertedAmount = amount * customRate;
      setResult({
        convertedAmount,
        rateUsed: customRate
      });
      setErrors({});
    }
  }, [amount, customRate]);

  const handleCalculate = (e: React.FormEvent) => {
    e.preventDefault();
  };

  const handleReset = () => {
    setAmount(100);
    setFromCurrency('USD');
    setToCurrency('INR');
    setIsManualRate(false);
    setResult(null);
    setErrors({});
  };

  const currencyOptions = Object.keys(rates).map(code => ({
    value: code,
    label: CURRENCY_LABELS[code] || code
  })).sort((a, b) => a.value.localeCompare(b.value));

  const formula = "Converted Amount = Amount × Exchange Rate\nExchange Rate (computed) = (1 / USD-rate-of-From) × USD-rate-of-To";
  const example = `Convert: 100 USD to INR, Rate: 83.50\nConverted Value: 100 × 83.50 = ₹8,350.00`;

  const resultItems = result ? [
    { label: 'Source Amount', value: `${amount.toFixed(2)} ${fromCurrency}` },
    { label: 'Exchange Rate', value: `${result.rateUsed.toFixed(4)}` },
    { label: 'Target Amount', value: `${result.convertedAmount.toFixed(2)} ${toCurrency}` },
  ] : [];

  const inputs = (
    <>
      <CalculatorInput
        label="Amount to Convert"
        value={amount || ''}
        onChange={(val) => setAmount(val)}
        error={errors.amount}
        required
      />
      <div className="grid grid-cols-2 gap-4">
        <CalculatorSelect
          label="From Currency"
          value={fromCurrency}
          onChange={(e) => {
            setFromCurrency(e.target.value);
            setIsManualRate(false);
          }}
          options={currencyOptions}
        />
        <CalculatorSelect
          label="To Currency"
          value={toCurrency}
          onChange={(e) => {
            setToCurrency(e.target.value);
            setIsManualRate(false);
          }}
          options={currencyOptions}
        />
      </div>

      <div className="pt-2 space-y-3">
        <label className="flex items-center gap-2 font-sans text-sm text-slate select-none cursor-pointer">
          <input
            type="checkbox"
            checked={isManualRate}
            onChange={(e) => {
              setIsManualRate(e.target.checked);
              setResult(null);
            }}
            className="w-4 h-4 rounded border-border text-primary focus:ring-primary/20 accent-primary cursor-pointer bg-surface"
          />
          <span className="font-semibold text-ink">Override exchange rate manually</span>
        </label>

        {isManualRate && (
          <CalculatorInput
            label={`Custom Rate (1 ${fromCurrency} = ? ${toCurrency})`}
            value={customRate || ''}
            onChange={(val) => setCustomRate(val)}
            step="0.0001"
            error={errors.customRate}
            required
          />
        )}
      </div>
    </>
  );

  const results = result ? (
    <CalculatorResult
      title="Conversion Results"
      highlightLabel="Converted Total"
      highlightValue={`${result.convertedAmount.toFixed(2)} ${toCurrency}`}
      items={resultItems}
    >
      <div className="mt-4 p-3 bg-primary/5 border border-primary/10 rounded-lg text-[11px] font-sans text-slate text-center leading-relaxed">
        <strong>Note:</strong> Currency rates are fetched live from open.er-api.com. Feel free to adjust the rate above manually if needed.
      </div>
    </CalculatorResult>
  ) : (
    <div className="bg-background border border-border rounded-xl p-6 text-center text-slate font-sans text-sm">
      Enter currency parameters and click Calculate to view target conversions.
    </div>
  );

  return (
    <CalculatorLayout
      toolId={toolId}
      title={title}
      description={description}
      onCalculate={handleCalculate}
      onReset={handleReset}
      inputs={inputs}
      results={results}
      formula={formula}
      example={example}
    />
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { CalculatorLayout } from '../CalculatorLayout';
import { CalculatorInput } from '../CalculatorInput';
import { CalculatorSelect } from '../CalculatorSelect';
import { CalculatorResult } from '../CalculatorResult';
import { validatePositiveNumber } from '@/lib/calculators/calculatorValidation';

interface SimpleInterestCalculatorViewProps {
  toolId: string;
  title: string;
  description: string;
}

export function SimpleInterestCalculatorView({ toolId, title, description }: SimpleInterestCalculatorViewProps) {
  const [solveFor, setSolveFor] = useState<'interest' | 'principal' | 'rate' | 'time'>('interest');
  const [principal, setPrincipal] = useState<number>(50000);
  const [rate, setRate] = useState<number>(6.5);
  const [time, setTime] = useState<number>(3);
  const [timeUnit, setTimeUnit] = useState<'years' | 'months'>('years');
  const [interest, setInterest] = useState<number>(9750);
  
  const [result, setResult] = useState<{
    principal: number;
    rate: number;
    time: number;
    interest: number;
    totalAmount: number;
  } | null>(null);

  const [errors, setErrors] = useState<Record<string, string | null>>({});

  const handleCalculate = (e: React.FormEvent) => {
    e.preventDefault();
    const errs: Record<string, string | null> = {};

    const tPeriod = timeUnit === 'months' ? time / 12 : time;

    if (solveFor !== 'principal') {
      errs.principal = validatePositiveNumber(principal, 'Principal Amount');
    }
    if (solveFor !== 'rate') {
      errs.rate = validatePositiveNumber(rate, 'Interest Rate %');
    }
    if (solveFor !== 'time') {
      errs.time = validatePositiveNumber(time, 'Time Period');
    }
    if (solveFor === 'principal' || solveFor === 'rate' || solveFor === 'time') {
      errs.interest = validatePositiveNumber(interest, 'Interest Amount');
    }

    if (Object.values(errs).some(x => x !== null)) {
      setErrors(errs);
      setResult(null);
      return;
    }

    setErrors({});
    let p = principal;
    let r = rate;
    let t = tPeriod;
    let i = interest;

    if (solveFor === 'interest') {
      i = (p * r * t) / 100;
    } else if (solveFor === 'principal') {
      p = (i * 100) / (r * t);
    } else if (solveFor === 'rate') {
      r = (i * 100) / (p * t);
    } else if (solveFor === 'time') {
      t = (i * 100) / (p * r);
    }

    const calculatedTime = timeUnit === 'months' && solveFor === 'time' ? t * 12 : t;

    setResult({
      principal: p,
      rate: r,
      time: calculatedTime,
      interest: i,
      totalAmount: p + i
    });
  };

  const handleReset = () => {
    setSolveFor('interest');
    setPrincipal(50000);
    setRate(6.5);
    setTime(3);
    setTimeUnit('years');
    setInterest(9750);
    setResult(null);
    setErrors({});
  };

  const formatCurrency = (val: number) => {
    return '₹' + Math.round(val).toLocaleString('en-IN');
  };

  const formula = solveFor === 'interest' 
    ? "Interest = (Principal × Rate × Time) / 100"
    : solveFor === 'principal'
    ? "Principal = (Interest × 100) / (Rate × Time)"
    : solveFor === 'rate'
    ? "Rate = (Interest × 100) / (Principal × Time)"
    : "Time = (Interest × 100) / (Principal × Rate)";

  const example = "Principal: ₹50,000, Interest Rate: 6.5% p.a., Time: 3 Years\nSimple Interest: ₹9,750\nTotal Accrued Amount: ₹59,750";

  const resultItems = result ? [
    { label: 'Principal (P)', value: formatCurrency(result.principal) },
    { label: 'Interest Rate (R)', value: `${result.rate.toFixed(2)}% p.a.` },
    { label: 'Time Period (T)', value: `${result.time.toFixed(1)} ${timeUnit}` },
    { label: 'Interest Amount (I)', value: formatCurrency(result.interest) },
    { label: 'Total Value (P + I)', value: formatCurrency(result.totalAmount) }
  ] : [];

  const inputs = (
    <>
      <CalculatorSelect
        label="Solve For"
        value={solveFor}
        onChange={(e) => {
          setSolveFor(e.target.value as any);
          setResult(null);
        }}
        options={[
          { value: 'interest', label: 'Simple Interest Amount' },
          { value: 'principal', label: 'Principal Amount' },
          { value: 'rate', label: 'Interest Rate (%)' },
          { value: 'time', label: 'Time Period' }
        ]}
      />

      {solveFor !== 'principal' && (
        <CalculatorInput
          label="Principal Amount (P)"
          value={principal || ''}
          onChange={(val) => setPrincipal(val)}
          prefixText="₹"
          error={errors.principal}
          required
        />
      )}

      {solveFor !== 'rate' && (
        <CalculatorInput
          label="Interest Rate (R % per year)"
          value={rate || ''}
          onChange={(val) => setRate(val)}
          suffixText="%"
          error={errors.rate}
          step="0.01"
          required
        />
      )}

      {solveFor !== 'time' && (
        <div className="flex gap-4">
          <CalculatorInput
            label="Time Period (T)"
            value={time || ''}
            onChange={(val) => setTime(val)}
            error={errors.time}
            className="flex-1"
            required
          />
          <CalculatorSelect
            label="Time Unit"
            value={timeUnit}
            onChange={(e) => setTimeUnit(e.target.value as any)}
            options={[
              { value: 'years', label: 'Years' },
              { value: 'months', label: 'Months' }
            ]}
            className="w-28"
          />
        </div>
      )}

      {(solveFor === 'principal' || solveFor === 'rate' || solveFor === 'time') && (
        <CalculatorInput
          label="Interest Earned (I)"
          value={interest || ''}
          onChange={(val) => setInterest(val)}
          prefixText="₹"
          error={errors.interest}
          required
        />
      )}
    </>
  );

  const results = result ? (
    <CalculatorResult
      title="Simple Interest Repayment Breakdown"
      highlightLabel={solveFor === 'interest' ? 'Simple Interest Earned' : 'Principal Amount'}
      highlightValue={formatCurrency(solveFor === 'interest' ? result.interest : result.principal)}
      items={resultItems}
    />
  ) : (
    <div className="bg-background border border-border rounded-xl p-6 text-center text-slate font-sans text-sm">
      Specify simple interest input values and calculate the remaining variable.
    </div>
  );

  return (
    <CalculatorLayout
      toolId={toolId}
      title={title}
      description={description}
      onCalculate={handleCalculate}
      onReset={handleReset}
      inputs={inputs}
      results={results}
      formula={formula}
      example={example}
    />
  );
}

'use client';

import React, { useState } from 'react';
import { CalculatorLayout } from '../CalculatorLayout';
import { CalculatorSelect } from '../CalculatorSelect';
import { CalculatorResult } from '../CalculatorResult';

interface TimeDurationCalculatorViewProps {
  toolId: string;
  title: string;
  description: string;
}

export function TimeDurationCalculatorView({ toolId, title, description }: TimeDurationCalculatorViewProps) {
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('17:00');
  const [isNextDay, setIsNextDay] = useState(false);

  const [result, setResult] = useState<{
    hours: number;
    minutes: number;
    totalMinutes: number;
    totalHours: number;
    totalSeconds: number;
    formatted: string;
  } | null>(null);

  const [error, setError] = useState<string | null>(null);

  const handleCalculate = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    const [startH, startM] = startTime.split(':').map(Number);
    const [endH, endM] = endTime.split(':').map(Number);

    if (isNaN(startH) || isNaN(startM) || isNaN(endH) || isNaN(endM)) {
      setError('Please select valid start and end times.');
      setResult(null);
      return;
    }

    const startMinutes = startH * 60 + startM;
    let endMinutes = endH * 60 + endM;

    if (endMinutes < startMinutes) {
      if (isNextDay) {
        endMinutes += 24 * 60;
      } else {
        // Automatically assume next day if end time is earlier and not explicitly set
        endMinutes += 24 * 60;
      }
    } else if (isNextDay) {
      endMinutes += 24 * 60;
    }

    const diffMinutes = endMinutes - startMinutes;
    const hours = Math.floor(diffMinutes / 60);
    const minutes = diffMinutes % 60;

    setResult({
      hours,
      minutes,
      totalMinutes: diffMinutes,
      totalHours: diffMinutes / 60,
      totalSeconds: diffMinutes * 60,
      formatted: `${hours} hours and ${minutes} minutes`
    });
  };

  const handleReset = () => {
    setStartTime('09:00');
    setEndTime('17:00');
    setIsNextDay(false);
    setResult(null);
    setError(null);
  };

  const resultItems = result ? [
    { label: 'Elapsed Duration', value: result.formatted },
    { label: 'Hours Component', value: `${result.hours} hrs` },
    { label: 'Minutes Component', value: `${result.minutes} mins` },
    { label: 'Total Hours', value: `${result.totalHours.toFixed(2)} hrs` },
    { label: 'Total Minutes', value: `${result.totalMinutes} mins` },
    { label: 'Total Seconds', value: `${result.totalSeconds} secs` }
  ] : [];

  const inputs = (
    <>
      <div className="flex flex-col gap-1.5 w-full">
        <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">Start Time</label>
        <input
          type="time"
          value={startTime}
          onChange={(e) => setStartTime(e.target.value)}
          className="p-3 border border-border rounded-xl bg-background text-ink font-mono outline-none focus:border-primary/80"
          required
        />
      </div>
      <div className="flex flex-col gap-1.5 w-full">
        <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">End Time</label>
        <input
          type="time"
          value={endTime}
          onChange={(e) => setEndTime(e.target.value)}
          className="p-3 border border-border rounded-xl bg-background text-ink font-mono outline-none focus:border-primary/80"
          required
        />
      </div>
      <div className="flex items-center gap-3 p-1">
        <input
          type="checkbox"
          id="isNextDay"
          checked={isNextDay}
          onChange={(e) => setIsNextDay(e.target.checked)}
          className="w-4.5 h-4.5 accent-primary border border-border rounded"
        />
        <label htmlFor="isNextDay" className="text-sm font-sans text-ink cursor-pointer select-none">
          End time is on the next calendar day
        </label>
      </div>
      {error && (
        <p className="text-sm text-red-500 font-medium font-sans">{error}</p>
      )}
    </>
  );

  const results = result ? (
    <CalculatorResult
      title="Elapsed Time breakdown"
      highlightLabel="Time Duration"
      highlightValue={`${result.hours}h ${result.minutes}m`}
      items={resultItems}
    />
  ) : (
    <div className="bg-background border border-border rounded-xl p-6 text-center text-slate font-sans text-sm">
      Define start and end times to calculate elapsed durations.
    </div>
  );

  return (
    <CalculatorLayout
      toolId={toolId}
      title={title}
      description={description}
      onCalculate={handleCalculate}
      onReset={handleReset}
      inputs={inputs}
      results={results}
      formula="Time Duration = End Time (minutes) - Start Time (minutes). If End Time < Start Time, End Time is increased by 1440 minutes (24 hours)."
      example="Start: 09:00 AM, End: 05:00 PM\nDuration: 8 hours (480 minutes)"
    />
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { ToolLayout } from '../shared/ToolLayout';
import { Button } from '@/components/ui/Button';
import { getConvertContent } from './convertContent';

interface ConvertToolContainerProps {
  toolId: string;
  toolName: string;
  toolDescription: string;
}

interface UnitOption {
  value: string;
  label: string;
  factor: number; // Multiplier to convert to base unit
}

export function ConvertToolContainer({ toolId, toolName, toolDescription }: ConvertToolContainerProps) {
  const [inputValue, setInputValue] = useState('1');
  const [fromUnit, setFromUnit] = useState('');
  const [toUnit, setToUnit] = useState('');
  const [result, setResult] = useState('');
  const [error, setError] = useState('');

  // Define base units and ratios for each converter type
  const getUnitConfig = (): { category: string; units: UnitOption[] } => {
    switch (toolId) {
      case 'length-converter':
        return {
          category: 'Length',
          units: [
            { value: 'm', label: 'Meters (m)', factor: 1 },
            { value: 'km', label: 'Kilometers (km)', factor: 1000 },
            { value: 'cm', label: 'Centimeters (cm)', factor: 0.01 },
            { value: 'mm', label: 'Millimeters (mm)', factor: 0.001 },
            { value: 'mi', label: 'Miles (mi)', factor: 1609.344 },
            { value: 'yd', label: 'Yards (yd)', factor: 0.9144 },
            { value: 'ft', label: 'Feet (ft)', factor: 0.3048 },
            { value: 'in', label: 'Inches (in)', factor: 0.0254 }
          ]
        };
      case 'weight-converter':
        return {
          category: 'Weight',
          units: [
            { value: 'kg', label: 'Kilograms (kg)', factor: 1 },
            { value: 'g', label: 'Grams (g)', factor: 0.001 },
            { value: 'mg', label: 'Milligrams (mg)', factor: 0.000001 },
            { value: 'lb', label: 'Pounds (lb)', factor: 0.45359237 },
            { value: 'oz', label: 'Ounces (oz)', factor: 0.028349523 },
            { value: 'ton', label: 'Tons (t)', factor: 1000 }
          ]
        };
      case 'temperature-converter':
        return {
          category: 'Temperature',
          units: [
            { value: 'c', label: 'Celsius (°C)', factor: 1 },
            { value: 'f', label: 'Fahrenheit (°F)', factor: 1 },
            { value: 'k', label: 'Kelvin (K)', factor: 1 }
          ]
        };
      case 'area-converter':
        return {
          category: 'Area',
          units: [
            { value: 'm2', label: 'Square Meters (m²)', factor: 1 },
            { value: 'km2', label: 'Square Kilometers (km²)', factor: 1000000 },
            { value: 'ft2', label: 'Square Feet (ft²)', factor: 0.092903 },
            { value: 'ac', label: 'Acres (ac)', factor: 4046.856 },
            { value: 'ha', label: 'Hectares (ha)', factor: 10000 }
          ]
        };
      case 'volume-converter':
        return {
          category: 'Volume',
          units: [
            { value: 'l', label: 'Liters (L)', factor: 1 },
            { value: 'ml', label: 'Milliliters (mL)', factor: 0.001 },
            { value: 'm3', label: 'Cubic Meters (m³)', factor: 1000 },
            { value: 'gal', label: 'Gallons (US)', factor: 3.78541 },
            { value: 'qt', label: 'Quarts', factor: 0.946353 },
            { value: 'cup', label: 'Cups', factor: 0.24 }
          ]
        };
      case 'speed-converter':
        return {
          category: 'Speed',
          units: [
            { value: 'mps', label: 'Meters per second (m/s)', factor: 1 },
            { value: 'kmh', label: 'Kilometers per hour (km/h)', factor: 0.277778 },
            { value: 'mph', label: 'Miles per hour (mph)', factor: 0.44704 },
            { value: 'knot', label: 'Knots', factor: 0.514444 }
          ]
        };
      case 'time-converter':
        return {
          category: 'Time',
          units: [
            { value: 's', label: 'Seconds (s)', factor: 1 },
            { value: 'min', label: 'Minutes (min)', factor: 60 },
            { value: 'hr', label: 'Hours (hr)', factor: 3600 },
            { value: 'day', label: 'Days', factor: 86400 },
            { value: 'week', label: 'Weeks', factor: 604800 },
            { value: 'yr', label: 'Years', factor: 31536000 }
          ]
        };
      case 'data-storage-converter':
        return {
          category: 'Data Storage',
          units: [
            { value: 'b', label: 'Bits (b)', factor: 0.125 },
            { value: 'B', label: 'Bytes (B)', factor: 1 },
            { value: 'KB', label: 'Kilobytes (KB)', factor: 1024 },
            { value: 'MB', label: 'Megabytes (MB)', factor: 1048576 },
            { value: 'GB', label: 'Gigabytes (GB)', factor: 1073741824 },
            { value: 'TB', label: 'Terabytes (TB)', factor: 1099511627776 }
          ]
        };
      case 'angle-converter':
        return {
          category: 'Angle',
          units: [
            { value: 'deg', label: 'Degrees (°)', factor: 1 },
            { value: 'rad', label: 'Radians (rad)', factor: 57.2958 },
            { value: 'grad', label: 'Gradians (grad)', factor: 0.9 }
          ]
        };
      case 'pressure-converter':
        return {
          category: 'Pressure',
          units: [
            { value: 'pa', label: 'Pascal (Pa)', factor: 1 },
            { value: 'bar', label: 'Bar', factor: 100000 },
            { value: 'psi', label: 'PSI (pound/sq in)', factor: 6894.76 },
            { value: 'atm', label: 'Atmosphere (atm)', factor: 101325 }
          ]
        };
      case 'energy-converter':
        return {
          category: 'Energy',
          units: [
            { value: 'j', label: 'Joules (J)', factor: 1 },
            { value: 'cal', label: 'Calories (cal)', factor: 4.184 },
            { value: 'kcal', label: 'Kilocalories (kcal)', factor: 4184 },
            { value: 'wh', label: 'Watt-hours (Wh)', factor: 3600 },
            { value: 'kwh', label: 'Kilowatt-hours (kWh)', factor: 3600000 },
            { value: 'btu', label: 'BTUs', factor: 1055.06 }
          ]
        };
      case 'power-converter':
        return {
          category: 'Power',
          units: [
            { value: 'w', label: 'Watts (W)', factor: 1 },
            { value: 'kw', label: 'Kilowatts (kW)', factor: 1000 },
            { value: 'hp', label: 'Horsepower (hp)', factor: 745.7 }
          ]
        };
      case 'frequency-converter':
        return {
          category: 'Frequency',
          units: [
            { value: 'hz', label: 'Hertz (Hz)', factor: 1 },
            { value: 'khz', label: 'Kilohertz (kHz)', factor: 1000 },
            { value: 'mhz', label: 'Megahertz (MHz)', factor: 1000000 },
            { value: 'ghz', label: 'Gigahertz (GHz)', factor: 1000000000 }
          ]
        };
      case 'number-base-converter':
        return {
          category: 'Number Base',
          units: [
            { value: '10', label: 'Decimal (Base 10)', factor: 10 },
            { value: '2', label: 'Binary (Base 2)', factor: 2 },
            { value: '8', label: 'Octal (Base 8)', factor: 8 },
            { value: '16', label: 'Hexadecimal (Base 16)', factor: 16 }
          ]
        };
      case 'fuel-efficiency-converter':
        return {
          category: 'Fuel Efficiency',
          units: [
            { value: 'mpg', label: 'Miles per Gallon (mpg)', factor: 1 },
            { value: 'kml', label: 'Kilometers per Liter (km/L)', factor: 0.42514 },
            { value: 'l100', label: 'Liters per 100km (L/100km)', factor: 0 } // handled custom
          ]
        };
      default:
        return { category: 'Units', units: [] };
    }
  };

  const { units } = getUnitConfig();

  // Reset input values, result, and errors when switching/re-entering tools
  useEffect(() => {
    setInputValue('1');
    setResult('');
    setError('');
  }, [toolId]);

  // Initialize from/to units when config loads
  useEffect(() => {
    if (units.length > 1) {
      setFromUnit(units[0].value);
      setToUnit(units[1].value);
    }
  }, [toolId]);

  // Conversion calculations
  useEffect(() => {
    setError('');
    if (!inputValue || !fromUnit || !toUnit) {
      setResult('');
      return;
    }

    try {
      if (toolId === 'temperature-converter') {
        const temp = parseFloat(inputValue);
        if (isNaN(temp)) throw new Error('Invalid input number.');
        
        let celsius = temp;
        // Convert from input to Celsius
        if (fromUnit === 'f') celsius = (temp - 32) * 5 / 9;
        if (fromUnit === 'k') celsius = temp - 273.15;
        
        // Convert Celsius to target
        let converted = celsius;
        if (toUnit === 'f') converted = celsius * 9 / 5 + 32;
        if (toUnit === 'k') converted = celsius + 273.15;
        
        setResult(converted.toFixed(4).replace(/\.?0+$/, ''));
      } else if (toolId === 'number-base-converter') {
        const baseFrom = parseInt(fromUnit);
        const baseTo = parseInt(toUnit);
        // Parse input value according to from base
        const parsed = parseInt(inputValue.trim(), baseFrom);
        if (isNaN(parsed)) throw new Error(`Invalid base-${baseFrom} value.`);
        setResult(parsed.toString(baseTo).toUpperCase());
      } else if (toolId === 'fuel-efficiency-converter') {
        const val = parseFloat(inputValue);
        if (isNaN(val) || val <= 0) throw new Error('Value must be a positive number.');
        
        if (fromUnit === toUnit) {
          setResult(val.toString());
          return;
        }

        let mpgVal = val;
        // Convert to mpg base
        if (fromUnit === 'kml') mpgVal = val * 2.352146;
        if (fromUnit === 'l100') mpgVal = 235.2146 / val;

        let finalVal = mpgVal;
        // Convert from mpg to target
        if (toUnit === 'kml') finalVal = mpgVal * 0.4251437;
        if (toUnit === 'l100') finalVal = 235.2146 / mpgVal;

        setResult(finalVal.toFixed(4).replace(/\.?0+$/, ''));
      } else {
        // Standard conversions using factors
        const val = parseFloat(inputValue);
        if (isNaN(val)) throw new Error('Value must be a valid number.');
        
        const fromFactor = units.find(u => u.value === fromUnit)?.factor || 1;
        const toFactor = units.find(u => u.value === toUnit)?.factor || 1;
        
        const baseValue = val * fromFactor;
        const converted = baseValue / toFactor;
        setResult(converted.toFixed(6).replace(/\.?0+$/, ''));
      }
    } catch (err: any) {
      setError(err.message || 'Error occurred.');
      setResult('');
    }
  }, [inputValue, fromUnit, toUnit, toolId]);

  const handleSwap = () => {
    const temp = fromUnit;
    setFromUnit(toUnit);
    setToUnit(temp);
  };

  const handleCopy = () => {
    if (!result) return;
    navigator.clipboard.writeText(result);
  };

  const activeUnits = units;
  const content = getConvertContent(toolId);

  return (
    <ToolLayout
      utilityId={toolId}
      title={toolName}
      description={toolDescription}
      categoryName="Unit Conversion Tools"
      categoryPath="/tools/convert"
      howToUse={content.howToUse}
      faqs={content.faqs}
    >
      <div className="space-y-6 max-w-2xl mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 items-end">
          {/* Input Value */}
          <div className="flex flex-col gap-1.5 md:col-span-2">
            <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">Input Value</label>
            <input 
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)} 
              placeholder="e.g. 1" 
              className="p-3.5 border border-border rounded-xl bg-background text-ink font-mono text-lg outline-none focus:border-primary/80" 
            />
          </div>

          {/* From Unit */}
          <div className="flex flex-col gap-1.5">
            <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">From</label>
            <select
              value={fromUnit}
              onChange={(e) => setFromUnit(e.target.value)}
              className="p-3 border border-border rounded-xl bg-background text-ink text-[15px] font-sans outline-none focus:border-primary/80"
            >
              {activeUnits.map((u) => (
                <option key={u.value} value={u.value}>{u.label}</option>
              ))}
            </select>
          </div>

          {/* Swap & To Unit */}
          <div className="flex items-center gap-3">
            <Button variant="outline" size="lg" className="px-4 py-3 shrink-0" onClick={handleSwap}>Swap</Button>
            <div className="flex-1 flex flex-col gap-1.5">
              <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">To</label>
              <select
                value={toUnit}
                onChange={(e) => setToUnit(e.target.value)}
                className="p-3 border border-border rounded-xl bg-background text-ink text-[15px] font-sans outline-none focus:border-primary/80 w-full"
              >
                {activeUnits.map((u) => (
                  <option key={u.value} value={u.value}>{u.label}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Errors & Result */}
        {error && (
          <div className="p-3 bg-red-500/10 border border-red-500/20 text-red-500 font-sans text-sm rounded-lg">
            {error}
          </div>
        )}

        <div className="p-6 bg-background rounded-xl border border-border mt-8 flex flex-col items-center justify-center text-center relative overflow-hidden">
          <p className="text-[12px] uppercase font-sans font-semibold text-slate tracking-wider mb-2">Converted Value</p>
          {result ? (
            <h2 className="text-3xl md:text-4xl font-mono font-bold text-primary truncate max-w-full px-4">{result}</h2>
          ) : (
            <span className="text-slate font-mono">...</span>
          )}
          {result && (
            <Button size="sm" variant="outline" className="mt-4" onClick={handleCopy}>Copy Result</Button>
          )}
        </div>
      </div>
    </ToolLayout>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { ToolLayout } from '../shared/ToolLayout';
import { TextBox } from '../shared/TextBox';
import { ResultBox } from '../shared/ResultBox';
import { Button } from '@/components/ui/Button';
import { format as formatSql } from 'sql-formatter';
import { sanitizeHtml } from '@/lib/sanitization';
import { useHtmlPreviewerStore } from '@/store/useCompilerStore';
import { MonacoEditorWrapper } from '../shared/MonacoEditorWrapper';
import { DevicePreviewFrame } from '../shared/DevicePreviewFrame';
import { Group as PanelGroup, Panel, Separator as PanelResizeHandle } from 'react-resizable-panels';
import { Play, Download, Layout, FileJson, AlignLeft, Image as ImageIcon } from 'lucide-react';
import { saveAs } from 'file-saver';
import { getDevContent } from './devContent';

interface DevToolContainerProps {
  toolId: string;
  toolName: string;
  toolDescription: string;
}

// Color conversion helpers
function hexToRgb(hex: string): { r: number; g: number; b: number } | null {
  const sanitized = hex.trim().replace('#', '');
  if (sanitized.length !== 3 && sanitized.length !== 6) return null;
  const r = parseInt(sanitized.length === 3 ? sanitized[0] + sanitized[0] : sanitized.substring(0, 2), 16);
  const g = parseInt(sanitized.length === 3 ? sanitized[1] + sanitized[1] : sanitized.substring(2, 4), 16);
  const b = parseInt(sanitized.length === 3 ? sanitized[2] + sanitized[2] : sanitized.substring(4, 6), 16);
  if (isNaN(r) || isNaN(g) || isNaN(b)) return null;
  return { r, g, b };
}

function rgbToHsl(r: number, g: number, b: number): { h: number; s: number; l: number } {
  r /= 255;
  g /= 255;
  b /= 255;
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  let h = 0;
  let s = 0;
  const l = (max + min) / 2;

  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = (g - b) / d + (g < b ? 6 : 0); break;
      case g: h = (b - r) / d + 2; break;
      case b: h = (r - g) / d + 4; break;
    }
    h /= 6;
  }

  return {
    h: Math.round(h * 360),
    s: Math.round(s * 100),
    l: Math.round(l * 100)
  };
}

export function DevToolContainer({ toolId, toolName, toolDescription }: DevToolContainerProps) {
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [error, setError] = useState('');
  
  // Custom states for specific tools
  const [regexPattern, setRegexPattern] = useState('[a-zA-Z]+');
  const [regexFlags, setRegexFlags] = useState('g');
  const [hashType, setHashType] = useState('SHA-256');
  const [unixTime, setUnixTime] = useState<number>(0);
  
  // Color Picker states
  const [colorInput, setColorInput] = useState('#0f766e');
  const [colorRgb, setColorRgb] = useState('rgb(15, 118, 110)');
  const [colorHsl, setColorHsl] = useState('hsl(175, 77%, 26%)');
  const [colorError, setColorError] = useState('');
  const [copiedType, setCopiedType] = useState<string | null>(null);

  // Code Beautifier language selection
  const [beautifyLanguage, setBeautifyLanguage] = useState<'js' | 'html' | 'css'>('js');
  const [beautifierLoaded, setBeautifierLoaded] = useState(false);

  // UUID states
  const [uuidResult, setUuidResult] = useState('');
  const [copiedUuid, setCopiedUuid] = useState(false);

  // HTML Previewer states & store
  const htmlPreviewStore = useHtmlPreviewerStore();
  const [srcDoc, setSrcDoc] = useState('');
  const [isMobile, setIsMobile] = useState(false);
  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');

  // Dynamic script loader for js-beautify CDN
  useEffect(() => {
    if (toolId !== 'code-beautifier' && toolId !== 'html-previewer') return;

    let active = true;
    const loadScript = (url: string): Promise<void> => {
      return new Promise((resolve, reject) => {
        if (document.querySelector(`script[src="${url}"]`)) {
          resolve();
          return;
        }
        const script = document.createElement('script');
        script.src = url;
        script.onload = () => resolve();
        script.onerror = () => reject(new Error(`Failed to load script: ${url}`));
        document.head.appendChild(script);
      });
    };

    Promise.all([
      loadScript('https://cdnjs.cloudflare.com/ajax/libs/js-beautify/1.15.4/beautify.min.js'),
      loadScript('https://cdnjs.cloudflare.com/ajax/libs/js-beautify/1.15.4/beautify-css.min.js'),
      loadScript('https://cdnjs.cloudflare.com/ajax/libs/js-beautify/1.15.4/beautify-html.min.js')
    ]).then(() => {
      if (active) setBeautifierLoaded(true);
    }).catch((err) => {
      if (active) setError('Failed to load code beautifier libraries: ' + err.message);
    });

    return () => {
      active = false;
    };
  }, [toolId]);

  // Resize listener for mobile/desktop layout threshold
  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // HTML Previewer auto-run logic
  useEffect(() => {
    if (toolId !== 'html-previewer') return;
    if (htmlPreviewStore.autoRun) {
      const timeout = setTimeout(() => {
        setSrcDoc(htmlPreviewStore.html);
      }, 500);
      return () => clearTimeout(timeout);
    }
  }, [htmlPreviewStore.html, htmlPreviewStore.autoRun, toolId]);
  
  // Reset all states when switching/re-entering tools
  useEffect(() => {
    setInput('');
    setOutput('');
    setError('');
    setRegexPattern('[a-zA-Z]+');
    setRegexFlags('g');
    setHashType('SHA-256');
    setColorInput('#0f766e');
    setColorRgb('rgb(15, 118, 110)');
    setColorHsl('hsl(175, 77%, 26%)');
    setColorError('');
    setCopiedType(null);
    setBeautifyLanguage('js');
    setUuidResult('');
    setCopiedUuid(false);
    if (toolId === 'html-previewer') {
      setSrcDoc(htmlPreviewStore.html);
    } else {
      setSrcDoc('');
    }
  }, [toolId]);

  // Live Unix clock interval
  useEffect(() => {
    if (toolId !== 'unix-time-converter') return;
    setUnixTime(Math.floor(Date.now() / 1000));
    const interval = setInterval(() => {
      setUnixTime(Math.floor(Date.now() / 1000));
    }, 1000);
    return () => clearInterval(interval);
  }, [toolId]);

  // Auto-run logic for immediate formatters/converters
  useEffect(() => {
    setError('');
    
    if (!input && !['uuid-generator', 'unix-time-converter', 'color-picker-tool'].includes(toolId)) {
      setOutput('');
      return;
    }

    try {
      switch (toolId) {
        case 'json-formatter': {
          const parsed = JSON.parse(input);
          setOutput(JSON.stringify(parsed, null, 2));
          break;
        }
        case 'json-validator': {
          JSON.parse(input);
          setOutput("JSON is Valid.");
          break;
        }
        case 'base64-encoder-decoder': {
          try {
            if (/^[a-zA-Z0-9+/]*={0,2}$/.test(input.trim()) && input.length % 4 === 0) {
              setOutput(decodeURIComponent(escape(atob(input.trim()))));
            } else {
              setOutput(btoa(unescape(encodeURIComponent(input))));
            }
          } catch {
            setOutput(btoa(unescape(encodeURIComponent(input))));
          }
          break;
        }
        case 'url-encoder-decoder': {
          if (input.includes('%')) {
            setOutput(decodeURIComponent(input));
          } else {
            setOutput(encodeURIComponent(input));
          }
          break;
        }
        case 'jwt-decoder': {
          const parts = input.split('.');
          if (parts.length < 2) {
            throw new Error("Invalid JWT token format (must contain at least Header and Payload segments separated by dots).");
          }
          const base64UrlDecode = (str: string) => {
            let base64 = str.replace(/-/g, '+').replace(/_/g, '/');
            while (base64.length % 4) {
              base64 += '=';
            }
            return decodeURIComponent(escape(atob(base64)));
          };
          const header = JSON.parse(base64UrlDecode(parts[0]));
          const payload = JSON.parse(base64UrlDecode(parts[1]));
          setOutput(`// HEADER:\n${JSON.stringify(header, null, 2)}\n\n// PAYLOAD:\n${JSON.stringify(payload, null, 2)}`);
          break;
        }
        case 'html-encoder-decoder': {
          if (input.includes('&') && input.includes(';')) {
            const txt = document.createElement("textarea");
            txt.innerHTML = input;
            setOutput(txt.value);
          } else {
            setOutput(input.replace(/[\u00A0-\u9999<>&]/g, (i) => `&#${i.charCodeAt(0)};`));
          }
          break;
        }
        case 'html-minifier':
          setOutput(input.replace(/<!--[\s\S]*?-->/g, '').replace(/\s+/g, ' ').replace(/>\s+</g, '><').trim());
          break;
        case 'css-minifier':
          setOutput(input.replace(/\/\*[\s\S]*?\*\//g, '').replace(/\s+/g, ' ').replace(/\s*([\{\}:;,])\s*/g, '$1').trim());
          break;
        case 'js-minifier':
          setOutput(input.replace(/\/\*[\s\S]*?\*\//g, '').replace(/\/\/.*$/gm, '').replace(/\s+/g, ' ').trim());
          break;
        case 'hex-to-rgb': {
          const hex = input.trim().replace('#', '');
          if (hex.length !== 3 && hex.length !== 6) {
            throw new Error("Invalid HEX color code (must be 3 or 6 hex characters).");
          }
          const r = parseInt(hex.length === 3 ? hex[0] + hex[0] : hex.substring(0, 2), 16);
          const g = parseInt(hex.length === 3 ? hex[1] + hex[1] : hex.substring(2, 4), 16);
          const b = parseInt(hex.length === 3 ? hex[2] + hex[2] : hex.substring(4, 6), 16);
          setOutput(`rgb(${r}, ${g}, ${b})`);
          break;
        }
        case 'rgb-to-hex': {
          const matches = input.match(/\d+/g);
          if (!matches || matches.length < 3) {
            throw new Error("Please enter three comma-separated numbers (e.g. 255, 255, 255).");
          }
          const r = Math.min(255, Math.max(0, parseInt(matches[0])));
          const g = Math.min(255, Math.max(0, parseInt(matches[1])));
          const b = Math.min(255, Math.max(0, parseInt(matches[2])));
          const hex = "#" + [r, g, b].map(x => x.toString(16).padStart(2, '0')).join('');
          setOutput(hex.toUpperCase());
          break;
        }
        case 'timestamp-converter': {
          if (/^\d+$/.test(input.trim())) {
            let val = parseInt(input.trim());
            if (input.trim().length === 10) val *= 1000;
            const date = new Date(val);
            setOutput(`GMT: ${date.toUTCString()}\nLocal Time: ${date.toString()}`);
          } else {
            const date = new Date(input.trim());
            if (isNaN(date.getTime())) {
              throw new Error("Invalid date string. Try: '2026-06-04 12:00:00' or UTC format.");
            }
            setOutput(`Seconds: ${Math.floor(date.getTime() / 1000)}\nMilliseconds: ${date.getTime()}`);
          }
          break;
        }
        case 'xml-formatter': {
          let formatted = '';
          const reg = /(>)(<)(\/*)/g;
          const xml = input.replace(reg, '$1\r\n$2$3');
          let pad = 0;
          xml.split('\r\n').forEach((node) => {
            let indent = 0;
            if (node.match(/.+<\/\w[^>]*>$/)) {
              indent = 0;
            } else if (node.match(/^<\/\w/)) {
              if (pad !== 0) pad -= 1;
            } else if (node.match(/^<\w[^>]*[^\/]>.*$/)) {
              indent = 1;
            }
            formatted += '  '.repeat(pad) + node + '\r\n';
            pad += indent;
          });
          setOutput(formatted.trim());
          break;
        }
        case 'yaml-formatter': {
          let indentLevel = 0;
          const lines = input.split('\n');
          const beauty = lines.map(line => {
            const l = line.trim();
            if (l.startsWith('}') || l.startsWith(']')) indentLevel = Math.max(0, indentLevel - 1);
            const res = '  '.repeat(indentLevel) + l;
            if (l.endsWith('{') || l.endsWith('[') || l.endsWith('(')) indentLevel += 1;
            return res;
          }).join('\n');
          setOutput(beauty);
          break;
        }
        case 'sql-formatter': {
          if (!input.trim()) {
            setOutput('');
            break;
          }
          try {
            const formatted = formatSql(input, {
              language: 'sql',
              tabWidth: 2,
              keywordCase: 'upper'
            });
            setOutput(formatted);
          } catch (err: any) {
            throw new Error('Invalid SQL syntax: ' + (err.message || 'Check your query syntax.'));
          }
          break;
        }
        case 'code-beautifier': {
          if (!input.trim()) {
            setOutput('');
            break;
          }
          if (!beautifierLoaded) {
            setOutput('Loading beautifier libraries...');
            break;
          }
          try {
            const options = {
              indent_size: 2,
              space_in_empty_paren: true,
              jslint_happy: true,
              end_with_newline: true
            };
            let formatted = '';
            const w = window as any;
            if (beautifyLanguage === 'js' && typeof w.js_beautify === 'function') {
              formatted = w.js_beautify(input, options);
            } else if (beautifyLanguage === 'html' && typeof w.html_beautify === 'function') {
              formatted = w.html_beautify(input, options);
            } else if (beautifyLanguage === 'css' && typeof w.css_beautify === 'function') {
              formatted = w.css_beautify(input, options);
            } else {
              throw new Error('Beautifier library is not loaded yet.');
            }
            setOutput(formatted);
          } catch (err: any) {
            throw new Error('Beautification failed: ' + (err.message || 'Verify your code layout.'));
          }
          break;
        }
        case 'markdown-previewer': {
          const html = input
            .replace(/^### (.*$)/gim, '<h3>$1</h3>')
            .replace(/^## (.*$)/gim, '<h2>$1</h2>')
            .replace(/^# (.*$)/gim, '<h1>$1</h1>')
            .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
            .replace(/\*(.*)\*/gim, '<em>$1</em>')
            .replace(/`(.*)`/gim, '<code>$1</code>')
            .replace(/\n$/gim, '<br />');
          setOutput(html);
          break;
        }
        default:
          break;
      }
    } catch (err: any) {
      setError(err.message || 'Formatting error. Please check your syntax.');
    }
  }, [input, toolId, beautifyLanguage]);

  // Execute hash generation (uses async Web Crypto)
  const handleHash = async () => {
    setError('');
    try {
      const encoder = new TextEncoder();
      const data = encoder.encode(input);
      const hashBuffer = await crypto.subtle.digest(hashType, data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      setOutput(hashHex);
    } catch (err: any) {
      setError('Hash generation failed.');
    }
  };

  const handleRegexTest = () => {
    setError('');
    try {
      const regex = new RegExp(regexPattern, regexFlags);
      const matches = input.match(regex);
      if (matches) {
        setOutput(`Matches Found (${matches.length}):\n${JSON.stringify(matches, null, 2)}`);
      } else {
        setOutput("No matches found.");
      }
    } catch (err: any) {
      setError(err.message || 'Invalid regex pattern.');
    }
  };

  const generateUuid = () => {
    setError('');
    try {
      const uuid = crypto.randomUUID();
      setUuidResult(uuid);
      setCopiedUuid(false);
    } catch (err) {
      const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
        const r = Math.random() * 16 | 0;
        const v = c === 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
      });
      setUuidResult(uuid);
      setCopiedUuid(false);
    }
  };

  const handleCopyUuid = () => {
    if (!uuidResult) return;
    navigator.clipboard.writeText(uuidResult);
    setCopiedUuid(true);
    setTimeout(() => setCopiedUuid(false), 2000);
  };

  const handleColorChange = (value: string) => {
    setColorInput(value);
    
    let hex = value.trim();
    if (!hex.startsWith('#')) {
      hex = '#' + hex;
    }
    
    const hexReg = /^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/;
    if (!hexReg.test(hex)) {
      setColorError('Invalid HEX color code (must be e.g. #0f766e or #0f7).');
      return;
    }
    
    setColorError('');
    const rgb = hexToRgb(hex);
    if (rgb) {
      const rgbStr = `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`;
      const hsl = rgbToHsl(rgb.r, rgb.g, rgb.b);
      const hslStr = `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`;
      
      setColorRgb(rgbStr);
      setColorHsl(hslStr);
    }
  };

  const handleCopyValue = (val: string, type: string) => {
    navigator.clipboard.writeText(val);
    setCopiedType(type);
    setTimeout(() => setCopiedType(null), 2000);
  };

  const handleManualRun = () => {
    setSrcDoc(htmlPreviewStore.html);
  };

  const loadHtmlTemplate = (name: string) => {
    if (name === 'blank') {
      htmlPreviewStore.setHtml('<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n  <title>Blank Template</title>\n</head>\n<body>\n  <h1>Hello World</h1>\n</body>\n</html>');
    } else if (name === 'login') {
      htmlPreviewStore.setHtml('<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n  <title>Login Form</title>\n  <style>\n    body { font-family: sans-serif; display: flex; justify-content: center; align-items: center; height: 100vh; background: #f1f5f9; margin: 0; }\n    .card { background: white; padding: 2rem; border-radius: 12px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); width: 300px; }\n    h2 { margin-top: 0; color: #0f766e; }\n    input { width: 100%; padding: 0.5rem; margin-bottom: 1rem; border: 1px solid #cbd5e1; border-radius: 4px; box-sizing: border-box; }\n    button { width: 100%; padding: 0.5rem; background: #0f766e; color: white; border: none; border-radius: 4px; cursor: pointer; font-weight: bold; }\n  </style>\n</head>\n<body>\n  <div class="card">\n    <h2>Login</h2>\n    <input type="email" placeholder="Email">\n    <input type="password" placeholder="Password">\n    <button>Sign In</button>\n  </div>\n</body>\n</html>');
    }
  };

  const handleExportHTML = () => {
    const blob = new Blob([htmlPreviewStore.html], { type: 'text/html;charset=utf-8' });
    saveAs(blob, 'singulariti-preview.html');
  };

  const formatHtmlCode = () => {
    const w = window as any;
    if (typeof w.html_beautify === 'function') {
      try {
        const formatted = w.html_beautify(htmlPreviewStore.html, { indent_size: 2 });
        htmlPreviewStore.setHtml(formatted);
      } catch (err) {
        console.error('HTML Beautification failed', err);
      }
    } else {
      setError('Beautifier library is not loaded yet.');
    }
  };
  const content = getDevContent(toolId);

  return (
    <ToolLayout
      utilityId={toolId}
      title={toolName}
      description={toolDescription}
      categoryName="Developer Tools"
      categoryPath="/tools/dev"
      howToUse={content.howToUse}
      faqs={content.faqs}
    >
      <div className="space-y-6">
        {/* Custom Actions */}
        {toolId === 'uuid-generator' && (
          <div className="space-y-6 bg-background border border-border rounded-xl p-6 text-center max-w-xl mx-auto font-sans">
            <div className="space-y-3">
              <span className="text-[12px] uppercase font-bold text-slate tracking-wider block">Generated UUID</span>
              {uuidResult ? (
                <h2 className="text-2xl md:text-3xl font-mono font-bold text-primary break-all p-4 bg-surface rounded-xl border border-border select-all">
                  {uuidResult}
                </h2>
              ) : (
                <div className="p-4 bg-surface rounded-xl border border-border text-slate font-mono">
                  No UUID generated yet.
                </div>
              )}
            </div>
            
            <div className="flex justify-center gap-3">
              {uuidResult && (
                <Button variant="outline" onClick={handleCopyUuid}>
                  {copiedUuid ? 'Copied!' : 'Copy UUID'}
                </Button>
              )}
              <Button variant="primary" onClick={generateUuid}>
                {uuidResult ? 'Generate Another' : 'Generate UUID'}
              </Button>
            </div>
          </div>
        )}

        {toolId === 'unix-time-converter' && (
          <div className="p-5 bg-background border border-border rounded-xl text-center space-y-3">
            <p className="text-[12px] uppercase font-sans font-bold text-slate tracking-wider">Current Unix Epoch Time</p>
            <h2 className="text-3xl font-mono font-bold text-primary">{unixTime}</h2>
            <p className="text-sm font-sans text-slate">Updates live every second. Copy the value below.</p>
            <div className="flex justify-center gap-3">
              <Button size="sm" variant="outline" onClick={() => navigator.clipboard.writeText(unixTime.toString())}>Copy Timestamp</Button>
            </div>
          </div>
        )}

        {toolId === 'hash-generator' && (
          <div className="flex items-center gap-4 p-4 bg-background border border-border rounded-xl">
            <div className="flex flex-col gap-1.5">
              <label className="text-[12px] font-sans font-bold text-ink">Algorithm:</label>
              <select 
                value={hashType} 
                onChange={(e) => setHashType(e.target.value)}
                className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none w-36"
              >
                <option value="SHA-256">SHA-256</option>
                <option value="SHA-512">SHA-512</option>
                <option value="SHA-1">SHA-1</option>
              </select>
            </div>
            <Button variant="primary" onClick={handleHash} className="mt-5">Generate Hash</Button>
          </div>
        )}

        {toolId === 'regex-tester' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-background border border-border rounded-xl">
            <div className="flex flex-col gap-1">
              <label className="text-[12px] font-sans font-bold text-ink">Regex Pattern:</label>
              <input 
                type="text" 
                value={regexPattern} 
                onChange={(e) => setRegexPattern(e.target.value)} 
                placeholder="[a-zA-Z]+" 
                className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
              />
            </div>
            <div className="flex flex-col gap-1">
              <label className="text-[12px] font-sans font-bold text-ink">Flags:</label>
              <input 
                type="text" 
                value={regexFlags} 
                onChange={(e) => setRegexFlags(e.target.value)} 
                placeholder="g" 
                className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
              />
            </div>
            <div className="md:col-span-2 flex justify-end">
              <Button variant="primary" onClick={handleRegexTest}>Test Pattern</Button>
            </div>
          </div>
        )}

        {toolId === 'code-beautifier' && (
          <div className="flex items-center gap-4 p-4 bg-background border border-border rounded-xl font-sans">
            <div className="flex flex-col gap-1.5">
              <label className="text-[12px] font-bold text-ink">Language:</label>
              <select 
                value={beautifyLanguage} 
                onChange={(e) => setBeautifyLanguage(e.target.value as any)}
                className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none w-36"
              >
                <option value="js">JavaScript</option>
                <option value="html">HTML</option>
                <option value="css">CSS</option>
              </select>
            </div>
          </div>
        )}

        {/* Color Picker Custom UI */}
        {toolId === 'color-picker-tool' && (
          <div className="space-y-6 bg-background border border-border rounded-xl p-6 font-sans">
            <div className="flex flex-col md:flex-row gap-6 items-center">
              {/* Color Block Preview */}
              <div 
                className="w-24 h-24 rounded-2xl border border-border shadow-inner shrink-0 transition-colors" 
                style={{ backgroundColor: colorError ? '#ccc' : colorInput }} 
              />
              
              {/* Pickers and Inputs */}
              <div className="flex-1 w-full space-y-4">
                <div className="flex items-center gap-4">
                  <div className="flex flex-col gap-1">
                    <label className="text-[12px] font-bold text-ink">Choose Color:</label>
                    <div className="flex items-center gap-2">
                      <input
                        type="color"
                        value={colorError ? '#000000' : (colorInput.startsWith('#') ? colorInput : '#' + colorInput)}
                        onChange={(e) => handleColorChange(e.target.value)}
                        className="w-10 h-10 rounded border border-border cursor-pointer p-0 bg-transparent"
                      />
                      <span className="text-xs text-slate">Click to pick</span>
                    </div>
                  </div>
                  <div className="flex-1 flex flex-col gap-1">
                    <label className="text-[12px] font-bold text-ink">Hex Code Input:</label>
                    <input
                      type="text"
                      value={colorInput}
                      onChange={(e) => handleColorChange(e.target.value)}
                      placeholder="#0f766e"
                      className={`p-2 border rounded bg-surface text-ink font-mono text-sm outline-none w-full ${
                        colorError ? 'border-red-500/80 focus:border-red-500' : 'border-border'
                      }`}
                    />
                  </div>
                </div>
                {colorError && (
                  <p className="text-xs text-red-500 font-medium">{colorError}</p>
                )}
              </div>
            </div>

            {/* Results Grid with Copy Buttons */}
            {!colorError && (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4 border-t border-border/50">
                <div className="flex flex-col gap-1.5 p-3.5 bg-surface border border-border rounded-lg relative">
                  <span className="text-[11px] font-bold text-slate uppercase tracking-wider">HEX Code</span>
                  <div className="flex justify-between items-center mt-1">
                    <code className="text-[14px] font-mono font-bold text-primary">{colorInput}</code>
                    <button
                      onClick={() => handleCopyValue(colorInput, 'hex')}
                      className="text-xs font-semibold text-primary hover:text-primary/80 transition-colors cursor-pointer"
                    >
                      {copiedType === 'hex' ? 'Copied!' : 'Copy'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-col gap-1.5 p-3.5 bg-surface border border-border rounded-lg relative">
                  <span className="text-[11px] font-bold text-slate uppercase tracking-wider">RGB Format</span>
                  <div className="flex justify-between items-center mt-1">
                    <code className="text-[14px] font-mono font-bold text-primary">{colorRgb}</code>
                    <button
                      onClick={() => handleCopyValue(colorRgb, 'rgb')}
                      className="text-xs font-semibold text-primary hover:text-primary/80 transition-colors cursor-pointer"
                    >
                      {copiedType === 'rgb' ? 'Copied!' : 'Copy'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-col gap-1.5 p-3.5 bg-surface border border-border rounded-lg relative">
                  <span className="text-[11px] font-bold text-slate uppercase tracking-wider">HSL Format</span>
                  <div className="flex justify-between items-center mt-1">
                    <code className="text-[14px] font-mono font-bold text-primary">{colorHsl}</code>
                    <button
                      onClick={() => handleCopyValue(colorHsl, 'hsl')}
                      className="text-xs font-semibold text-primary hover:text-primary/80 transition-colors cursor-pointer"
                    >
                      {copiedType === 'hsl' ? 'Copied!' : 'Copy'}
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* HTML Previewer UI */}
        {toolId === 'html-previewer' && (
          <div className="flex flex-col w-full h-[80vh] border border-border rounded-2xl overflow-hidden bg-background shadow-sm relative">
            {/* Top Toolbar */}
            <div className="flex items-center justify-between px-4 py-3 bg-surface border-b border-border shrink-0">
              <div className="flex items-center gap-2">
                <Button 
                  id="html-preview-run-btn"
                  onClick={handleManualRun}
                  variant="primary"
                  className="flex items-center gap-2 text-[13px] font-bold"
                >
                  <Play className="w-4 h-4 fill-current" /> Run
                </Button>
                <div className="h-6 w-px bg-border mx-2" />
                <select 
                  id="html-preview-template-select"
                  onChange={(e) => loadHtmlTemplate(e.target.value)}
                  className="px-3 py-1.5 bg-background border border-border rounded-lg text-[13px] font-medium text-ink outline-none focus:border-primary cursor-pointer hidden md:block"
                >
                  <option value="">Load Template...</option>
                  <option value="blank">Blank HTML5</option>
                  <option value="login">Login Form</option>
                </select>
              </div>

              <div className="flex items-center gap-2">
                <button 
                  id="html-preview-beautify-btn"
                  onClick={formatHtmlCode}
                  className="p-2 text-slate hover:bg-slate/10 hover:text-ink rounded-lg transition-colors flex items-center gap-2 text-[13px] font-medium"
                  title="Beautify HTML"
                >
                  <AlignLeft className="w-4 h-4" /> <span className="hidden md:inline">Beautify</span>
                </button>
                <button 
                  id="html-preview-export-btn"
                  onClick={handleExportHTML}
                  className="p-2 text-slate hover:bg-slate/10 hover:text-ink rounded-lg transition-colors flex items-center gap-2 text-[13px] font-medium"
                  title="Download HTML"
                >
                  <Download className="w-4 h-4" /> <span className="hidden md:inline">Export</span>
                </button>
                <div className="h-6 w-px bg-border mx-2 hidden md:block" />
                <div className="hidden md:flex items-center gap-1 bg-background p-1 rounded-lg border border-border">
                  <button 
                    id="html-preview-layout-horiz-btn"
                    onClick={() => htmlPreviewStore.setLayout('horizontal')}
                    className={`p-1.5 rounded-md ${htmlPreviewStore.layout === 'horizontal' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                    title="Horizontal Split"
                  >
                    <Layout className="w-4 h-4" />
                  </button>
                  <button 
                    id="html-preview-layout-vert-btn"
                    onClick={() => htmlPreviewStore.setLayout('vertical')}
                    className={`p-1.5 rounded-md ${htmlPreviewStore.layout === 'vertical' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                    title="Vertical Split"
                  >
                    <Layout className="w-4 h-4 rotate-90" />
                  </button>
                  <button 
                    id="html-preview-layout-preview-btn"
                    onClick={() => htmlPreviewStore.setLayout('preview-only')}
                    className={`p-1.5 rounded-md ${htmlPreviewStore.layout === 'preview-only' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                    title="Preview Only"
                  >
                    <ImageIcon className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>

            {/* Main Workspace */}
            <div className="flex-1 overflow-hidden relative">
              {isMobile ? (
                <div className="flex flex-col h-full bg-surface">
                  <div className="flex border-b border-border bg-background shrink-0">
                    <button
                      id="html-preview-tab-editor"
                      onClick={() => setActiveTab('editor')}
                      className={`flex-1 py-3 text-[13px] font-bold uppercase tracking-wider transition-colors ${activeTab === 'editor' ? 'border-b-2 border-primary text-primary' : 'text-slate hover:bg-slate/5'}`}
                    >
                      Code Editor
                    </button>
                    <button
                      id="html-preview-tab-preview"
                      onClick={() => setActiveTab('preview')}
                      className={`flex-1 py-3 text-[13px] font-bold uppercase tracking-wider transition-colors ${activeTab === 'preview' ? 'border-b-2 border-primary text-primary' : 'text-slate hover:bg-slate/5'}`}
                    >
                      Live Preview
                    </button>
                  </div>
                  <div className="flex-1 relative">
                    {activeTab === 'editor' ? (
                      <MonacoEditorWrapper 
                        language="html" 
                        value={htmlPreviewStore.html} 
                        onChange={(v: string | undefined) => htmlPreviewStore.setHtml(v || '')} 
                      />
                    ) : (
                      <DevicePreviewFrame 
                        srcDoc={srcDoc} 
                        deviceView={htmlPreviewStore.deviceView} 
                        setDeviceView={htmlPreviewStore.setDeviceView} 
                      />
                    )}
                  </div>
                </div>
              ) : htmlPreviewStore.layout === 'preview-only' ? (
                <div className="w-full h-full relative p-2">
                  <DevicePreviewFrame 
                    srcDoc={srcDoc} 
                    deviceView={htmlPreviewStore.deviceView} 
                    setDeviceView={htmlPreviewStore.setDeviceView} 
                  />
                </div>
              ) : htmlPreviewStore.layout === 'code-only' ? (
                <MonacoEditorWrapper 
                  language="html" 
                  value={htmlPreviewStore.html} 
                  onChange={(v: string | undefined) => htmlPreviewStore.setHtml(v || '')} 
                />
              ) : (
                <PanelGroup orientation={htmlPreviewStore.layout === 'vertical' ? 'horizontal' : 'vertical'}>
                  <Panel defaultSize={50} minSize={30}>
                    <div className="flex flex-col h-full bg-surface border border-border rounded-lg overflow-hidden m-1 relative">
                      <MonacoEditorWrapper 
                        language="html" 
                        value={htmlPreviewStore.html} 
                        onChange={(v: string | undefined) => htmlPreviewStore.setHtml(v || '')} 
                      />
                    </div>
                  </Panel>
                  <PanelResizeHandle className={`bg-border hover:bg-primary/50 transition-colors ${htmlPreviewStore.layout === 'horizontal' ? 'h-2' : 'w-2'}`} />
                  <Panel defaultSize={50} minSize={30}>
                    <div className="w-full h-full relative flex flex-col p-1">
                      <DevicePreviewFrame 
                        srcDoc={srcDoc} 
                        deviceView={htmlPreviewStore.deviceView} 
                        setDeviceView={htmlPreviewStore.setDeviceView} 
                      />
                    </div>
                  </Panel>
                </PanelGroup>
              )}
            </div>
          </div>
        )}

        {/* Input & Output */}
        {toolId !== 'uuid-generator' && toolId !== 'unix-time-converter' && toolId !== 'color-picker-tool' && toolId !== 'html-previewer' && (
          <div className="grid grid-cols-1 gap-6">
            <div>
              <TextBox 
                value={input} 
                onChange={setInput} 
                label="Source Input" 
                error={error} 
                rows={8}
                placeholder={
                  toolId === 'jwt-decoder' 
                    ? 'Paste encoded JWT token here...' 
                    : 'Paste raw content here...'
                }
              />
            </div>
            {toolId === 'markdown-previewer' && output && (
              <div className="space-y-2">
                <label className="text-[13px] font-sans font-semibold text-ink uppercase tracking-wider">Markdown Output Preview</label>
                <div 
                  dangerouslySetInnerHTML={{ __html: sanitizeHtml(output) }}
                  className="w-full p-4 border border-border bg-surface rounded-xl prose max-w-none text-ink font-sans"
                />
              </div>
            )}
            <ResultBox value={output} downloadFileName={`${toolId}-result.txt`} />
          </div>
        )}
      </div>
    </ToolLayout>
  );
}

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { Group as PanelGroup, Panel, Separator as PanelResizeHandle } from 'react-resizable-panels';
import { useHtmlPreviewerStore } from '@/store/useCompilerStore';
import { MonacoEditorWrapper } from '../shared/MonacoEditorWrapper';
import { DevicePreviewFrame } from '../shared/DevicePreviewFrame';
import { ToolLayout } from '../shared/ToolLayout';
import { Play, Download, Upload, Layout, FileJson, AlignLeft, CheckCircle2, Image as ImageIcon } from 'lucide-react';
import { saveAs } from 'file-saver';

export function HtmlPreviewerClient() {
  const store = useHtmlPreviewerStore();
  const [srcDoc, setSrcDoc] = useState('');
  const [isMobile, setIsMobile] = useState(false);
  const [activeTab, setActiveTab] = useState<'editor' | 'preview'>('editor');
  const [runKey, setRunKey] = useState(0);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (store.autoRun) {
      const timeout = setTimeout(() => {
        setSrcDoc(store.html);
      }, 500);
      return () => clearTimeout(timeout);
    }
  }, [store.html, store.autoRun]);

  const handleManualRun = () => {
    setSrcDoc(store.html);
    setRunKey(prev => prev + 1);
  };

  const handleExportHTML = () => {
    const blob = new Blob([store.html], { type: 'text/html;charset=utf-8' });
    saveAs(blob, 'singulariti-preview.html');
  };

  const formatCode = async () => {
    try {
      const loadScript = (url: string): Promise<void> => {
        return new Promise((resolve, reject) => {
          if (document.querySelector(`script[src="${url}"]`)) {
            resolve();
            return;
          }
          const script = document.createElement('script');
          script.src = url;
          script.onload = () => resolve();
          script.onerror = () => reject(new Error(`Failed to load script: ${url}`));
          document.head.appendChild(script);
        });
      };

      await loadScript('https://cdn.jsdelivr.net/npm/js-beautify@1.15.1/js/lib/beautify-html.min.js');

      const w = window as any;
      if (typeof w.html_beautify === 'function') {
        store.setHtml(w.html_beautify(store.html, { indent_size: 2 }));
      } else {
        console.error('Beautifier library failed to initialize on window.');
      }
    } catch (e) {
      console.error('Beautify failed', e);
    }
  };

  const loadTemplate = (name: string) => {
    if (name === 'blank') {
      store.setHtml('<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n  <title>Blank Template</title>\n</head>\n<body>\n  \n</body>\n</html>');
    } else if (name === 'login') {
      store.setHtml('<!DOCTYPE html>\n<html>\n<head>\n  <style>\n    body { font-family: sans-serif; display: flex; justify-content: center; align-items: center; height: 100vh; background: #f1f5f9; }\n    .card { background: white; padding: 2rem; border-radius: 12px; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); width: 300px; }\n    input { width: 100%; padding: 0.5rem; margin-bottom: 1rem; border: 1px solid #cbd5e1; border-radius: 4px; box-sizing: border-box; }\n    button { width: 100%; padding: 0.5rem; background: #0f766e; color: white; border: none; border-radius: 4px; cursor: pointer; }\n  </style>\n</head>\n<body>\n  <div class="card">\n    <h2>Login</h2>\n    <input type="email" placeholder="Email">\n    <input type="password" placeholder="Password">\n    <button>Sign In</button>\n  </div>\n</body>\n</html>');
    }
  };

  const howToUse = [
    "Paste your raw HTML code into the Code Editor panel.",
    "The Live Preview panel will automatically render your HTML.",
    "Use the top toolbar to load templates, format your code, or export the result as an HTML file.",
    "Toggle between different layout modes using the layout icons in the toolbar."
  ];

  const faqs = [
    {
      question: "Is my code saved on your servers?",
      answer: "No, all code processing and rendering happens entirely locally in your browser. We do not store or transmit any of your code to our servers."
    },
    {
      question: "Can I use external CSS or JavaScript libraries?",
      answer: "Yes! You can include standard <link> and <script> tags within your HTML code to pull in external resources via CDN."
    },
    {
      question: "How do I format my code?",
      answer: "Simply click the 'Beautify' button in the toolbar. It will automatically indent and format your HTML code for better readability."
    }
  ];

  const renderEditor = () => {
    return (
      <div className="flex flex-col h-full bg-surface border border-border rounded-lg overflow-hidden m-1 relative">
        <div className="bg-background px-4 py-2 border-b border-border flex justify-between items-center text-[12px] font-sans font-bold text-ink uppercase tracking-wider">
          <div className="flex items-center gap-2">
            <FileJson className="w-4 h-4 text-primary" /> HTML Source
          </div>
        </div>
        <MonacoEditorWrapper language="html" value={store.html} onChange={(v) => store.setHtml(v || '')} />
      </div>
    );
  };

  return (
    <ToolLayout
      utilityId="html-previewer"
      title="Premium HTML Previewer"
      description="A lightning-fast, production-grade HTML renderer with Monaco Editor, live responsive preview, and automatic validation."
      categoryName="Developer Tools"
      categoryPath="/tools/dev"
      howToUse={howToUse}
      faqs={faqs}
    >
      <div className="flex flex-col w-full h-[85vh] border border-border rounded-2xl overflow-hidden bg-background shadow-sm relative">
        
        {/* Top Toolbar */}
        <div className="flex items-center justify-between px-4 py-3 bg-surface border-b border-border shrink-0">
          <div className="flex items-center gap-2">
            <button 
              onClick={handleManualRun}
              className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg text-[13px] font-bold hover:bg-primary/90 transition-colors"
            >
              <Play className="w-4 h-4 fill-current" /> Run
            </button>
            <div className="h-6 w-px bg-border mx-2" />
            <select 
              onChange={(e) => loadTemplate(e.target.value)}
              className="px-3 py-2 bg-background border border-border rounded-lg text-[13px] font-medium text-ink outline-none focus:border-primary cursor-pointer hidden md:block"
            >
              <option value="">Load Template...</option>
              <option value="blank">Blank HTML5</option>
              <option value="login">Login Form</option>
            </select>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={formatCode}
              className="p-2 text-slate hover:bg-slate/10 hover:text-ink rounded-lg transition-colors flex items-center gap-2 text-[13px] font-medium"
              title="Beautify HTML"
            >
              <AlignLeft className="w-4 h-4" /> <span className="hidden md:inline">Beautify</span>
            </button>
            <button 
              onClick={handleExportHTML}
              className="p-2 text-slate hover:bg-slate/10 hover:text-ink rounded-lg transition-colors flex items-center gap-2 text-[13px] font-medium"
              title="Download HTML"
            >
              <Download className="w-4 h-4" /> <span className="hidden md:inline">Export</span>
            </button>
            {/* Auto Run Toggle */}
            <label className="hidden md:flex items-center gap-2 mr-2 cursor-pointer text-[13px] font-medium text-slate hover:text-ink transition-colors">
              <input 
                type="checkbox" 
                checked={store.autoRun} 
                onChange={(e) => store.setAutoRun(e.target.checked)} 
                className="w-4 h-4 rounded border-border text-primary focus:ring-primary focus:ring-offset-background bg-background" 
              />
              Auto Run
            </label>
            <div className="h-6 w-px bg-border mx-2 hidden md:block" />
            <div className="hidden md:flex items-center gap-1 bg-background p-1 rounded-lg border border-border">
              <button 
                onClick={() => store.setLayout('code-only')}
                className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-[13px] font-medium transition-colors ${store.layout === 'code-only' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                title="Code Only"
              >
                <FileJson className="w-4 h-4" /> Code Only
              </button>
              <button 
                onClick={() => store.setLayout('horizontal')}
                className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-[13px] font-medium transition-colors ${store.layout === 'horizontal' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                title="Horizontal Split"
              >
                <Layout className="w-4 h-4" /> Split
              </button>
              <button 
                onClick={() => store.setLayout('vertical')}
                className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-[13px] font-medium transition-colors ${store.layout === 'vertical' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                title="Vertical Split"
              >
                <Layout className="w-4 h-4 rotate-90" /> Split
              </button>
              <button 
                onClick={() => store.setLayout('preview-only')}
                className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-md text-[13px] font-medium transition-colors ${store.layout === 'preview-only' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
                title="Full Screen Preview"
              >
                <ImageIcon className="w-4 h-4" /> Full Screen
              </button>
            </div>
          </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 overflow-hidden relative">
          {isMobile ? (
            <div className="flex flex-col h-full bg-surface">
              <div className="flex border-b border-border bg-background shrink-0">
                <button
                  onClick={() => setActiveTab('editor')}
                  className={`flex-1 py-3 text-[13px] font-bold uppercase tracking-wider transition-colors ${activeTab === 'editor' ? 'border-b-2 border-primary text-primary' : 'text-slate hover:bg-slate/5'}`}
                >
                  Code Editor
                </button>
                <button
                  onClick={() => setActiveTab('preview')}
                  className={`flex-1 py-3 text-[13px] font-bold uppercase tracking-wider transition-colors ${activeTab === 'preview' ? 'border-b-2 border-primary text-primary' : 'text-slate hover:bg-slate/5'}`}
                >
                  Live Preview
                </button>
              </div>
              <div className="flex-1 relative">
                {activeTab === 'editor' ? renderEditor() : (
                  <DevicePreviewFrame srcDoc={srcDoc} deviceView={store.deviceView} setDeviceView={store.setDeviceView} />
                )}
              </div>
            </div>
          ) : store.layout === 'preview-only' ? (
            <div className="w-full h-full relative p-2">
              <DevicePreviewFrame srcDoc={srcDoc} deviceView={store.deviceView} setDeviceView={store.setDeviceView} />
            </div>
          ) : store.layout === 'code-only' ? (
            renderEditor()
          ) : (
            <PanelGroup orientation={store.layout === 'vertical' ? 'horizontal' : 'vertical'}>
              <Panel defaultSize={50} minSize={30}>
                {renderEditor()}
              </Panel>
              <PanelResizeHandle className={`bg-border hover:bg-primary/50 transition-colors ${store.layout === 'horizontal' ? 'h-2' : 'w-2'}`} />
              <Panel defaultSize={50} minSize={30}>
                <div className="w-full h-full relative flex flex-col p-1">
                  <DevicePreviewFrame srcDoc={srcDoc} deviceView={store.deviceView} setDeviceView={store.setDeviceView} />
                </div>
              </Panel>
            </PanelGroup>
          )}
        </div>
      </div>
    </ToolLayout>
  );
}

"use client";

import React, { useState, useEffect, useRef } from 'react';
import { Group as PanelGroup, Panel, Separator as PanelResizeHandle } from 'react-resizable-panels';
import { useWebCompilerStore, LayoutMode } from '@/store/useCompilerStore';
import { MonacoEditorWrapper } from '../shared/MonacoEditorWrapper';
import { DevicePreviewFrame } from '../shared/DevicePreviewFrame';
import { ConsoleOverlay } from '../shared/ConsoleOverlay';
import { ToolLayout } from '../shared/ToolLayout';
import { Play, Download, Upload, Layout, FileJson, Settings2, Trash2, Eraser, AlignLeft } from 'lucide-react';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';

export function WebCompilerClient() {
  const store = useWebCompilerStore();
  const [srcDoc, setSrcDoc] = useState('');
  const [runKey, setRunKey] = useState(0);
  const [logs, setLogs] = useState<any[]>([]);
  const [activeTab, setActiveTab] = useState<'html' | 'css' | 'js'>('html');
  const [isMobile, setIsMobile] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    // Reset compiler inputs to default template when entering/re-entering the page
    store.loadTemplate({
      html: '<h1>Welcome to Singulariti Compiler</h1>\n<p>Start writing HTML, CSS, and JS...</p>',
      css: 'body {\n  font-family: system-ui, sans-serif;\n  padding: 1rem;\n}',
      js: 'console.log("Ready to code!");'
    });
  }, []);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Iframe Message Listener for Console
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      if (event.data?.source === 'singulariti-compiler-console') {
        setLogs(prev => [...prev, {
          id: Date.now().toString() + Math.random(),
          type: event.data.type,
          content: event.data.content,
          timestamp: Date.now()
        }]);
      }
    };
    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const generateSrcDoc = () => {
    const consoleInterceptor = `
      <script>
        const originalConsole = {
          log: console.log,
          error: console.error,
          warn: console.warn,
          info: console.info
        };

        function sendLog(type, args) {
          try {
            const content = Array.from(args).map(arg => {
              if (arg instanceof Event) return 'Event: ' + (arg.type || 'unknown');
              if (arg instanceof Error) return arg.toString();
              return typeof arg === 'object' ? JSON.stringify(arg, null, 2) : String(arg);
            }).join(' ');
            window.parent.postMessage({ source: 'singulariti-compiler-console', type, content }, '*');
          } catch(e) {
            window.parent.postMessage({ source: 'singulariti-compiler-console', type: 'error', content: 'Console logging error: ' + String(e) }, '*');
          }
        }

        console.log = function() { sendLog('log', arguments); originalConsole.log.apply(console, arguments); };
        console.error = function() { sendLog('error', arguments); };
        console.warn = function() { sendLog('warn', arguments); originalConsole.warn.apply(console, arguments); };
        console.info = function() { sendLog('info', arguments); originalConsole.info.apply(console, arguments); };
        
        window.addEventListener('error', function(e) {
          e.preventDefault();
          e.stopImmediatePropagation();
          sendLog('error', [e.message + ' at line ' + e.lineno]);
        });
        window.addEventListener('unhandledrejection', function(e) {
          e.preventDefault();
          e.stopImmediatePropagation();
          sendLog('error', ['Unhandled Promise Rejection: ' + (e.reason || 'unknown')]);
        });
      <\/script>
    `;

    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <meta name="viewport" content="width=device-width, initial-scale=1">
          ${consoleInterceptor}
          <style>${store.css}</style>
        </head>
        <body>
          ${store.html}
          <script>
            try {
              ${store.js}
            } catch (err) {
              console.error(err);
            }
          <\/script>
        </body>
      </html>
    `;
  };

  useEffect(() => {
    if (store.autoRun) {
      const timeout = setTimeout(() => {
        setSrcDoc(generateSrcDoc());
      }, 500);
      return () => clearTimeout(timeout);
    }
  }, [store.html, store.css, store.js, store.autoRun]);

  const handleManualRun = () => {
    setSrcDoc(generateSrcDoc());
    setRunKey(prev => prev + 1);
  };

  const handleExport = async () => {
    const zip = new JSZip();
    zip.file('index.html', `<!DOCTYPE html>\n<html>\n<head>\n  <meta charset="utf-8">\n  <link rel="stylesheet" href="styles.css">\n</head>\n<body>\n  ${store.html}\n  <script src="script.js"></script>\n</body>\n</html>`);
    zip.file('styles.css', store.css);
    zip.file('script.js', store.js);
    
    const content = await zip.generateAsync({ type: 'blob' });
    saveAs(content, 'singulariti-project.zip');
  };

  const loadTemplate = (name: string) => {
    if (name === 'portfolio') {
      store.loadTemplate({
        html: '<div class="portfolio">\n  <h1>My Portfolio</h1>\n  <p>Welcome to my premium playground.</p>\n  <button id="btn">Click Me</button>\n</div>',
        css: 'body { font-family: system-ui; background: #0f172a; color: white; display: flex; justify-content: center; align-items: center; height: 100vh; margin: 0; }\n.portfolio { text-align: center; }\nbutton { padding: 10px 20px; border-radius: 8px; border: none; background: #0ea5e9; color: white; cursor: pointer; }',
        js: 'document.getElementById("btn").addEventListener("click", () => {\n  console.log("Button clicked!");\n  alert("Hello from Singulariti!");\n});'
      });
    }
  };

  const formatCode = async () => {
    try {
      const loadScript = (url: string): Promise<void> => {
        return new Promise((resolve, reject) => {
          if (document.querySelector(`script[src="${url}"]`)) {
            resolve();
            return;
          }
          const script = document.createElement('script');
          script.src = url;
          script.onload = () => resolve();
          script.onerror = () => reject(new Error(`Failed to load script: ${url}`));
          document.head.appendChild(script);
        });
      };

      await Promise.all([
        loadScript('https://cdn.jsdelivr.net/npm/js-beautify@1.15.1/js/lib/beautify.min.js'),
        loadScript('https://cdn.jsdelivr.net/npm/js-beautify@1.15.1/js/lib/beautify-css.min.js'),
        loadScript('https://cdn.jsdelivr.net/npm/js-beautify@1.15.1/js/lib/beautify-html.min.js')
      ]);

      const w = window as any;
      if (typeof w.html_beautify === 'function' && typeof w.css_beautify === 'function' && typeof w.js_beautify === 'function') {
        store.setHtml(w.html_beautify(store.html, { indent_size: 2 }));
        store.setCss(w.css_beautify(store.css, { indent_size: 2 }));
        store.setJs(w.js_beautify(store.js, { indent_size: 2 }));
      } else {
        console.error('Beautifier libraries failed to initialize on window.');
