  const renderEditors = () => {
    if (isMobile) {
      return (
        <div className="flex flex-col h-full bg-surface border-r border-border">
          <div className="flex border-b border-border bg-background">
            {['html', 'css', 'js'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab as any)}
