"use client";

import React, { useState, useEffect, useRef } from 'react';
import { ToolLayout } from '@/components/tools/ToolLayout';
import { FileUploader } from '@/components/tools/FileUploader';
import { EditorCanvas } from './EditorCanvas';
import { EditorSettingsPanel } from './EditorSettingsPanel';
import { DownloadImageButton, DownloadParams } from './DownloadImageButton';
import { EditorSettings, EditorToolId, HistoryState, ImageState } from '../../../lib/image-editor/editorTypes';
import { renderImageWithSettings, getPreviewScaleFactor, getPositionCoordinates } from '../../../lib/image-editor/canvasHelpers';
import { downloadCanvasAsImage } from '../../../lib/image-editor/downloadHelpers';
import { validateImageFile } from '../../../lib/image-editor/validationHelpers';
import { Button } from '../../ui/Button';
import { Check, RotateCcw, Image as ImageIcon, ZoomIn, ZoomOut, Loader2 } from 'lucide-react';
import ReactCrop, { type Crop as CropType, centerCrop, makeAspectCrop } from 'react-image-crop';
import 'react-image-crop/dist/ReactCrop.css';
import { ToolRegistryItem } from '@/registry/types';
import { TransformableOverlay } from '@/components/ui/TransformableOverlay';

const DEFAULT_SETTINGS: EditorSettings = {
  crop: { x: 0, y: 0, width: 0, height: 0, unit: 'px' },
  resize: { width: 0, height: 0, lockAspect: true },
  rotate: { angle: 0 },
  flip: { horizontal: false, vertical: false },
  blur: { strength: 0 },
  pixelate: { size: 1 },
  grayscale: { enabled: false },
  upscaler: { scale: '1x', width: 0, height: 0, lockAspect: true, quality: 'medium' },
  enhancer: { auto: false, color: false, clarity: false, exposure: false, saturation: false },
  sharpen: { strength: 0 },
  denoiser: { strength: 0 },
  colorAdjust: { saturation: 0, hue: 0, vibrance: 0, temperature: 0, tint: 0, exposure: 0, gamma: 1.0 },
  brightnessContrast: { brightness: 0, contrast: 0, highlights: 0, shadows: 0 },
  watermark: { text: '', fontSize: 24, fontFamily: 'Sans-serif', color: '#ffffff', opacity: 30, rotation: 45, position: 'center', posX: 50, posY: 50, repeat: true },
  text: { content: '', fontSize: 36, fontFamily: 'Sans-serif', bold: false, italic: false, color: '#ffffff', bgColor: 'transparent', opacity: 100, rotation: 0, position: 'bottomLeft', posX: 10, posY: 90 },
  logo: { url: null, size: 20, opacity: 80, rotation: 0, position: 'bottomRight', posX: 90, posY: 90, lockAspect: true },
  bwToColor: { mode: 'tint', tintColor: '#ffffff' },
  colorToBw: { mode: 'custom', contrast: 0 }
};

const initDefaultSettingsWithImageDims = (width: number, height: number): EditorSettings => {
  const s = JSON.parse(JSON.stringify(DEFAULT_SETTINGS)) as EditorSettings;
  s.resize.width = width;
  s.resize.height = height;
  s.upscaler.width = width;
  s.upscaler.height = height;
  return s;
};

interface Props {
  tool: ToolRegistryItem;
}

function didBackgroundSettingsChange(prev: EditorSettings, current: EditorSettings): boolean {
  if (JSON.stringify(prev.crop) !== JSON.stringify(current.crop)) return true;
  if (JSON.stringify(prev.resize) !== JSON.stringify(current.resize)) return true;
  if (JSON.stringify(prev.rotate) !== JSON.stringify(current.rotate)) return true;
  if (JSON.stringify(prev.flip) !== JSON.stringify(current.flip)) return true;
  if (JSON.stringify(prev.blur) !== JSON.stringify(current.blur)) return true;
  if (JSON.stringify(prev.pixelate) !== JSON.stringify(current.pixelate)) return true;
  if (JSON.stringify(prev.grayscale) !== JSON.stringify(current.grayscale)) return true;
  if (JSON.stringify(prev.upscaler) !== JSON.stringify(current.upscaler)) return true;
  if (JSON.stringify(prev.enhancer) !== JSON.stringify(current.enhancer)) return true;
  if (JSON.stringify(prev.sharpen) !== JSON.stringify(current.sharpen)) return true;
  if (JSON.stringify(prev.denoiser) !== JSON.stringify(current.denoiser)) return true;
  if (JSON.stringify(prev.colorAdjust) !== JSON.stringify(current.colorAdjust)) return true;
  if (JSON.stringify(prev.brightnessContrast) !== JSON.stringify(current.brightnessContrast)) return true;
  if (JSON.stringify(prev.bwToColor) !== JSON.stringify(current.bwToColor)) return true;
  if (JSON.stringify(prev.colorToBw) !== JSON.stringify(current.colorToBw)) return true;
  
  if (prev.watermark.repeat || current.watermark.repeat) {
    if (JSON.stringify(prev.watermark) !== JSON.stringify(current.watermark)) return true;
  }
  
  return false;
}

interface LogoOverlayState {
  x: number;
  y: number;
  width: number;
  height: number;
  opacity: number;
  rotation: number;
}

export function SingleFeatureEditorClient({ tool }: Props) {
  const activeTool = (tool.options?.action || 'crop') as EditorToolId;
  const isLogoTool = tool.id === 'add-logo-overlay';

  const [imageState, setImageState] = useState<ImageState>({ file: null, url: null, width: 0, height: 0 });
  const [settings, setSettings] = useState<EditorSettings>(DEFAULT_SETTINGS);
  const [zoom, setZoom] = useState(100);

  // Logo overlay specific states and refs
  const [logoState, setLogoState] = useState<LogoOverlayState>({
    x: 0,
    y: 0,
    width: 100,
    height: 100,
    opacity: 80,
    rotation: 0
  });

  const logoStateRef = useRef<LogoOverlayState>({
    x: 0,
    y: 0,
    width: 100,
    height: 100,
    opacity: 80,
    rotation: 0
  });

  const viewportRef = useRef<HTMLDivElement>(null);
  const [containerWidth, setContainerWidth] = useState(800);
  const dragModeRef = useRef<'none' | 'drag' | 'rotate' | 'resize-tl' | 'resize-tr' | 'resize-bl' | 'resize-br'>('none');
  const startMousePosRef = useRef({ x: 0, y: 0 });
  const startLogoStateRef = useRef<LogoOverlayState>({ x: 0, y: 0, width: 100, height: 100, opacity: 80, rotation: 0 });
  const animationFrameIdRef = useRef<number | null>(null);

  const prevSettingsRef = useRef<EditorSettings>(DEFAULT_SETTINGS);
  const prevActiveToolRef = useRef<EditorToolId>('crop');
  const prevLogoImgRef = useRef<HTMLImageElement | null>(null);
  
  // Crop states
  const [crop, setCrop] = useState<CropType>();
  const [completedCrop, setCompletedCrop] = useState<CropType | null>(null);
  const cropImgRef = useRef<HTMLImageElement | null>(null);

  // Logo file state
  const [logoFile, setLogoFile] = useState<File | null>(null);
  const [logoImg, setLogoImg] = useState<HTMLImageElement | null>(null);

  // Processing indicators
  const [isProcessing, setIsProcessing] = useState(false);
  const [canvasLoading, setCanvasLoading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  
  // Error handling
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [logoError, setLogoError] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const activeImageRef = useRef<HTMLImageElement | null>(null);

  // Keep track of the original image data url to allow resetting
  const originalImageUrlRef = useRef<string | null>(null);

  // Safe URL references to prevent premature revocation
  const createdUrlsRef = useRef<string[]>([]);

  const createSafeObjectURL = (file: File): string => {
    const url = URL.createObjectURL(file);
    createdUrlsRef.current.push(url);
    return url;
  };

  const getOverlayCoords = (
    position: 'topLeft' | 'topRight' | 'center' | 'bottomLeft' | 'bottomRight' | 'custom',
    posX: number,
    posY: number,
    elementW: number,
    elementH: number
  ) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const previewScaleFactor = getPreviewScaleFactor(imageState.width, imageState.height, settings);
    const pos = getPositionCoordinates(
      position,
      canvasRef.current.offsetWidth,
      canvasRef.current.offsetHeight,
      elementW,
      elementH,
      posX,
      posY,
      previewScaleFactor
    );
    return {
      x: pos.x + elementW / 2,
      y: pos.y + elementH / 2
    };
  };

  // Clean URLs on unmount
  useEffect(() => {
    return () => {
      if (imageState.url) URL.revokeObjectURL(imageState.url);
      if (originalImageUrlRef.current && originalImageUrlRef.current.startsWith('blob:')) {
        URL.revokeObjectURL(originalImageUrlRef.current);
      }
      createdUrlsRef.current.forEach(url => {
        try { URL.revokeObjectURL(url); } catch (e) {}
      });
    };
  }, [imageState.url]);

  // Load logo file image element
  useEffect(() => {
    if (!logoFile) {
      setLogoImg(null);
      return;
    }
    const img = new Image();
    const url = settings.logo.url || createSafeObjectURL(logoFile);
    img.src = url;
    img.onload = () => {
      setLogoImg(img);
    };
  }, [logoFile, settings.logo.url]);

  // --- START: ADD LOGO OVERLAY SPECIFIC CUSTOM CANVAS IMPLEMENTATION ---
  useEffect(() => {
    if (!isLogoTool || !viewportRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        if (entry.contentRect.width > 0) {
          setContainerWidth(entry.contentRect.width);
        }
      }
    });
    observer.observe(viewportRef.current);
    return () => {
      observer.disconnect();
    };
  }, [isLogoTool, viewportRef.current]);

  const drawPreviewCanvas = () => {
    const canvas = canvasRef.current;
    if (!canvas || !activeImageRef.current || !imageState.width) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const containerHeight = 450;
    const scale = Math.min(containerWidth / imageState.width, containerHeight / imageState.height);
    const previewWidth = imageState.width * scale;
    const previewHeight = imageState.height * scale;

    const displayWidth = previewWidth * (zoom / 100);
    const displayHeight = previewHeight * (zoom / 100);

    const dpr = window.devicePixelRatio || 1;
    canvas.width = displayWidth * dpr;
    canvas.height = displayHeight * dpr;
    canvas.style.width = `${displayWidth}px`;
    canvas.style.height = `${displayHeight}px`;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.save();
    ctx.scale(dpr, dpr);

    // Draw base image
    ctx.drawImage(activeImageRef.current, 0, 0, displayWidth, displayHeight);

    // Draw logo if loaded
    if (logoImg && settings.logo.url) {
      const state = logoStateRef.current;

      const mapScaleX = displayWidth / imageState.width;
      const mapScaleY = displayHeight / imageState.height;

      const previewX = state.x * mapScaleX;
      const previewY = state.y * mapScaleY;
      const previewW = state.width * mapScaleX;
      const previewH = state.height * mapScaleY;

      ctx.save();
      ctx.translate(previewX + previewW / 2, previewY + previewH / 2);
      ctx.rotate((state.rotation * Math.PI) / 180);
      ctx.globalAlpha = state.opacity / 100;
      ctx.drawImage(logoImg, -previewW / 2, -previewH / 2, previewW, previewH);

      // Restore alpha, draw UI selection
      ctx.globalAlpha = 1.0;
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 1.5;
      ctx.setLineDash([4, 4]);
      ctx.strokeRect(-previewW / 2, -previewH / 2, previewW, previewH);
      ctx.setLineDash([]); // Reset

      // Handles
      const handleSize = 6;
      ctx.fillStyle = '#ffffff';
      ctx.strokeStyle = '#2563eb';
      ctx.lineWidth = 1.5;

      const drawHandle = (hx: number, hy: number) => {
        ctx.beginPath();
        ctx.rect(hx - handleSize / 2, hy - handleSize / 2, handleSize, handleSize);
        ctx.fill();
        ctx.stroke();
      };

      drawHandle(-previewW / 2, -previewH / 2); // tl
      drawHandle(previewW / 2, -previewH / 2);  // tr
      drawHandle(-previewW / 2, previewH / 2);  // bl
      drawHandle(previewW / 2, previewH / 2);   // br

      // Rotation handle
      ctx.beginPath();
      ctx.moveTo(0, -previewH / 2);
      ctx.lineTo(0, -previewH / 2 - 20);
      ctx.stroke();

      ctx.beginPath();
      ctx.arc(0, -previewH / 2 - 20, 4, 0, 2 * Math.PI);
      ctx.fill();
      ctx.stroke();

      ctx.restore();
    }

    ctx.restore();
  };

  const requestDraw = () => {
    if (animationFrameIdRef.current !== null) {
      cancelAnimationFrame(animationFrameIdRef.current);
    }
    animationFrameIdRef.current = requestAnimationFrame(() => {
      drawPreviewCanvas();
      animationFrameIdRef.current = null;
    });
  };

  // Sync settings changes to refs and redraw preview canvas
  useEffect(() => {
    if (!isLogoTool || !imageState.width || !logoImg) return;

    const logoW = (settings.logo.size / 100) * imageState.width;
    const logoH = settings.logo.lockAspect
      ? logoW * (logoImg.naturalHeight / logoImg.naturalWidth)
      : logoW;

    const pos = getPositionCoordinates(
      settings.logo.position,
      imageState.width,
      imageState.height,
      logoW,
      logoH,
      settings.logo.posX,
      settings.logo.posY,
      1
    );

    const newState = {
      x: pos.x,
      y: pos.y,
      width: logoW,
      height: logoH,
      opacity: settings.logo.opacity,
      rotation: settings.logo.rotation
    };

    const isDifferent =
      Math.abs(logoStateRef.current.x - newState.x) > 0.1 ||
      Math.abs(logoStateRef.current.y - newState.y) > 0.1 ||
      Math.abs(logoStateRef.current.width - newState.width) > 0.1 ||
      Math.abs(logoStateRef.current.height - newState.height) > 0.1 ||
      logoStateRef.current.opacity !== newState.opacity ||
      logoStateRef.current.rotation !== newState.rotation;

    if (isDifferent) {
      logoStateRef.current = newState;
      setLogoState(newState);
      requestDraw();
    }
  }, [settings.logo, logoImg, imageState.width, imageState.height, isLogoTool]);

  useEffect(() => {
    if (isLogoTool) {
      requestDraw();
    }
  }, [isLogoTool, containerWidth, zoom, logoImg]);

  const handleMouseDownLogo = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current || !imageState.width || !logoImg || !settings.logo.url) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const containerHeight = 450;
    const scale = Math.min(containerWidth / imageState.width, containerHeight / imageState.height);
    const previewWidth = imageState.width * scale;
    const previewHeight = imageState.height * scale;

    const displayWidth = previewWidth * (zoom / 100);
    const displayHeight = previewHeight * (zoom / 100);

    const mapScaleX = displayWidth / imageState.width;
    const mapScaleY = displayHeight / imageState.height;

    const state = logoStateRef.current;
    const previewX = state.x * mapScaleX;
    const previewY = state.y * mapScaleY;
    const previewW = state.width * mapScaleX;
    const previewH = state.height * mapScaleY;

    const cx = previewX + previewW / 2;
    const cy = previewY + previewH / 2;

    const dx = mouseX - cx;
    const dy = mouseY - cy;
    const rad = -(state.rotation * Math.PI) / 180;
    const localX = dx * Math.cos(rad) - dy * Math.sin(rad);
    const localY = dx * Math.sin(rad) + dy * Math.cos(rad);

    const handleSize = 10;
    let mode: typeof dragModeRef.current = 'none';

    const dist = (x1: number, y1: number, x2: number, y2: number) =>
      Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);

    if (dist(localX, localY, 0, -previewH / 2 - 20) <= handleSize + 2) {
      mode = 'rotate';
    } else if (dist(localX, localY, -previewW / 2, -previewH / 2) <= handleSize) {
      mode = 'resize-tl';
    } else if (dist(localX, localY, previewW / 2, -previewH / 2) <= handleSize) {
      mode = 'resize-tr';
    } else if (dist(localX, localY, -previewW / 2, previewH / 2) <= handleSize) {
      mode = 'resize-bl';
    } else if (dist(localX, localY, previewW / 2, previewH / 2) <= handleSize) {
      mode = 'resize-br';
    } else if (
      Math.abs(localX) <= previewW / 2 &&
      Math.abs(localY) <= previewH / 2
    ) {
      mode = 'drag';
    }

    if (mode !== 'none') {
      dragModeRef.current = mode;
      startMousePosRef.current = { x: mouseX, y: mouseY };
      startLogoStateRef.current = { ...state };
      setIsDragging(true);
    }
  };

  const handleMouseMoveLogo = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (dragModeRef.current === 'none' || !canvasRef.current || !imageState.width || !logoImg) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const containerHeight = 450;
    const scale = Math.min(containerWidth / imageState.width, containerHeight / imageState.height);
    const previewWidth = imageState.width * scale;
    const previewHeight = imageState.height * scale;

    const displayWidth = previewWidth * (zoom / 100);
    const displayHeight = previewHeight * (zoom / 100);

    const mapScaleX = displayWidth / imageState.width;
    const mapScaleY = displayHeight / imageState.height;

    const dx = mouseX - startMousePosRef.current.x;
    const dy = mouseY - startMousePosRef.current.y;

    const state = logoStateRef.current;
    const startState = startLogoStateRef.current;

    if (dragModeRef.current === 'drag') {
      const moveX = dx / mapScaleX;
      const moveY = dy / mapScaleY;

      let nextX = startState.x + moveX;
      let nextY = startState.y + moveY;

      nextX = Math.max(0, Math.min(imageState.width - startState.width, nextX));
      nextY = Math.max(0, Math.min(imageState.height - startState.height, nextY));

      logoStateRef.current.x = nextX;
      logoStateRef.current.y = nextY;
      requestDraw();
    } else if (dragModeRef.current === 'rotate') {
      const previewX = startState.x * mapScaleX;
      const previewY = startState.y * mapScaleY;
      const previewW = startState.width * mapScaleX;
      const previewH = startState.height * mapScaleY;
      const cx = previewX + previewW / 2;
      const cy = previewY + previewH / 2;

      const vx = mouseX - cx;
      const vy = mouseY - cy;
      const angleDeg = Math.round(Math.atan2(vx, -vy) * (180 / Math.PI));
      logoStateRef.current.rotation = angleDeg;
      requestDraw();
    } else {
      const startCX = startState.x + startState.width / 2;
      const startCY = startState.y + startState.height / 2;
      const rad = (startState.rotation * Math.PI) / 180;
      const cosVal = Math.cos(rad);
      const sinVal = Math.sin(rad);

      let localFixedX = 0;
      let localFixedY = 0;
      if (dragModeRef.current === 'resize-br') { localFixedX = -startState.width / 2; localFixedY = -startState.height / 2; }
      else if (dragModeRef.current === 'resize-bl') { localFixedX = startState.width / 2; localFixedY = -startState.height / 2; }
      else if (dragModeRef.current === 'resize-tr') { localFixedX = -startState.width / 2; localFixedY = startState.height / 2; }
      else if (dragModeRef.current === 'resize-tl') { localFixedX = startState.width / 2; localFixedY = startState.height / 2; }

      const fixedX = startCX + localFixedX * cosVal - localFixedY * sinVal;
      const fixedY = startCY + localFixedX * sinVal + localFixedY * cosVal;

      const mouseOrigX = mouseX / mapScaleX;
      const mouseOrigY = mouseY / mapScaleY;

      const vecX = mouseOrigX - fixedX;
      const vecY = mouseOrigY - fixedY;

      const newW = vecX * cosVal + vecY * sinVal;
      const newH = -vecX * sinVal + vecY * cosVal;

      let w = Math.abs(newW);
      let h = Math.abs(newH);

      if (settings.logo.lockAspect) {
        const aspect = logoImg.naturalWidth / logoImg.naturalHeight;
        h = w / aspect;
      }

      w = Math.min(imageState.width * 2, Math.max(10, w));
      h = Math.min(imageState.height * 2, Math.max(10, h));

      let signX = 1;
      let signY = 1;
      if (dragModeRef.current === 'resize-br') { signX = 1; signY = 1; }
      else if (dragModeRef.current === 'resize-bl') { signX = -1; signY = 1; }
      else if (dragModeRef.current === 'resize-tr') { signX = 1; signY = -1; }
      else if (dragModeRef.current === 'resize-tl') { signX = -1; signY = -1; }

      const newCX = fixedX + (w / 2) * signX * cosVal - (h / 2) * signY * sinVal;
      const newCY = fixedY + (w / 2) * signX * sinVal + (h / 2) * signY * cosVal;

      logoStateRef.current.width = w;
      logoStateRef.current.height = h;
      logoStateRef.current.x = newCX - w / 2;
      logoStateRef.current.y = newCY - h / 2;
      requestDraw();
    }
  };

  const handleMouseUpLogo = () => {
    if (dragModeRef.current !== 'none') {
      dragModeRef.current = 'none';
      setIsDragging(false);

      const finalState = { ...logoStateRef.current };
      setLogoState(finalState);

      const cx = finalState.x + finalState.width / 2;
      const cy = finalState.y + finalState.height / 2;
      const pctX = Math.min(100, Math.max(0, (cx / imageState.width) * 100));
      const pctY = Math.min(100, Math.max(0, (cy / imageState.height) * 100));
      const pctSize = Math.min(100, Math.max(5, (finalState.width / imageState.width) * 100));

      setSettings((prev) => ({
        ...prev,
        logo: {
          ...prev.logo,
          position: 'custom',
          posX: pctX,
          posY: pctY,
          size: pctSize,
          rotation: finalState.rotation
        }
      }));
    }
  };

  const updateCursorStyle = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (dragModeRef.current !== 'none' || !canvasRef.current || !imageState.width || !logoImg) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    const containerHeight = 450;
    const scale = Math.min(containerWidth / imageState.width, containerHeight / imageState.height);
    const previewWidth = imageState.width * scale;
    const previewHeight = imageState.height * scale;

    const displayWidth = previewWidth * (zoom / 100);
    const displayHeight = previewHeight * (zoom / 100);

    const mapScaleX = displayWidth / imageState.width;
    const mapScaleY = displayHeight / imageState.height;

    const state = logoStateRef.current;
    const previewX = state.x * mapScaleX;
    const previewY = state.y * mapScaleY;
    const previewW = state.width * mapScaleX;
    const previewH = state.height * mapScaleY;

    const cx = previewX + previewW / 2;
    const cy = previewY + previewH / 2;

    const dx = mouseX - cx;
    const dy = mouseY - cy;
    const rad = -(state.rotation * Math.PI) / 180;
    const localX = dx * Math.cos(rad) - dy * Math.sin(rad);
    const localY = dx * Math.sin(rad) + dy * Math.cos(rad);

    const handleSize = 10;
    const dist = (x1: number, y1: number, x2: number, y2: number) =>
      Math.sqrt((x1 - x2) ** 2 + (y1 - y2) ** 2);

    if (dist(localX, localY, 0, -previewH / 2 - 20) <= handleSize + 2) {
      canvas.style.cursor = 'alias';
    } else if (
      dist(localX, localY, -previewW / 2, -previewH / 2) <= handleSize ||
      dist(localX, localY, previewW / 2, previewH / 2) <= handleSize
    ) {
      canvas.style.cursor = 'nwse-resize';
    } else if (
      dist(localX, localY, previewW / 2, -previewH / 2) <= handleSize ||
      dist(localX, localY, -previewW / 2, previewH / 2) <= handleSize
    ) {
      canvas.style.cursor = 'nesw-resize';
    } else if (
      Math.abs(localX) <= previewW / 2 &&
      Math.abs(localY) <= previewH / 2
    ) {
      canvas.style.cursor = 'move';
    } else {
      canvas.style.cursor = 'default';
    }
  };
  // --- END: ADD LOGO OVERLAY SPECIFIC CUSTOM CANVAS IMPLEMENTATION ---

  const handleLogoUpload = (file: File) => {
    const url = createSafeObjectURL(file);
    setLogoFile(file);
    setSettings(prev => ({
      ...prev,
      logo: {
        ...prev.logo,
        url
      }
    }));
  };

  const handleLogoRemove = () => {
    setLogoFile(null);
    setLogoImg(null);
    setSettings(prev => ({
      ...prev,
      logo: {
        ...prev.logo,
        url: null
      }
    }));
  };

  const handleFileSelected = (files: File[]) => {
    if (files.length === 0) return;
    setError(null);
    setWarning(null);
    setLogoError(null);
    setLogoFile(null);
    setLogoImg(null);

    const file = files[0];
    const validation = validateImageFile(file);
    if (!validation.isValid && validation.type === 'error') {
      setError(validation.message);
      return;
    }
    if (validation.message && validation.type === 'warning') {
      setWarning(validation.message);
    }

    const url = URL.createObjectURL(file);
    originalImageUrlRef.current = url;

    const img = new Image();
    img.src = url;
    img.onload = () => {
      const initialWidth = img.naturalWidth;
      const initialHeight = img.naturalHeight;
      
      setImageState({
        file,
        url,
        width: initialWidth,
        height: initialHeight
      });

      activeImageRef.current = img;
      setSettings(initDefaultSettingsWithImageDims(initialWidth, initialHeight));

      const initialCrop = centerCrop(
        makeAspectCrop(
          { unit: '%', width: 90 },
          initialWidth / initialHeight,
          initialWidth,
          initialHeight
        ),
        initialWidth,
        initialHeight
      );
      setCrop(initialCrop);
      setCompletedCrop(initialCrop);
    };
    img.onerror = () => {
      setError('Failed to load image. The file may be corrupted.');
    };
  };

  // Re-render canvas whenever settings changes
  useEffect(() => {
    if (isLogoTool) return;
    if (!activeImageRef.current || !canvasRef.current) return;

    const prevSettings = prevSettingsRef.current;
    prevSettingsRef.current = settings;

    const bgChanged = didBackgroundSettingsChange(prevSettings, settings);
    const shouldReRender = bgChanged ||
      activeTool !== prevActiveToolRef.current ||
      logoImg !== prevLogoImgRef.current;

    prevActiveToolRef.current = activeTool;
    prevLogoImgRef.current = logoImg;

    if (!shouldReRender) {
      return;
    }

    setCanvasLoading(true);
    const debounce = setTimeout(async () => {
      try {
        await renderImageWithSettings(
          activeImageRef.current!,
          canvasRef.current!,
          settings,
          logoImg,
          false,
          activeTool,
          true
        );
      } catch (err) {
        console.error('Render error:', err);
      } finally {
        setCanvasLoading(false);
      }
    }, 40);

    return () => clearTimeout(debounce);
  }, [settings, logoImg, activeTool]);

  const handleReset = () => {
    if (activeImageRef.current) {
      const initialWidth = activeImageRef.current.naturalWidth;
      const initialHeight = activeImageRef.current.naturalHeight;
      setImageState(prev => ({
        ...prev,
        width: initialWidth,
        height: initialHeight
      }));
      
      setSettings(initDefaultSettingsWithImageDims(initialWidth, initialHeight));
      
      const initialCrop = centerCrop(
        makeAspectCrop(
          { unit: '%', width: 90 },
          initialWidth / initialHeight,
          initialWidth,
          initialHeight
        ),
        initialWidth,
        initialHeight
      );
      setCrop(initialCrop);
      setCompletedCrop(initialCrop);
      setLogoFile(null);
      setLogoImg(null);

      if (isLogoTool) {
        logoStateRef.current = {
          x: 0,
          y: 0,
          width: 100,
          height: 100,
          opacity: 80,
          rotation: 0
        };
        setLogoState({
          x: 0,
          y: 0,
          width: 100,
          height: 100,
          opacity: 80,
          rotation: 0
        });
        requestDraw();
      }
    }
  };

  const handleClear = () => {
    if (imageState.url) URL.revokeObjectURL(imageState.url);
    setImageState({ file: null, url: null, width: 0, height: 0 });
    activeImageRef.current = null;
    originalImageUrlRef.current = null;
    setSettings(JSON.parse(JSON.stringify(DEFAULT_SETTINGS)));
    setLogoFile(null);
    setLogoImg(null);
    setError(null);
    setWarning(null);
    setLogoError(null);
  };

  const handleDownload = async (params: DownloadParams) => {
    if (!activeImageRef.current) return;
    if (activeTool !== 'crop' && !canvasRef.current) return;

    setIsProcessing(true);
    try {
      if (isLogoTool) {
        if (!logoImg || !settings.logo.url) {
          setError("Please upload a logo first.");
          setIsProcessing(false);
          return;
        }

        const offscreenCanvas = document.createElement('canvas');
        const ctx = offscreenCanvas.getContext('2d');
        if (!ctx) throw new Error("Could not get 2d context");

        offscreenCanvas.width = imageState.width;
        offscreenCanvas.height = imageState.height;

        // 1. Draw base image at full resolution
        ctx.drawImage(activeImageRef.current!, 0, 0, imageState.width, imageState.height);

        // 2. Draw logo at original coordinates
        const state = logoStateRef.current;
        ctx.save();
        ctx.translate(state.x + state.width / 2, state.y + state.height / 2);
        ctx.rotate((state.rotation * Math.PI) / 180);
        ctx.globalAlpha = state.opacity / 100;
        ctx.drawImage(logoImg, -state.width / 2, -state.height / 2, state.width, state.height);
        ctx.restore();

        await downloadCanvasAsImage(offscreenCanvas, {
          fileName: params.fileName,
          format: params.format,
          quality: params.quality
        });
        
        setIsProcessing(false);
        return;
      }

      if (activeTool === 'crop' && completedCrop && cropImgRef.current) {
        const offscreenCanvas = document.createElement('canvas');
        const ctx = offscreenCanvas.getContext('2d');
        if (!ctx) throw new Error("Could not get 2d context");

        const img = activeImageRef.current;
        const scaleX = img.naturalWidth / cropImgRef.current.width;
        const scaleY = img.naturalHeight / cropImgRef.current.height;

        const pixelCrop = completedCrop.unit === '%'
          ? {
              x: (completedCrop.x / 100) * cropImgRef.current.width,
              y: (completedCrop.y / 100) * cropImgRef.current.height,
              width: (completedCrop.width / 100) * cropImgRef.current.width,
              height: (completedCrop.height / 100) * cropImgRef.current.height,
            }
          : completedCrop;

        const srcX = pixelCrop.x * scaleX;
        const srcY = pixelCrop.y * scaleY;
        const srcW = pixelCrop.width * scaleX;
        const srcH = pixelCrop.height * scaleY;

        offscreenCanvas.width = Math.max(1, srcW);
        offscreenCanvas.height = Math.max(1, srcH);
        ctx.clearRect(0, 0, offscreenCanvas.width, offscreenCanvas.height);
        ctx.drawImage(img, srcX, srcY, srcW, srcH, 0, 0, srcW, srcH);
        
        await downloadCanvasAsImage(offscreenCanvas, {
          fileName: params.fileName,
          format: params.format,
          quality: params.quality
        });
        
        return;
      }

      // Normal render download
      const offscreenCanvas = document.createElement('canvas');
      await renderImageWithSettings(
        activeImageRef.current!,
        offscreenCanvas,
        settings,
        logoImg,
        true, // isFullResolution = true
        activeTool
      );

      await downloadCanvasAsImage(offscreenCanvas, {
        fileName: params.fileName,
        format: params.format,
        quality: params.quality
      });
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Failed to download image.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCanvasInteraction = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (!canvasRef.current || !activeImageRef.current) return;
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    
    const clickX = e.clientX - rect.left;
    const clickY = e.clientY - rect.top;
    
    const pctX = Math.min(100, Math.max(0, Math.round((clickX / rect.width) * 100)));
    const pctY = Math.min(100, Math.max(0, Math.round((clickY / rect.height) * 100)));

    if (activeTool === 'text') {
      setSettings(prev => ({
        ...prev,
        text: { ...prev.text, position: 'custom', posX: pctX, posY: pctY }
      }));
    } else if (activeTool === 'logo') {
      setSettings(prev => ({
        ...prev,
        logo: { ...prev.logo, position: 'custom', posX: pctX, posY: pctY }
      }));
    } else if (activeTool === 'watermark') {
      setSettings(prev => ({
        ...prev,
        watermark: { ...prev.watermark, position: 'custom', posX: pctX, posY: pctY }
      }));
    }
  };

  const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (activeTool === 'text' || activeTool === 'logo' || activeTool === 'watermark') {
      setIsDragging(true);
      handleCanvasInteraction(e);
    }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (isDragging) {
      handleCanvasInteraction(e);
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  return (
    <div className="w-full max-w-7xl mx-auto my-12">
      {error && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg text-red-600 text-sm">
          {error}
        </div>
      )}
      {warning && (
        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-lg text-amber-700 text-sm">
          {warning}
        </div>
      )}

      {!imageState.file ? (
        <FileUploader
          onFilesSelected={handleFileSelected}
          multiple={false}
          accept={{ 'image/*': ['.png', '.jpg', '.jpeg', '.webp', '.svg'] }}
          title={`Upload an image to ${tool.name.toLowerCase()}`}
          subtitle="Supports JPG, JPEG, PNG, or WEBP formats up to 15MB"
        />
      ) : (
        <div className="flex flex-col gap-6 max-w-4xl mx-auto">
          
          {/* Top: Preview Viewport */}
          <div className="flex flex-col items-center bg-surface border border-border rounded-xl p-4 min-h-[450px] w-full">
            {isLogoTool ? (
              <div className="flex items-center gap-2 mb-4 bg-background/80 backdrop-blur-xs border border-border px-3 py-1.5 rounded-lg shadow-xs z-20">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setZoom(prev => Math.max(25, prev - 25))}
                  disabled={zoom <= 25}
                  className="h-8 w-8 p-0"
                  title="Zoom Out"
                >
                  <ZoomOut className="w-4 h-4" />
                </Button>
                <span className="text-xs font-semibold font-mono min-w-[48px] text-center text-ink select-none">
                  {zoom}%
                </span>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setZoom(prev => Math.min(400, prev + 25))}
                  disabled={zoom >= 400}
                  className="h-8 w-8 p-0"
                  title="Zoom In"
                >
                  <ZoomIn className="w-4 h-4" />
                </Button>
                <div className="h-4 w-[1px] bg-border mx-1" />
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setZoom(100)}
                  disabled={zoom === 100}
                  className="px-2 h-8 text-xs text-ink hover:text-primary"
                  title="Reset Zoom"
                >
                  Reset Zoom
                </Button>
                <div className="h-4 w-[1px] bg-border mx-1" />
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setZoom(100)}
                  disabled={zoom === 100}
                  className="px-2 h-8 text-xs text-ink hover:text-primary"
                  title="Fit to Screen"
                >
                  Fit to Screen
                </Button>
              </div>
            ) : (
              activeTool !== 'crop' && (
                <div className="flex items-center gap-2 mb-4 bg-background/80 backdrop-blur-xs border border-border px-3 py-1.5 rounded-lg shadow-xs z-20">
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setZoom(prev => Math.max(25, prev - 25))}
                    disabled={zoom <= 25}
                    className="h-8 w-8 p-0"
                    title="Zoom Out"
                  >
                    <ZoomOut className="w-4 h-4" />
                  </Button>
                  <span className="text-xs font-semibold font-mono min-w-[48px] text-center text-ink select-none">
                    {zoom}%
                  </span>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setZoom(prev => Math.min(400, prev + 25))}
                    disabled={zoom >= 400}
                    className="h-8 w-8 p-0"
                    title="Zoom In"
                  >
                    <ZoomIn className="w-4 h-4" />
                  </Button>
                  <div className="h-4 w-[1px] bg-border mx-1" />
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setZoom(100)}
                    disabled={zoom === 100}
                    className="px-2 h-8 text-xs text-ink hover:text-primary"
                  >
                    Reset
                  </Button>
                </div>
              )
            )}

            {isLogoTool ? (
              <div 
                ref={viewportRef}
                className="relative rounded-xl border border-border bg-background/50 overflow-auto min-h-[400px] w-full flex items-center justify-center p-4 select-none"
                style={{ height: '450px' }}
              >
                <div 
                  className="absolute inset-0 opacity-10 pointer-events-none" 
                  style={{
                    backgroundImage: `linear-gradient(45deg, var(--color-border) 25%, transparent 25%), 
                                      linear-gradient(-45deg, var(--color-border) 25%, transparent 25%), 
                                      linear-gradient(45deg, transparent 75%, var(--color-border) 75%), 
                                      linear-gradient(-45deg, transparent 75%, var(--color-border) 75%)`,
                    backgroundSize: '20px 20px',
                    backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px'
                  }}
                />
                
                {(canvasLoading || isProcessing) && (
                  <div className="absolute inset-0 flex items-center justify-center bg-surface/60 backdrop-blur-xs z-10 transition-opacity">
                    <div className="flex flex-col items-center gap-2">
                      <Loader2 className="w-8 h-8 animate-spin text-primary" />
                      <span className="text-[12px] font-sans font-medium text-slate">Rendering changes...</span>
                    </div>
                  </div>
                )}

                <div className="relative inline-flex shadow-md rounded-lg border border-border bg-white z-0">
                  <canvas 
                    ref={canvasRef} 
                    onMouseDown={handleMouseDownLogo}
                    onMouseMove={(e) => {
                      if (dragModeRef.current !== 'none') {
                        handleMouseMoveLogo(e);
                      } else {
                        updateCursorStyle(e);
                      }
                    }}
                    onMouseUp={handleMouseUpLogo}
                    onMouseLeave={handleMouseUpLogo}
                    className="max-w-none rounded-lg" 
                  />
                </div>
              </div>
            ) : activeTool === 'crop' ? (
              <div className="relative rounded-xl border border-border bg-background/50 overflow-hidden min-h-[400px] flex items-center justify-center p-4 w-full select-none">
                <div 
                  className="absolute inset-0 opacity-10 pointer-events-none" 
                  style={{
                    backgroundImage: `linear-gradient(45deg, var(--color-border) 25%, transparent 25%), 
                                      linear-gradient(-45deg, var(--color-border) 25%, transparent 25%), 
                                      linear-gradient(45deg, transparent 75%, var(--color-border) 75%), 
                                      linear-gradient(-45deg, transparent 75%, var(--color-border) 75%)`,
                    backgroundSize: '20px 20px',
                    backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px'
                  }}
                />
                <div className="max-w-full max-h-[58vh] flex justify-center items-center z-0">
                  <ReactCrop crop={crop} onChange={c => setCrop(c)} onComplete={c => setCompletedCrop(c)}>
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img 
                      ref={cropImgRef} 
                      src={imageState.url!} 
                      alt="Crop bounding viewport" 
                      className="max-w-full max-h-[55vh] object-contain shadow-xs rounded-lg border border-border bg-white" 
                    />
                  </ReactCrop>
                </div>
              </div>
            ) : (
              <EditorCanvas 
                canvasRef={canvasRef} 
                isLoading={canvasLoading || isProcessing} 
                zoom={zoom}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
              >
                {/* Text Overlay */}
                {settings.text.content.trim() !== '' && canvasRef.current && (
                  <TransformableOverlay
                    isActive={activeTool === 'text'}
                    onSelect={() => {}}
                    zoom={zoom}
                    x={getOverlayCoords(
                      settings.text.position,
                      settings.text.posX,
                      settings.text.posY,
                      settings.text.fontSize * 4,
                      settings.text.fontSize * 1.5
                    ).x}
                    y={getOverlayCoords(
                      settings.text.position,
                      settings.text.posX,
                      settings.text.posY,
                      settings.text.fontSize * 4,
                      settings.text.fontSize * 1.5
                    ).y}
                    width={settings.text.fontSize * 4} // Approximation for bounding box
                    height={settings.text.fontSize * 1.5}
                    rotation={settings.text.rotation}
                    lockAspect={false}
                    onChange={(updates) => {
                      if (canvasRef.current) {
                        const px = Math.min(100, Math.max(0, (updates.x / canvasRef.current.offsetWidth) * 100));
                        const py = Math.min(100, Math.max(0, (updates.y / canvasRef.current.offsetHeight) * 100));
                        const newFontSize = Math.max(8, updates.height / 1.5);
                        setSettings(s => ({ ...s, text: { ...s.text, position: 'custom', posX: px, posY: py, rotation: updates.rotation, fontSize: newFontSize } }));
                      }
                    }}
                  >
                    <div style={{
                      color: settings.text.color,
                      opacity: settings.text.opacity / 100,
                      fontFamily: settings.text.fontFamily,
                      fontSize: `${settings.text.fontSize}px`,
                      fontWeight: settings.text.bold ? 'bold' : 'normal',
                      fontStyle: settings.text.italic ? 'italic' : 'normal',
                      backgroundColor: settings.text.bgColor !== 'transparent' ? settings.text.bgColor : undefined,
                      padding: '4px 8px',
                      whiteSpace: 'nowrap',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: '100%',
                      height: '100%'
                    }}>
                      {settings.text.content}
                    </div>
                  </TransformableOverlay>
                )}

                {/* Logo Overlay */}
                {logoImg && settings.logo.url && canvasRef.current && (
                  <TransformableOverlay
                    isActive={activeTool === 'logo'}
                    onSelect={() => {}}
                    zoom={zoom}
                    x={getOverlayCoords(
                      settings.logo.position,
                      settings.logo.posX,
                      settings.logo.posY,
                      (settings.logo.size / 100) * canvasRef.current.offsetWidth,
                      ((settings.logo.size / 100) * canvasRef.current.offsetWidth) * (logoImg.naturalHeight / logoImg.naturalWidth)
                    ).x}
                    y={getOverlayCoords(
                      settings.logo.position,
                      settings.logo.posX,
                      settings.logo.posY,
                      (settings.logo.size / 100) * canvasRef.current.offsetWidth,
                      ((settings.logo.size / 100) * canvasRef.current.offsetWidth) * (logoImg.naturalHeight / logoImg.naturalWidth)
                    ).y}
                    width={(settings.logo.size / 100) * canvasRef.current.offsetWidth}
                    height={((settings.logo.size / 100) * canvasRef.current.offsetWidth) * (logoImg.naturalHeight / logoImg.naturalWidth)}
                    rotation={settings.logo.rotation}
                    lockAspect={settings.logo.lockAspect}
                    onChange={(updates) => {
                      if (canvasRef.current) {
                        const px = Math.min(100, Math.max(0, (updates.x / canvasRef.current.offsetWidth) * 100));
                        const py = Math.min(100, Math.max(0, (updates.y / canvasRef.current.offsetHeight) * 100));
                        const size = Math.min(100, Math.max(5, (updates.width / canvasRef.current.offsetWidth) * 100));
                        setSettings(s => ({ ...s, logo: { ...s.logo, position: 'custom', posX: px, posY: py, rotation: updates.rotation, size } }));
                      }
                    }}
                  >
                    <img 
                      src={settings.logo.url} 
                      alt="Logo" 
                      style={{ 
                        opacity: settings.logo.opacity / 100, 
                        width: '100%', 
                        height: '100%', 
                        objectFit: 'contain'
                      }} 
                    />
                  </TransformableOverlay>
                )}

                {/* Watermark Overlay */}
                {settings.watermark.text.trim() !== '' && !settings.watermark.repeat && canvasRef.current && (
                  <TransformableOverlay
                    isActive={activeTool === 'watermark'}
                    onSelect={() => {}}
                    zoom={zoom}
                    x={getOverlayCoords(
                      settings.watermark.position,
                      settings.watermark.posX,
                      settings.watermark.posY,
                      settings.watermark.fontSize * 5,
                      settings.watermark.fontSize * 1.5
                    ).x}
                    y={getOverlayCoords(
                      settings.watermark.position,
                      settings.watermark.posX,
                      settings.watermark.posY,
                      settings.watermark.fontSize * 5,
                      settings.watermark.fontSize * 1.5
                    ).y}
                    width={settings.watermark.fontSize * 5}
                    height={settings.watermark.fontSize * 1.5}
                    rotation={settings.watermark.rotation}
                    lockAspect={false}
                    onChange={(updates) => {
                      if (canvasRef.current) {
                        const px = Math.min(100, Math.max(0, (updates.x / canvasRef.current.offsetWidth) * 100));
                        const py = Math.min(100, Math.max(0, (updates.y / canvasRef.current.offsetHeight) * 100));
                        const newFontSize = Math.max(8, updates.height / 1.5);
                        setSettings(s => ({ ...s, watermark: { ...s.watermark, position: 'custom', posX: px, posY: py, rotation: updates.rotation, fontSize: newFontSize } }));
                      }
                    }}
                  >
                    <div style={{
                      color: settings.watermark.color,
                      opacity: settings.watermark.opacity / 100,
                      fontFamily: settings.watermark.fontFamily,
                      fontSize: `${settings.watermark.fontSize}px`,
                      whiteSpace: 'nowrap',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: '100%',
                      height: '100%'
                    }}>
                      {settings.watermark.text}
                    </div>
                  </TransformableOverlay>
                )}
              </EditorCanvas>
            )}
            
            {/* Privacy Message */}
            <p className="text-[10px] font-sans text-slate text-center mt-3">
              🔒 Your image is edited locally in your browser. Nothing is uploaded to any server.
            </p>
          </div>

          {/* Bottom: Settings Panel & Download */}
          <div className="bg-surface border border-border rounded-xl p-6 flex flex-col gap-4">
            
            <div className="flex justify-between items-center pb-4 border-b border-border">
              <h3 className="font-display font-bold text-ink text-xl">{tool.name}</h3>
              <div className="flex gap-2">
                <Button variant="outline" size="sm" onClick={handleReset} title="Reset adjustments">
                  <RotateCcw className="w-4 h-4 mr-1.5" /> Reset
                </Button>
                <Button variant="outline" size="sm" onClick={handleClear} title="Load different image">
                  <ImageIcon className="w-4 h-4 mr-1.5" /> New Image
                </Button>
              </div>
            </div>

            <div className="mb-2">
              <EditorSettingsPanel
                activeTool={activeTool}
                settings={settings}
                onChangeSettings={(s) => setSettings(s)}
                originalWidth={imageState.width}
                originalHeight={imageState.height}
                logoFile={logoFile}
                onLogoUpload={handleLogoUpload}
                onLogoRemove={handleLogoRemove}
                logoError={logoError}
                setLogoError={setLogoError}
              />
            </div>
            
            <div className="pt-4 border-t border-border">
              <DownloadImageButton
                defaultFileName={`edited_${imageState.file.name}`}
                onDownload={handleDownload}
                isProcessing={isProcessing}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { ToolLayout } from '../shared/ToolLayout';
import { TextBox } from '../shared/TextBox';
import { ResultBox } from '../shared/ResultBox';
import { Button } from '@/components/ui/Button';
import { getSeoContent } from './seoContent';

interface SeoToolContainerProps {
  toolId: string;
  toolName: string;
  toolDescription: string;
}

export function SeoToolContainer({ toolId, toolName, toolDescription }: SeoToolContainerProps) {
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [error, setError] = useState('');

  // Form states for Keyword Density Checker
  const [keywordInput, setKeywordInput] = useState('');
  const [keywordDensityTotalWords, setKeywordDensityTotalWords] = useState(0);

  // Form states for Meta Tag Generator
  const [metaTitle, setMetaTitle] = useState('');
  const [metaDescription, setMetaDescription] = useState('');
  const [metaKeywords, setMetaKeywords] = useState('');
  const [metaAuthor, setMetaAuthor] = useState('');
  const [metaPageUrl, setMetaPageUrl] = useState('');
  const [metaImageUrl, setMetaImageUrl] = useState('');
  const [metaSiteName, setMetaSiteName] = useState('');
  const [metaPageType, setMetaPageType] = useState('website');
  const [metaRobotsIndex, setMetaRobotsIndex] = useState('index');
  const [metaRobotsFollow, setMetaRobotsFollow] = useState('follow');
  const [metaLanguage, setMetaLanguage] = useState('English');
  const [metaCharset, setMetaCharset] = useState('UTF-8');

  // Form states for Robots.txt Generator
  const [robotsUserAgent, setRobotsUserAgent] = useState('*');
  const [robotsCrawlDelay, setRobotsCrawlDelay] = useState('none');
  const [robotsSitemapUrl, setRobotsSitemapUrl] = useState('');
  const [robotsDisallowed, setRobotsDisallowed] = useState('/admin\n/cgi-bin\n/temp');

  // Form states for Sitemap Generator
  const [sitemapBaseUrl, setSitemapBaseUrl] = useState('https://example.com');
  const [sitemapPaths, setSitemapPaths] = useState('/\n/about\n/contact\n/blog');
  const [sitemapFreq, setSitemapFreq] = useState('weekly');
  const [sitemapPriority, setSitemapPriority] = useState('0.8');

  // Form states for Open Graph
  const [ogTitle, setOgTitle] = useState('');
  const [ogDescription, setOgDescription] = useState('');
  const [ogUrl, setOgUrl] = useState('');
  const [ogType, setOgType] = useState('website');
  const [ogImage, setOgImage] = useState('');
  const [ogSiteName, setOgSiteName] = useState('');

  // Form states for Twitter Card
  const [twitterTitle, setTwitterTitle] = useState('');
  const [twitterDescription, setTwitterDescription] = useState('');
  const [twitterImage, setTwitterImage] = useState('');
  const [twitterCard, setTwitterCard] = useState('summary_large_image');
  const [twitterSite, setTwitterSite] = useState('');

  // Analysis result states
  const [keywordDensity, setKeywordDensity] = useState<{ word: string; count: number; density: string }[]>([]);
  const [seoWordStats, setSeoWordStats] = useState<{
    words: number;
    chars: number;
    paragraphs: number;
    sentences: number;
    readTime: number;
    speakTime: number;
    seoEvaluation: string;
    seoEvaluationColor: string;
  } | null>(null);

  const [headingTree, setHeadingTree] = useState<{ tag: string; text: string; level: number; error?: string }[]>([]);
  const [headingIssues, setHeadingIssues] = useState<string[]>([]);

  // Reset all states when switching/re-entering tools
  useEffect(() => {
    setInput('');
    setOutput('');
    setError('');
    setKeywordInput('');
    setKeywordDensityTotalWords(0);
    setMetaTitle('');
    setMetaDescription('');
    setMetaKeywords('');
    setMetaAuthor('');
    setMetaPageUrl('');
    setMetaImageUrl('');
    setMetaSiteName('');
    setMetaPageType('website');
    setMetaRobotsIndex('index');
    setMetaRobotsFollow('follow');
    setMetaLanguage('English');
    setMetaCharset('UTF-8');
    setRobotsUserAgent('*');
    setRobotsCrawlDelay('none');
    setRobotsSitemapUrl('');
    setRobotsDisallowed('/admin\n/cgi-bin\n/temp');
    setSitemapBaseUrl('https://example.com');
    setSitemapPaths('/\n/about\n/contact\n/blog');
    setSitemapFreq('weekly');
    setSitemapPriority('0.8');
    setOgTitle('');
    setOgDescription('');
    setOgUrl('');
    setOgType('website');
    setOgImage('');
    setOgSiteName('');
    setTwitterTitle('');
    setTwitterDescription('');
    setTwitterImage('');
    setTwitterCard('summary_large_image');
    setTwitterSite('');
    setKeywordDensity([]);
    setSeoWordStats(null);
    setHeadingTree([]);
    setHeadingIssues([]);
  }, [toolId]);

  // Automatically compute values as user interacts
  useEffect(() => {
    setError('');

    if (toolId === 'meta-title-checker') {
      const length = input.length;
      let evaluation = '';
      if (length === 0) {
        setOutput('');
        return;
      }
      if (length < 30) {
        evaluation = `Length: ${length} characters. Too short. (Recommended: 50-60 characters)`;
      } else if (length > 60) {
        evaluation = `Length: ${length} characters. Too long. Search engines may truncate it. (Recommended: 50-60 characters)`;
      } else {
        evaluation = `Length: ${length} characters. Perfect! (Recommended: 50-60 characters)`;
      }
      setOutput(evaluation);
    } else if (toolId === 'meta-description-checker') {
      const length = input.length;
      let evaluation = '';
      if (length === 0) {
        setOutput('');
        return;
      }
      if (length < 120) {
        evaluation = `Length: ${length} characters. Too short. (Recommended: 150-160 characters)`;
      } else if (length > 160) {
        evaluation = `Length: ${length} characters. Too long. Search engines may truncate it. (Recommended: 150-160 characters)`;
      } else {
        evaluation = `Length: ${length} characters. Perfect! (Recommended: 150-160 characters)`;
      }
      setOutput(evaluation);
    } else if (toolId === 'seo-slug-generator') {
      if (!input) {
        setOutput('');
        return;
      }
      const slug = input
        .toLowerCase()
        .replace(/[^\w\s-]/g, '') // remove special characters
        .trim()
        .replace(/\s+/g, '-') // replace spaces with hyphens
        .replace(/-+/g, '-'); // replace duplicate hyphens
      setOutput(slug);
    } else if (toolId === 'seo-keyword-density') {
      if (!input.trim()) {
        setKeywordDensity([]);
        setOutput('');
        return;
      }
      if (!keywordInput.trim()) {
        setKeywordDensity([]);
        setOutput('');
        setError('Keyword is required to calculate density.');
        return;
      }

      // Count raw words in text (excluding punctuation except inside words, like hyphens)
      const rawWords = input
        .toLowerCase()
        .replace(/[^\w\s-]/g, ' ')
        .split(/\s+/)
        .filter(Boolean);
      const rawWordCount = rawWords.length;

      // Clean keyword
      const cleanKeyword = keywordInput.trim().toLowerCase();
      const kwWords = cleanKeyword.split(/\s+/).filter(Boolean);
      const keywordWordCount = kwWords.length;

      if (keywordWordCount === 0 || rawWordCount === 0) {
        setKeywordDensity([]);
        setOutput('');
        return;
      }

      // Construct Regex for matching keyword exactly with word boundaries
      const escapedWords = kwWords.map(w => w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
      const regexStr = '\\b' + escapedWords.join('\\s+') + '\\b';
      let occurrences = 0;
      try {
        const regex = new RegExp(regexStr, 'gi');
        const matches = input.match(regex);
        occurrences = matches ? matches.length : 0;
      } catch (e) {
        occurrences = 0;
      }

      // adjustedTotalWords = rawWordCount - (keywordWordCount - 1) * occurrences
      const adjustedTotalWords = Math.max(1, rawWordCount - (keywordWordCount - 1) * occurrences);
      const densityVal = ((occurrences / adjustedTotalWords) * 100).toFixed(2);
      const densityStr = densityVal + '%';

      setKeywordDensity([{
        word: keywordInput.trim(),
        count: occurrences,
        density: densityStr
      }]);
      setKeywordDensityTotalWords(adjustedTotalWords);

      setOutput(`Keyword: ${keywordInput.trim()}\nOccurrences: ${occurrences}\nTotal words: ${adjustedTotalWords}\nDensity: ${densityStr}`);
    } else if (toolId === 'seo-word-count') {
      if (!input.trim()) {
        setSeoWordStats(null);
        return;
      }
      const words = input.trim().split(/\s+/).filter(w => w.length > 0).length;
      const chars = input.length;
      const paragraphs = input.split(/\n+/).filter(p => p.trim().length > 0).length;
      const sentences = input.split(/[.!?]+/).filter(s => s.trim().length > 0).length;
      const readTime = Math.ceil(words / 200); // 200 wpm
      const speakTime = Math.ceil(words / 130); // 130 wpm

      let evaluation = '';
      let color = '';
      if (words < 300) {
        evaluation = 'Thin content. Below 300 words. Search engines prefer more detailed, informative text for article indexation.';
        color = 'text-red-500 bg-red-500/10 border-red-500/20';
      } else if (words < 600) {
        evaluation = 'Short content. Good for brief announcements or product pages, but might struggle to rank for competitive keywords.';
        color = 'text-yellow-500 bg-yellow-500/10 border-yellow-500/20';
      } else if (words <= 1200) {
        evaluation = 'Standard article depth. Great size for blog posts and standard SEO content. Easy to read and cover key queries.';
        color = 'text-green-500 bg-green-500/10 border-green-500/20';
      } else {
        evaluation = 'Excellent high-depth content! Ideal for pillar pages, ultimate guides, and high-authority search queries.';
        color = 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20';
      }

      setSeoWordStats({
        words,
        chars,
        paragraphs,
        sentences,
        readTime,
        speakTime,
        seoEvaluation: evaluation,
        seoEvaluationColor: color
      });
    } else if (toolId === 'heading-structure-checker') {
      if (!input.trim()) {
        setHeadingTree([]);
        setHeadingIssues([]);
        setOutput('');
        return;
      }
      try {
        const parser = new DOMParser();
        const doc = parser.parseFromString(input, 'text/html');
        const headings = doc.querySelectorAll('h1, h2, h3, h4, h5, h6');
        const parsedTree: { tag: string; text: string; level: number; error?: string }[] = [];
        const issues: string[] = [];
        const counts = { h1: 0, h2: 0, h3: 0, h4: 0, h5: 0, h6: 0 };

        const headingList = Array.from(headings).map((node, index) => {
          const tag = node.tagName.toLowerCase();
          const level = parseInt(tag.substring(1));
          const text = (node.textContent || '').trim();
          
          if (tag in counts) {
            counts[tag as keyof typeof counts]++;
          }

          return { node, tag, level, text, index };
        });

        // 1. Missing H1
        if (counts.h1 === 0) {
          issues.push('Missing H1 heading: A page should contain exactly one H1 tag defining its primary topic.');
          issues.push('- Suggestion: Add an H1 heading at the beginning of your HTML content.');
        }
        // 2. Multiple H1 tags
        if (counts.h1 > 1) {
          issues.push(`Multiple H1 headings detected (${counts.h1}): Standard SEO recommends a single primary H1 heading per page.`);
          issues.push('- Suggestion: Change subsequent H1 headings to H2 or H3 headings.');
        }
        // 3. First heading is not H1
        if (headingList.length > 0 && headingList[0].level !== 1) {
          issues.push(`First heading is not H1: The heading structure starts with H${headingList[0].level} ("${headingList[0].text || '(Empty Heading)'}").`);
          issues.push(`- Suggestion: Change "${headingList[0].text || 'the first heading'}" to H1 to establish proper hierarchy.`);
        }

        let lastLevel = 0;
        let lastHeadingText = '';
        let correctedLastLevel = 0;
        const correctedHeadings: { text: string; level: number }[] = [];

        headingList.forEach((h, index) => {
          let errMessage = '';
          const tagUpper = h.tag.toUpperCase();

          // 4. Empty heading text
          if (!h.text) {
            issues.push(`Empty heading text: The H${h.level} heading at position ${index + 1} has no text content.`);
            issues.push(`- Suggestion: Add descriptive text inside the empty H${h.level} heading tag.`);
            errMessage = `Empty H${h.level} heading.`;
          }

          // Corrected level logic
          let correctedLevel = h.level;
          if (index === 0) {
            if (h.level > 1) {
              correctedLevel = 1;
            }
          } else {
            // 5. Heading level skipped (jumps deeper by > 1 level, e.g. H2 to H4)
            if (lastLevel > 0 && h.level - lastLevel > 1) {
              errMessage = `Skipped heading level. Jumped from H${lastLevel} directly to H${h.level}.`;
              issues.push(`Heading level skipped: H${lastLevel} to H${h.level}.`);
              
              const parentInfo = lastHeadingText ? ` because it comes under "${lastHeadingText}"` : '';
              issues.push(`"${h.text || '(Empty Heading)'}" should probably be H${lastLevel + 1}${parentInfo}.`);
              
              correctedLevel = correctedLastLevel + 1;
            }
          }

          parsedTree.push({
            tag: tagUpper,
            text: h.text || '(Empty Heading Text)',
            level: h.level,
            error: errMessage
          });

          correctedHeadings.push({
            text: h.text || '(Empty Heading Text)',
            level: correctedLevel
          });

          lastLevel = h.level;
          lastHeadingText = h.text;
          correctedLastLevel = correctedLevel;
        });

        setHeadingTree(parsedTree);
        setHeadingIssues(issues);

        // Build output report text
        let outputReport = '';
        if (issues.length > 0) {
          outputReport += 'SEO Issues Found:\n' + issues.map(iss => `- ${iss}`).join('\n');
        } else {
          outputReport += 'SEO Issues Found:\n- No issues found. Heading structure is correct!';
        }

        outputReport += '\n\nHeading Map:\n';
        headingList.forEach((item, idx) => {
          // Use corrected level to compute indent spaces, but keep original tag
          const correctedLevel = correctedHeadings[idx].level;
          const indent = '  '.repeat(correctedLevel - 1);
          outputReport += `${indent}${item.tag.toUpperCase()} ${item.text || '(Empty Heading Text)'}\n`;
        });

        outputReport += '\nSuggested fixed HTML:\n';
        correctedHeadings.forEach(h => {
          outputReport += `<h${h.level}>${h.text}</h${h.level}>\n`;
        });

        setOutput(outputReport.trim());
      } catch (err: any) {
        setError('Failed to parse pasted HTML. Make sure it is valid HTML markup.');
      }
    }
  }, [input, keywordInput, toolId]);

  // Handler for generating Meta Tags
  const generateMetaTags = () => {
    if (!metaTitle.trim()) {
      setError('Page Title is required.');
      return;
    }
    setError('');

    let tags = '';
    
    // Basic Meta Tags
    tags += `<title>${metaTitle}</title>\n`;
    if (metaDescription) {
      tags += `<meta name="description" content="${metaDescription}">\n`;
    }
    if (metaKeywords) {
      tags += `<meta name="keywords" content="${metaKeywords}">\n`;
    }
    if (metaAuthor) {
      tags += `<meta name="author" content="${metaAuthor}">\n`;
    }
    if (metaPageUrl) {
      tags += `<link rel="canonical" href="${metaPageUrl}">\n`;
    }
    
    tags += `\n`;

    // Open Graph Tags
    tags += `<meta property="og:title" content="${metaTitle}">\n`;
    if (metaDescription) {
      tags += `<meta property="og:description" content="${metaDescription}">\n`;
    }
    if (metaPageUrl) {
      tags += `<meta property="og:url" content="${metaPageUrl}">\n`;
    }
    if (metaImageUrl) {
      tags += `<meta property="og:image" content="${metaImageUrl}">\n`;
    }
    if (metaSiteName) {
      tags += `<meta property="og:site_name" content="${metaSiteName}">\n`;
    }
    if (metaPageType) {
      tags += `<meta property="og:type" content="${metaPageType}">\n`;
    }
    
    tags += `\n`;

    // Twitter Card Tags
    tags += `<meta name="twitter:card" content="summary_large_image">\n`;
    tags += `<meta name="twitter:title" content="${metaTitle}">\n`;
    if (metaDescription) {
      tags += `<meta name="twitter:description" content="${metaDescription}">\n`;
    }
    if (metaImageUrl) {
      tags += `<meta name="twitter:image" content="${metaImageUrl}">\n`;
    }

    setOutput(tags.trim());
  };

  const clearMetaTagsForm = () => {
    setMetaTitle('');
    setMetaDescription('');
    setMetaKeywords('');
    setMetaAuthor('');
    setMetaPageUrl('');
    setMetaImageUrl('');
    setMetaSiteName('');
    setMetaPageType('website');
    setOutput('');
    setError('');
  };

  // Handler for generating Robots.txt
  const generateRobotsTxt = () => {
    let content = `User-agent: ${robotsUserAgent}\n`;
    if (robotsCrawlDelay !== 'none') {
      content += `Crawl-delay: ${robotsCrawlDelay}\n`;
    }
    const disallowedList = robotsDisallowed.split('\n').map(p => p.trim()).filter(p => p.length > 0);
    disallowedList.forEach(path => {
      content += `Disallow: ${path}\n`;
    });

    if (robotsSitemapUrl) {
      content += `Sitemap: ${robotsSitemapUrl}\n`;
    }
    setOutput(content);
  };

  // Handler for generating Sitemap
  const generateSitemap = () => {
    let xml = `<?xml version="1.0" encoding="UTF-8"?>\n`;
    xml += `<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n`;

    const paths = sitemapPaths.split('\n').map(p => p.trim()).filter(p => p.length > 0);
    const dateStr = new Date().toISOString().split('T')[0];

    paths.forEach(p => {
      // Ensure slash structure
      const relative = p.startsWith('/') ? p : '/' + p;
      const fullUrl = sitemapBaseUrl.replace(/\/$/, '') + relative;
      xml += `  <url>\n`;
      xml += `    <loc>${fullUrl}</loc>\n`;
      xml += `    <lastmod>${dateStr}</lastmod>\n`;
      xml += `    <changefreq>${sitemapFreq}</changefreq>\n`;
      xml += `    <priority>${sitemapPriority}</priority>\n`;
      xml += `  </url>\n`;
    });

    xml += `</urlset>`;
    setOutput(xml);
  };

  // Handler for generating Open Graph tags
  const generateOgTags = () => {
    let og = `<!-- Open Graph / Facebook -->\n`;
    og += `<meta property="og:type" content="${ogType}">\n`;
    if (ogUrl) og += `<meta property="og:url" content="${ogUrl}">\n`;
    if (ogTitle) og += `<meta property="og:title" content="${ogTitle}">\n`;
    if (ogDescription) og += `<meta property="og:description" content="${ogDescription}">\n`;
    if (ogImage) og += `<meta property="og:image" content="${ogImage}">\n`;
    if (ogSiteName) og += `<meta property="og:site_name" content="${ogSiteName}">\n`;
    setOutput(og);
  };

  // Handler for generating Twitter cards tags
  const generateTwitterTags = () => {
    let tw = `<!-- Twitter Card -->\n`;
    tw += `<meta name="twitter:card" content="${twitterCard}">\n`;
    if (twitterSite) tw += `<meta name="twitter:site" content="${twitterSite}">\n`;
    if (twitterTitle) tw += `<meta name="twitter:title" content="${twitterTitle}">\n`;
    if (twitterDescription) tw += `<meta name="twitter:description" content="${twitterDescription}">\n`;
    if (twitterImage) tw += `<meta name="twitter:image" content="${twitterImage}">\n`;
    setOutput(tw);
  };

  // Form rendering helpers
  const renderGeneratorForm = () => {
    switch (toolId) {
      case 'meta-tag-generator':
        return (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl">
            <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Meta Tag Configuration</h3>
            {error && (
              <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-red-500 text-xs font-sans">
                {error}
              </div>
            )}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Page Title</label>
                <input
                  type="text"
                  value={metaTitle}
                  onChange={(e) => setMetaTitle(e.target.value)}
                  placeholder="e.g. Free Developer Tools"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Author</label>
                <input
                  type="text"
                  value={metaAuthor}
                  onChange={(e) => setMetaAuthor(e.target.value)}
                  placeholder="e.g. Sampath Kumar"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Page Description</label>
                <textarea
                  value={metaDescription}
                  onChange={(e) => setMetaDescription(e.target.value)}
                  placeholder="e.g. Format JSON, validate XML, encode Base64, decode URLs, test regex, format SQL, and beautify code."
                  rows={2}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80 resize-none"
                />
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Keywords</label>
                <input
                  type="text"
                  value={metaKeywords}
                  onChange={(e) => setMetaKeywords(e.target.value)}
                  placeholder="e.g. developer tools, json formatter, sql formatter, base64 encoder"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Page URL</label>
                <input
                  type="text"
                  value={metaPageUrl}
                  onChange={(e) => setMetaPageUrl(e.target.value)}
                  placeholder="e.g. https://example.com/developer-tools"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Image URL</label>
                <input
                  type="text"
                  value={metaImageUrl}
                  onChange={(e) => setMetaImageUrl(e.target.value)}
                  placeholder="e.g. https://example.com/images/developer-tools-og.png"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Site Name</label>
                <input
                  type="text"
                  value={metaSiteName}
                  onChange={(e) => setMetaSiteName(e.target.value)}
                  placeholder="e.g. Example Tools"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Page Type</label>
                <input
                  type="text"
                  value={metaPageType}
                  onChange={(e) => setMetaPageType(e.target.value)}
                  placeholder="e.g. website"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
            </div>
            <div className="flex justify-end gap-3 pt-2">
              <Button variant="secondary" onClick={clearMetaTagsForm}>Clear Form</Button>
              <Button variant="primary" onClick={generateMetaTags}>Generate Meta Tags</Button>
            </div>
          </div>
        );
      case 'robots-txt-generator':
        return (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl">
            <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Robots.txt Configuration</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">User Agent</label>
                <input
                  type="text"
                  value={robotsUserAgent}
                  onChange={(e) => setRobotsUserAgent(e.target.value)}
                  placeholder="e.g. *"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Crawl Delay</label>
                <select
                  value={robotsCrawlDelay}
                  onChange={(e) => setRobotsCrawlDelay(e.target.value)}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none"
                >
                  <option value="none">No Delay</option>
                  <option value="5">5 seconds</option>
                  <option value="10">10 seconds</option>
                </select>
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Sitemap XML URL (Optional)</label>
                <input
                  type="text"
                  value={robotsSitemapUrl}
                  onChange={(e) => setRobotsSitemapUrl(e.target.value)}
                  placeholder="e.g. https://example.com/sitemap.xml"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Disallowed Directory Paths (one per line)</label>
                <textarea
                  value={robotsDisallowed}
                  onChange={(e) => setRobotsDisallowed(e.target.value)}
                  placeholder="e.g. /admin"
                  rows={3}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink font-mono text-sm outline-none focus:border-primary/80"
                />
              </div>
            </div>
            <div className="flex justify-end pt-2">
              <Button variant="primary" onClick={generateRobotsTxt}>Generate Robots.txt</Button>
            </div>
          </div>
        );
      case 'sitemap-xml-generator':
        return (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl">
            <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Sitemap XML Configuration</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Website Base URL</label>
                <input
                  type="text"
                  value={sitemapBaseUrl}
                  onChange={(e) => setSitemapBaseUrl(e.target.value)}
                  placeholder="e.g. https://example.com"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Change Frequency</label>
                <select
                  value={sitemapFreq}
                  onChange={(e) => setSitemapFreq(e.target.value)}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none"
                >
                  <option value="always">Always</option>
                  <option value="hourly">Hourly</option>
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                  <option value="monthly">Monthly</option>
                  <option value="yearly">Yearly</option>
                  <option value="never">Never</option>
                </select>
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Default Priority</label>
                <select
                  value={sitemapPriority}
                  onChange={(e) => setSitemapPriority(e.target.value)}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none"
                >
                  <option value="1.0">1.0 (Highest)</option>
                  <option value="0.8">0.8</option>
                  <option value="0.5">0.5 (Average)</option>
                  <option value="0.3">0.3</option>
                  <option value="0.1">0.1 (Lowest)</option>
                </select>
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Relative URLs to Include (one per line)</label>
                <textarea
                  value={sitemapPaths}
                  onChange={(e) => setSitemapPaths(e.target.value)}
                  placeholder="e.g. /"
                  rows={4}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink font-mono text-sm outline-none focus:border-primary/80"
                />
              </div>
            </div>
            <div className="flex justify-end pt-2">
              <Button variant="primary" onClick={generateSitemap}>Generate XML Sitemap</Button>
            </div>
          </div>
        );
      case 'open-graph-generator':
        return (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl">
            <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Open Graph Tag Configuration</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Page Title</label>
                <input
                  type="text"
                  value={ogTitle}
                  onChange={(e) => setOgTitle(e.target.value)}
                  placeholder="e.g. Home - My Website"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Site Name</label>
                <input
                  type="text"
                  value={ogSiteName}
                  onChange={(e) => setOgSiteName(e.target.value)}
                  placeholder="e.g. Singulariti"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Page Description</label>
                <textarea
                  value={ogDescription}
                  onChange={(e) => setOgDescription(e.target.value)}
                  placeholder="e.g. Short summary description about the content."
                  rows={2}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80 resize-none"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Page URL</label>
                <input
                  type="text"
                  value={ogUrl}
                  onChange={(e) => setOgUrl(e.target.value)}
                  placeholder="e.g. https://example.com/page"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Object Type</label>
                <select
                  value={ogType}
                  onChange={(e) => setOgType(e.target.value)}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none"
                >
                  <option value="website">Website</option>
                  <option value="article">Article</option>
                  <option value="book">Book</option>
                  <option value="profile">Profile</option>
                </select>
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Image Banner URL (Absolute Path)</label>
                <input
                  type="text"
                  value={ogImage}
                  onChange={(e) => setOgImage(e.target.value)}
                  placeholder="e.g. https://example.com/assets/og-image.jpg"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
            </div>
            <div className="flex justify-end pt-2">
              <Button variant="primary" onClick={generateOgTags}>Generate OG Tags</Button>
            </div>
          </div>
        );
      case 'twitter-card-generator':
        return (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl">
            <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Twitter Card Configuration</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Card Title</label>
                <input
                  type="text"
                  value={twitterTitle}
                  onChange={(e) => setTwitterTitle(e.target.value)}
                  placeholder="e.g. Home - My Website"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Twitter Handle (username with @)</label>
                <input
                  type="text"
                  value={twitterSite}
                  onChange={(e) => setTwitterSite(e.target.value)}
                  placeholder="e.g. @singulariti"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Card Description</label>
                <textarea
                  value={twitterDescription}
                  onChange={(e) => setTwitterDescription(e.target.value)}
                  placeholder="e.g. Short summary description about the content."
                  rows={2}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80 resize-none"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label className="text-[12px] font-sans font-bold text-slate">Card Template Type</label>
                <select
                  value={twitterCard}
                  onChange={(e) => setTwitterCard(e.target.value)}
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none"
                >
                  <option value="summary_large_image">Summary Card with Large Image</option>
                  <option value="summary">Summary Card (Standard)</option>
                  <option value="app">Application Card</option>
                </select>
              </div>
              <div className="flex flex-col gap-1.5 md:col-span-2">
                <label className="text-[12px] font-sans font-bold text-slate">Banner Image URL</label>
                <input
                  type="text"
                  value={twitterImage}
                  onChange={(e) => setTwitterImage(e.target.value)}
                  placeholder="e.g. https://example.com/assets/og-image.jpg"
                  className="p-2.5 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
            </div>
            <div className="flex justify-end pt-2">
              <Button variant="primary" onClick={generateTwitterTags}>Generate Twitter Card</Button>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const isFormBasedTool = [
    'meta-tag-generator',
    'robots-txt-generator',
    'sitemap-xml-generator',
    'open-graph-generator',
    'twitter-card-generator'
  ].includes(toolId);

  const content = getSeoContent(toolId);

  return (
    <ToolLayout
      utilityId={toolId}
      title={toolName}
      description={toolDescription}
      categoryName="SEO Tools"
      categoryPath="/tools/seo"
      howToUse={content.howToUse}
      faqs={content.faqs}
    >
      <div className="space-y-6">
        {/* If Form-based, render form then output */}
        {isFormBasedTool && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
            {renderGeneratorForm()}
            <ResultBox value={output} downloadFileName={`${toolId}.txt`} label="Generated XML / HTML Tags" rows={18} />
          </div>
        )}

        {/* If Text-based, render text inputs and evaluations */}
        {!isFormBasedTool && (
          <div className="space-y-6">
            <TextBox
              value={input}
              onChange={setInput}
              label={
                toolId === 'heading-structure-checker'
                  ? 'Pasted HTML Source Code'
                  : 'Source Text for SEO Analysis'
              }
              error={error}
              placeholder={
                toolId === 'heading-structure-checker'
                  ? 'Paste raw page HTML here...'
                  : 'Paste your blog content or document description text here...'
              }
            />

            {/* Keyword Density Checker: Target Keyword Input */}
            {toolId === 'seo-keyword-density' && (
              <div className="flex flex-col gap-1.5 p-5 bg-background border border-border rounded-xl">
                <div className="flex items-center justify-between">
                  <label className="text-[13px] font-sans font-bold text-ink uppercase tracking-wider">Target Keyword</label>
                  {keywordInput && (
                    <button
                      onClick={() => setKeywordInput('')}
                      className="text-[12px] font-sans font-medium text-red-500 hover:text-red-600 transition-colors"
                    >
                      Clear Keyword
                    </button>
                  )}
                </div>
                <input
                  type="text"
                  value={keywordInput}
                  onChange={(e) => setKeywordInput(e.target.value)}
                  placeholder="Enter keyword or phrase separately..."
                  className="w-full p-3 border border-border rounded-lg bg-surface text-ink text-sm outline-none focus:border-primary/80"
                />
              </div>
            )}

            {/* Clear All Button for Keyword Density and Heading Checker */}
            {toolId === 'seo-keyword-density' && (input || keywordInput) && (
              <div className="flex justify-end">
                <Button variant="secondary" onClick={() => { setInput(''); setKeywordInput(''); setOutput(''); setError(''); setKeywordDensity([]); }}>
                  Clear All Fields
                </Button>
              </div>
            )}

            {toolId === 'heading-structure-checker' && input && (
              <div className="flex justify-end">
                <Button variant="secondary" onClick={() => { setInput(''); setOutput(''); setError(''); setHeadingTree([]); setHeadingIssues([]); }}>
                  Clear Content
                </Button>
              </div>
            )}

            {/* Title & Description Evaluators */}
            {(toolId === 'meta-title-checker' || toolId === 'meta-description-checker') && output && (
              <div className="p-5 border border-border bg-background rounded-xl flex flex-col justify-center gap-1.5">
                <span className="text-[12px] font-sans font-bold text-slate uppercase tracking-wider">SEO Evaluation</span>
                <p className="font-mono text-[15px] font-semibold text-primary">{output}</p>
                {/* Visual bar */}
                <div className="w-full bg-border h-2 rounded-full overflow-hidden mt-2">
                  <div
                    className={`h-full rounded-full transition-all duration-300 ${
                      input.length >= (toolId === 'meta-title-checker' ? 50 : 120) &&
                      input.length <= (toolId === 'meta-title-checker' ? 60 : 160)
                        ? 'bg-emerald-500'
                        : 'bg-yellow-500'
                    }`}
                    style={{
                      width: `${Math.min(
                        100,
                        (input.length / (toolId === 'meta-title-checker' ? 60 : 160)) * 100
                      )}%`
                    }}
                  />
                </div>
              </div>
            )}

            {/* Keyword Density Results */}
            {toolId === 'seo-keyword-density' && output && keywordDensity.length > 0 && (
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
                <div className="space-y-4 p-5 border border-border bg-background rounded-xl">
                  <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider mb-2">Keyword Density Analysis</h3>
                  <div className="space-y-3 font-sans text-sm text-slate">
                    <div className="flex justify-between border-b border-border/50 pb-2">
                      <span className="font-semibold text-ink">Keyword:</span>
                      <span className="font-mono text-primary font-bold">{keywordDensity[0]?.word}</span>
                    </div>
                    <div className="flex justify-between border-b border-border/50 pb-2">
                      <span className="font-semibold text-ink">Occurrences:</span>
                      <span className="font-mono text-primary font-bold">{keywordDensity[0]?.count}</span>
                    </div>
                    <div className="flex justify-between border-b border-border/50 pb-2">
                      <span className="font-semibold text-ink">Total words:</span>
                      <span className="font-mono text-primary font-bold">{keywordDensityTotalWords}</span>
                    </div>
                    <div className="flex justify-between pb-2">
                      <span className="font-semibold text-ink">Density:</span>
                      <span className="font-mono text-primary font-bold">{keywordDensity[0]?.density}</span>
                    </div>
                  </div>
                </div>
                <ResultBox value={output} downloadFileName="keyword-density-report.txt" label="Density Output Report" rows={10} />
              </div>
            )}

            {/* SEO Word Stats */}
            {toolId === 'seo-word-count' && seoWordStats && (
              <div className="space-y-5">
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                  {[
                    { label: 'Words', val: seoWordStats.words },
                    { label: 'Characters', val: seoWordStats.chars },
                    { label: 'Sentences', val: seoWordStats.sentences },
                    { label: 'Paragraphs', val: seoWordStats.paragraphs }
                  ].map((stat, i) => (
                    <div key={i} className="p-4 border border-border bg-background rounded-xl text-center">
                      <span className="text-[11px] font-sans font-bold text-slate uppercase tracking-wider">{stat.label}</span>
                      <p className="text-2xl font-mono font-bold text-primary mt-1">{stat.val}</p>
                    </div>
                  ))}
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div className="p-4 border border-border bg-background rounded-xl">
                    <span className="text-[11px] font-sans font-bold text-slate uppercase tracking-wider">Reading Time</span>
                    <p className="text-[15px] font-sans text-ink mt-1 font-semibold">
                      ~ <span className="font-mono text-primary text-lg">{seoWordStats.readTime}</span> minutes
                    </p>
                  </div>
                  <div className="p-4 border border-border bg-background rounded-xl">
                    <span className="text-[11px] font-sans font-bold text-slate uppercase tracking-wider">Speaking Time</span>
                    <p className="text-[15px] font-sans text-ink mt-1 font-semibold">
                      ~ <span className="font-mono text-primary text-lg">{seoWordStats.speakTime}</span> minutes
                    </p>
                  </div>
                </div>
                <div className={`p-4 border rounded-xl font-sans text-sm ${seoWordStats.seoEvaluationColor}`}>
                  <span className="font-bold uppercase tracking-wider text-[11px] block mb-1">SEO Readability Recommendation</span>
                  {seoWordStats.seoEvaluation}
                </div>
              </div>
            )}

            {/* Headings Structure Tree & Output */}
            {toolId === 'heading-structure-checker' && output && headingTree.length > 0 && (
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
                <div className="space-y-5">
                  {headingIssues.length > 0 && (
                    <div className="p-4 border border-red-500/20 bg-red-500/5 text-red-500 rounded-xl font-sans text-sm space-y-2">
                      <span className="font-bold uppercase tracking-wider text-[11px] block">SEO Issues Found</span>
                      <ul className="list-disc pl-5 space-y-1.5 text-xs">
                        {headingIssues.map((issue, idx) => (
                          <li key={idx}>{issue}</li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {headingIssues.length === 0 && (
                    <div className="p-4 border border-emerald-500/20 bg-emerald-500/5 text-emerald-500 rounded-xl font-sans text-sm">
                      <span className="font-bold uppercase tracking-wider text-[11px] block">Heading Check Passed</span>
                      No heading hierarchy or syntax issues detected. Structure is ideal for indexing.
                    </div>
                  )}
                  <div className="p-5 border border-border bg-background rounded-xl space-y-4">
                    <h3 className="text-sm font-sans font-bold text-ink uppercase tracking-wider">Heading Hierarchy Map</h3>
                    <div className="space-y-2.5 font-mono text-[13px] border-l-2 border-border/80 pl-3 ml-2">
                      {headingTree.map((item, idx) => {
                        const paddingMap = [0, 0, 4, 8, 12, 16, 20];
                        const indent = paddingMap[item.level] || 0;
                        return (
                          <div
                            key={idx}
                            style={{ paddingLeft: `${indent * 4}px` }}
                            className="flex flex-col gap-1 py-1"
                          >
                            <div className="flex items-center gap-2">
                              <span className={`px-2 py-0.5 rounded text-[11px] font-bold text-white ${
                                item.level === 1 ? 'bg-primary' : 'bg-slate/75'
                              }`}>
                                {item.tag}
                              </span>
                              <span className="text-ink font-sans">{item.text}</span>
                            </div>
                            {item.error && (
                              <span className="text-[11px] text-red-500 font-sans block mt-0.5">
                                ⚠️ {item.error}
                              </span>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
                <ResultBox value={output} downloadFileName="heading-structure-report.txt" label="Diagnostic Output & Suggestions" rows={18} />
              </div>
            )}

            {/* Standard Outputs */}
            {toolId === 'seo-slug-generator' && (
              <ResultBox value={output} downloadFileName="clean-slug.txt" label="URL Slug Result" />
            )}
          </div>
        )}
      </div>
    </ToolLayout>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Terminal, Trash2, Copy, X, ChevronUp, ChevronDown } from 'lucide-react';

interface LogMessage {
  id: string;
  type: 'log' | 'info' | 'warn' | 'error';
  content: string;
  timestamp: number;
}

interface ConsoleOverlayProps {
  logs: LogMessage[];
  onClear: () => void;
}

export function ConsoleOverlay({ logs, onClear }: ConsoleOverlayProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (!isOpen && logs.length > 0) {
      setUnreadCount(prev => prev + 1);
    }
  }, [logs]);

  useEffect(() => {
    if (isOpen) {
      setUnreadCount(0);
    }
  }, [isOpen]);

  const handleCopy = () => {
    const text = logs.map(l => `[${l.type.toUpperCase()}] ${l.content}`).join('\n');
    navigator.clipboard.writeText(text);
  };

  const getLogColor = (type: string) => {
    switch(type) {
      case 'error': return 'text-red-500 bg-red-500/10 border-red-500/20';
      case 'warn': return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
      case 'info': return 'text-blue-500 bg-blue-500/10 border-blue-500/20';
      default: return 'text-ink bg-transparent border-transparent';
    }
  };

  return (
    <div className={`absolute bottom-0 left-0 right-0 transition-all duration-300 ease-in-out bg-surface border-t border-border z-40 flex flex-col ${isOpen ? 'h-64' : 'h-10'}`}>
      {/* Header / Toggle */}
      <div 
        className="flex items-center justify-between px-4 h-10 cursor-pointer hover:bg-slate/5 transition-colors shrink-0"
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-2">
          <Terminal className="w-4 h-4 text-slate" />
          <span className="text-[13px] font-sans font-bold text-ink tracking-wide">Console</span>
          {!isOpen && unreadCount > 0 && (
            <span className="bg-primary text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">
              {unreadCount}
            </span>
          )}
        </div>
        <div className="flex items-center gap-1">
          {isOpen && (
            <>
              <button 
                onClick={(e) => { e.stopPropagation(); handleCopy(); }}
                className="p-1.5 text-slate hover:text-ink transition-colors rounded-md hover:bg-slate/10"
                title="Copy Console Output"
              >
                <Copy className="w-3.5 h-3.5" />
              </button>
              <button 
                onClick={(e) => { e.stopPropagation(); onClear(); }}
                className="p-1.5 text-slate hover:text-red-500 transition-colors rounded-md hover:bg-red-500/10"
                title="Clear Console"
              >
                <Trash2 className="w-3.5 h-3.5" />
              </button>
            </>
          )}
          <button className="p-1.5 text-slate">
            {isOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
          </button>
        </div>
      </div>

      {/* Logs Area */}
      {isOpen && (
        <div className="flex-1 overflow-y-auto bg-background p-2 font-mono text-[12px] space-y-1">
          {logs.length === 0 ? (
            <div className="flex items-center justify-center h-full text-slate/50 italic">
              Console output will appear here...
            </div>
          ) : (
            logs.map((log) => (
              <div 
                key={log.id} 
                className={`px-3 py-1.5 rounded border-l-2 ${getLogColor(log.type)} whitespace-pre-wrap break-words`}
              >
                {log.content}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect } from 'react';
import { DeviceView } from '@/store/useCompilerStore';
import { Monitor, Tablet, Smartphone, RotateCcw, Maximize } from 'lucide-react';

interface DevicePreviewFrameProps {
  srcDoc: string;
  deviceView: DeviceView;
  setDeviceView: (view: DeviceView) => void;
  runKey?: number;
}

export function DevicePreviewFrame({ srcDoc, deviceView, setDeviceView, runKey }: DevicePreviewFrameProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scale, setScale] = useState(1);
  const [isRotated, setIsRotated] = useState(false);

  const DEVICE_WIDTHS = {
    desktop: 1440,
    tablet: 768,
    mobile: 390,
  };

  const DEVICE_HEIGHTS = {
    desktop: 900,
    tablet: 1024,
    mobile: 844,
  };

  useEffect(() => {
    const handleResize = () => {
      if (deviceView === 'responsive' || !containerRef.current) {
        setScale(1);
        return;
      }

      const containerWidth = containerRef.current.clientWidth - 32; // 32px padding
      const containerHeight = containerRef.current.clientHeight - 32;
      
      const targetWidth = isRotated ? DEVICE_HEIGHTS[deviceView as keyof typeof DEVICE_HEIGHTS] : DEVICE_WIDTHS[deviceView as keyof typeof DEVICE_WIDTHS];
      const targetHeight = isRotated ? DEVICE_WIDTHS[deviceView as keyof typeof DEVICE_WIDTHS] : DEVICE_HEIGHTS[deviceView as keyof typeof DEVICE_HEIGHTS];

      const scaleX = containerWidth / targetWidth;
      const scaleY = containerHeight / targetHeight;
      
      // Calculate fit scale (min of X and Y, capped at 1 so it doesn't zoom in, only shrinks)
      const fitScale = Math.min(scaleX, scaleY, 1);
      setScale(fitScale);
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [deviceView, isRotated]);

  const getIframeDimensions = () => {
    if (deviceView === 'responsive') {
      return { width: '100%', height: '100%' };
    }
    const w = DEVICE_WIDTHS[deviceView as keyof typeof DEVICE_WIDTHS];
    const h = DEVICE_HEIGHTS[deviceView as keyof typeof DEVICE_HEIGHTS];
    return {
      width: isRotated ? h : w,
      height: isRotated ? w : h,
    };
  };

  const dims = getIframeDimensions();

  return (
    <div className="flex flex-col w-full h-full bg-slate/5 overflow-hidden">
      {/* Device Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 border-b border-border bg-surface">
        <div className="flex items-center gap-1 bg-background p-1 rounded-lg border border-border">
          <button
            onClick={() => setDeviceView('responsive')}
            className={`p-1.5 rounded-md text-[12px] font-medium transition-colors ${deviceView === 'responsive' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
            title="Responsive"
          >
            <Maximize className="w-4 h-4" />
          </button>
          <button
            onClick={() => setDeviceView('desktop')}
            className={`p-1.5 rounded-md text-[12px] font-medium transition-colors ${deviceView === 'desktop' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
            title="Desktop (1440px)"
          >
            <Monitor className="w-4 h-4" />
          </button>
          <button
            onClick={() => setDeviceView('tablet')}
            className={`p-1.5 rounded-md text-[12px] font-medium transition-colors ${deviceView === 'tablet' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
            title="Tablet (768px)"
          >
            <Tablet className="w-4 h-4" />
          </button>
          <button
            onClick={() => setDeviceView('mobile')}
            className={`p-1.5 rounded-md text-[12px] font-medium transition-colors ${deviceView === 'mobile' ? 'bg-primary text-white' : 'text-slate hover:bg-slate/10'}`}
            title="Mobile (390px)"
          >
            <Smartphone className="w-4 h-4" />
          </button>
        </div>

        {deviceView !== 'responsive' && (
          <div className="flex items-center gap-4 text-[12px] font-mono text-slate">
            <span>{typeof dims.width === 'number' ? `${dims.width} × ${dims.height}` : 'Responsive'}</span>
            <span className="text-slate/50">|</span>
            <span>{(scale * 100).toFixed(0)}%</span>
            
            <button
              onClick={() => setIsRotated(!isRotated)}
              className="p-1.5 text-ink hover:bg-slate/10 rounded-md transition-colors border border-border bg-background"
              title="Rotate Device"
            >
              <RotateCcw className="w-4 h-4" />
            </button>
          </div>
        )}
      </div>

      {/* Preview Area */}
      <div 
        ref={containerRef}
        className="flex-1 w-full h-full relative overflow-hidden flex items-center justify-center bg-[#e5e7eb] dark:bg-[#111827]"
      >
        <div 
          className="bg-white shadow-2xl overflow-hidden"
          style={{
            width: dims.width,
            height: dims.height,
            transform: deviceView !== 'responsive' ? `scale(${scale})` : 'none',
            transformOrigin: 'center center',
            transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
            borderRadius: deviceView !== 'responsive' ? '12px' : '0px',
            border: deviceView !== 'responsive' ? '4px solid #1f2937' : 'none',
          }}
        >
          <iframe
            key={`${srcDoc}-${runKey || 0}`}
            srcDoc={srcDoc}
            title="Preview Frame"
            className="w-full h-full border-none bg-white block"
            sandbox="allow-scripts allow-modals"
          />
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useRef, useEffect } from 'react';
import Editor, { useMonaco, loader } from '@monaco-editor/react';
import { useTheme } from 'next-themes';



interface MonacoEditorWrapperProps {
  language: 'html' | 'css' | 'javascript';
  value: string;
  onChange: (value: string | undefined) => void;
  readOnly?: boolean;
}

export function MonacoEditorWrapper({ language, value, onChange, readOnly = false }: MonacoEditorWrapperProps) {
  const { theme, systemTheme } = useTheme();
  const monaco = useMonaco();
  const editorRef = useRef<any>(null);

  const activeTheme = theme === 'system' ? systemTheme : theme;
  const monacoTheme = activeTheme === 'dark' ? 'vs-dark' : 'light';

  useEffect(() => {
    if (monaco) {
      // Register custom theme or rules if needed
      monaco.editor.defineTheme('singulariti-dark', {
        base: 'vs-dark',
        inherit: true,
        rules: [],
        colors: {
          'editor.background': '#0f172a', // Tailwind slate-900
        }
      });
      monaco.editor.defineTheme('singulariti-light', {
        base: 'vs',
        inherit: true,
        rules: [],
        colors: {
          'editor.background': '#ffffff',
        }
      });
      monaco.editor.setTheme(activeTheme === 'dark' ? 'singulariti-dark' : 'singulariti-light');
    }
  }, [monaco, activeTheme]);

  const handleEditorDidMount = (editor: any, monaco: any) => {
    editorRef.current = editor;
  };

  return (
    <div className="w-full h-full relative">
      <Editor
        height="100%"
        width="100%"
        language={language}
        value={value}
        onChange={onChange}
        onMount={handleEditorDidMount}
        theme={activeTheme === 'dark' ? 'singulariti-dark' : 'singulariti-light'}
        options={{
          minimap: { enabled: false },
          fontSize: 14,
          fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', Consolas, monospace",
          wordWrap: 'on',
          automaticLayout: true,
          readOnly,
          scrollBeyondLastLine: false,
          smoothScrolling: true,
          cursorBlinking: 'smooth',
          cursorSmoothCaretAnimation: 'on',
          formatOnPaste: true,
          padding: { top: 16, bottom: 16 },
          autoClosingBrackets: 'always',
          autoClosingQuotes: 'always',
          formatOnType: true,
        }}
        loading={<div className="flex w-full h-full items-center justify-center text-slate text-sm">Loading Editor...</div>}
      />
    </div>
  );
}

"use client";

import React, { useState } from 'react';
import Link from 'next/link';
