        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify({
            "@context": "https://schema.org",
            "@type": "HowTo",
            "name": `How to use ${title}`,
            "description": description,
            "step": howToUse.map((step, index) => ({
              "@type": "HowToStep",
              "position": index + 1,
              "text": step
