      <Header />
      <main className="flex-1 w-full flex flex-col items-center pt-20 pb-12 bg-background">
        {/* Breadcrumbs */}
        <div className="container mx-auto px-4 max-w-6xl mb-6">
          <nav className="flex items-center text-[13px] font-sans text-slate">
            <Link href="/" className="hover:text-primary transition-colors">Home</Link>
            <span className="mx-2">/</span>
            <Link href="/tools" className="hover:text-primary transition-colors">Tools</Link>
            <span className="mx-2">/</span>
            <Link href={categoryPath} className="hover:text-primary transition-colors">{categoryName}</Link>
            <span className="mx-2">/</span>
            <span className="text-ink font-medium">{title}</span>
          </nav>
        </div>

        {/* Hero Area */}
        <section className="container mx-auto px-4 max-w-3xl text-center mb-6">
          <h1 className="font-display font-bold text-3xl md:text-4xl text-ink mb-3 tracking-tight">
            {title}
          </h1>
          <p className="font-sans text-base text-slate leading-relaxed">
            {description}
          </p>
        </section>

        {/* Privacy Lock Banner */}
        <section className="container mx-auto px-4 max-w-6xl mb-6 w-full">
          <div className="flex items-center gap-3 bg-primary/5 border border-primary/10 rounded-xl p-3 text-primary max-w-3xl mx-auto">
            <ShieldCheck className="w-4.5 h-4.5 flex-shrink-0" />
            <p className="text-[12px] font-sans font-medium leading-relaxed">
              {privacyLabel || (() => {
                const cat = (categoryName || '').toLowerCase();
                if (cat.includes('pdf')) {
                  return "PDFs are processed only for the selected action. No files are uploaded to our server.";
                }
                if (cat.includes('image') || cat.includes('editing')) {
                  return "Images are processed locally in your browser. Nothing is uploaded to any server.";
                }
                if (cat.includes('text')) {
                  return "Text is processed temporarily and not stored. No files are uploaded to our server.";
                }
                return "Your inputs are processed locally in your browser. Nothing is uploaded to any server.";
              })()}
            </p>
          </div>
        </section>

        {/* Active Tool Area */}
        <section className="container mx-auto px-4 max-w-6xl mb-12 w-full">
          <div className="bg-surface border border-border rounded-2xl p-6 md:p-8 shadow-sm">
            {children}
          </div>
        </section>

        {/* Details & FAQ Area */}
        <section className="container mx-auto px-4 max-w-4xl mt-6 space-y-12">
          {/* How to Use */}
          {howToUse && howToUse.length > 0 && (
            <div className="bg-surface/50 border border-border/60 rounded-2xl p-6 md:p-8">
              <h2 className="font-display font-bold text-xl text-ink mb-6">How to Use</h2>
              <ol className="space-y-4">
                {howToUse.map((step, i) => (
                  <li key={i} className="flex gap-4 font-sans text-sm text-slate">
                    <span className="flex-shrink-0 flex items-center justify-center w-6 h-6 rounded-full bg-primary/10 text-primary font-bold text-xs">
                      {i + 1}
                    </span>
                    <span className="pt-0.5">{step}</span>
                  </li>
                ))}
              </ol>
            </div>
          )}

          {/* FAQs */}
          {faqs && faqs.length > 0 && (
            <div className="space-y-4">
              <h2 className="font-display font-bold text-xl text-ink mb-6 text-center">Frequently Asked Questions</h2>
              <div className="space-y-3">
                {faqs.map((faq, i) => (
                  <div key={i} className="border border-border bg-surface rounded-xl overflow-hidden transition-colors">
                    <button
                      onClick={() => toggleFaq(i)}
                      className="w-full flex items-center justify-between p-5 text-left font-display font-bold text-[15px] text-ink hover:text-primary transition-colors focus:outline-none"
                    >
                      <span>{faq.question}</span>
                      {openFaq === i ? (
                        <ChevronUp className="w-4 h-4 text-slate flex-shrink-0" />
                      ) : (
                        <ChevronDown className="w-4 h-4 text-slate flex-shrink-0" />
                      )}
                    </button>
                    {openFaq === i && (
                      <div className="px-5 pb-5 pt-0 text-sm font-sans text-slate leading-relaxed border-t border-border/50 animate-in fade-in duration-200">
                        {faq.answer}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}
        </section>
        {/* Related Tools Cross-linking */}
        {relatedTools && relatedTools.length > 0 && (
          <section className="container mx-auto px-4 max-w-6xl mt-12 mb-6 w-full">
            <h2 className="font-display font-bold text-2xl text-ink mb-6 text-center">Related Tools</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {relatedTools.map((tool, i) => (
                <Link key={i} href={tool.url} className="group block bg-surface border border-border rounded-xl p-5 hover:border-primary/50 hover:shadow-sm transition-all duration-300">
                  <h3 className="font-display font-bold text-[17px] text-ink group-hover:text-primary transition-colors mb-2">{tool.name}</h3>
                  <p className="font-sans text-[14px] text-slate leading-relaxed">{tool.description}</p>
                </Link>
              ))}
            </div>
          </section>
        )}
      </main>
      <Footer />
    </>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { ToolLayout } from '../shared/ToolLayout';
import { TextBox } from '../shared/TextBox';
import { ResultBox } from '../shared/ResultBox';
import { Button } from '@/components/ui/Button';
import { diffLines, diffWords, diffChars } from 'diff';
import { getTextContent } from './textContent';

interface TextToolContainerProps {
  toolId: string;
  toolName: string;
  toolDescription: string;
}

export function TextToolContainer({ toolId, toolName, toolDescription }: TextToolContainerProps) {
  const [input, setInput] = useState('');
  const [input2, setInput2] = useState(''); // Used for compare/diff
  const [output, setOutput] = useState('');
  const [error, setError] = useState('');
  
  // Custom states for generators
  const [count, setCount] = useState(3); // e.g. paragraphs count
  const [stringLength, setStringLength] = useState(12); // random string length
  const [findStr, setFindStr] = useState('');
  const [replaceStr, setReplaceStr] = useState('');

  // Custom states for Text Compare
  const [compareMode, setCompareMode] = useState<'line' | 'word' | 'char'>('line');
  const [compareSummary, setCompareSummary] = useState<{
    chars1: number;
    chars2: number;
    words1: number;
    words2: number;
    lines1: number;
    lines2: number;
    changedLines: number;
    addedLines: number;
    removedLines: number;
    similarity: number;
  } | null>(null);

  // Clear compare summaries when input changes
  useEffect(() => {
    if (toolId === 'text-compare') {
      setCompareSummary(null);
    }
  }, [input, input2, toolId]);

  // Reset all states when switching/re-entering tools
  useEffect(() => {
    setInput('');
    setInput2('');
    setOutput('');
    setError('');
    setCount(3);
    setStringLength(12);
    setFindStr('');
    setReplaceStr('');
    setCompareSummary(null);
    setCompareMode('line');
  }, [toolId]);

  // Auto-run logic for tools that process on-the-fly
  useEffect(() => {
    setError('');
    
    if (!input && toolId !== 'lorem-ipsum' && toolId !== 'random-text') {
      setOutput('');
      return;
    }

    try {
      switch (toolId) {
        case 'word-counter':
        case 'character-counter':
        case 'line-counter':
        case 'sentence-counter':
        case 'paragraph-counter': {
          const chars = input.length;
          const words = input.trim() === "" ? 0 : input.trim().split(/\s+/).length;
          const lines = input === "" ? 0 : input.split('\n').length;
          const sentences = input.trim() === "" ? 0 : input.split(/[.!?]+/).filter(Boolean).length;
          const paragraphs = input.trim() === "" ? 0 : input.split(/\n\s*\n/).filter(Boolean).length;

          if (toolId === 'word-counter') {
            setOutput(`Words: ${words}\nCharacters: ${chars}\nLines: ${lines}\nSentences: ${sentences}\nParagraphs: ${paragraphs}`);
          } else if (toolId === 'character-counter') {
            setOutput(`Characters (with spaces): ${chars}\nCharacters (no spaces): ${input.replace(/\s/g, '').length}`);
          } else if (toolId === 'line-counter') {
            setOutput(`Total Lines: ${lines}`);
          } else if (toolId === 'sentence-counter') {
            setOutput(`Total Sentences: ${sentences}`);
          } else if (toolId === 'paragraph-counter') {
            setOutput(`Total Paragraphs: ${paragraphs}`);
          }
          break;
        }
        case 'text-uppercase':
          setOutput(input.toUpperCase());
          break;
        case 'text-lowercase':
          setOutput(input.toLowerCase());
          break;
        case 'capitalize-text':
          setOutput(input.replace(/(^\s*|[.!?]\s+)([a-z])/g, m => m.toUpperCase()));
          break;
        case 'title-case':
          setOutput(input.replace(/\w\S*/g, txt => txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase()));
          break;
        case 'case-converter':
          setOutput(`UPPERCASE:\n${input.toUpperCase()}\n\nlowercase:\n${input.toLowerCase()}\n\nTitle Case:\n${input.replace(/\w\S*/g, txt => txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase())}`);
          break;
        case 'remove-duplicate-lines': {
          const lines = input.split('\n');
          const unique = Array.from(new Set(lines));
          setOutput(unique.join('\n'));
          break;
        }
        case 'text-sorter': {
          const lines = input.split('\n');
          setOutput(lines.sort((a, b) => a.localeCompare(b)).join('\n'));
          break;
        }
        case 'remove-extra-spaces':
          setOutput(input.replace(/[ \t]+/g, ' ').replace(/\n\s*\n/g, '\n\n').trim());
          break;
        case 'text-reverser':
          setOutput(input.split('').reverse().join(''));
          break;
        case 'slug-generator':
          setOutput(input.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, ''));
          break;
        default:
          break;
      }
    } catch (err: any) {
      setError(err.message || 'An error occurred during processing.');
    }
  }, [input, toolId]);

  // Execute logic for interactive tools (e.g. Find & Replace, Diff, Generators)
  const handleExecute = () => {
    setError('');
    try {
      if (toolId === 'find-replace') {
        if (!findStr) {
          setError('Please specify the text to find.');
          return;
        }
        setOutput(input.replaceAll(findStr, replaceStr));
      } else if (toolId === 'text-compare') {
        const chars1 = input.length;
        const chars2 = input2.length;
        const words1 = input.trim() === "" ? 0 : input.trim().split(/\s+/).length;
        const words2 = input2.trim() === "" ? 0 : input2.trim().split(/\s+/).length;
        const lines1 = input === "" ? 0 : input.split('\n').length;
        const lines2 = input2 === "" ? 0 : input2.split('\n').length;

        let changedLines = 0;
        let addedLines = 0;
        let removedLines = 0;

        const maxLines = Math.max(lines1, lines2);
        const l1List = input.split('\n');
        const l2List = input2.split('\n');

        for (let i = 0; i < maxLines; i++) {
          const l1 = l1List[i];
          const l2 = l2List[i];
          if (l1 !== undefined && l2 !== undefined && l1 !== l2) {
            changedLines++;
          } else if (l1 !== undefined && l2 === undefined) {
            removedLines++;
          } else if (l1 === undefined && l2 !== undefined) {
            addedLines++;
          }
        }

        // Calculate similarity percentage using diffChars
        const diffCh = diffChars(input, input2);
        let sameChars = 0;
        diffCh.forEach(part => {
          if (!part.added && !part.removed) {
            sameChars += part.value.length;
          }
        });
        const maxLen = Math.max(chars1, chars2);
        const similarity = maxLen === 0 ? 100 : Math.round((sameChars / maxLen) * 100);

        setCompareSummary({
          chars1,
          chars2,
          words1,
          words2,
          lines1,
          lines2,
          changedLines,
          addedLines,
          removedLines,
          similarity
        });

        // Compute output text based on selected mode
        if (compareMode === 'line') {
          const report: string[] = [];
          report.push(`=== LINE COMPARE REPORT ===`);
          report.push(`Similarity: ${similarity}%`);
          report.push(`Changed Lines: ${changedLines}, Added: ${addedLines}, Removed: ${removedLines}\n`);
          
          for (let i = 0; i < maxLines; i++) {
            const l1 = l1List[i];
            const l2 = l2List[i];
            if (l1 === l2) {
              report.push(`Line ${i + 1} [SAME]: ${l1}`);
            } else if (l1 !== undefined && l2 !== undefined) {
              report.push(`Line ${i + 1} [CHANGED]:\n- ${l1}\n+ ${l2}`);
            } else if (l1 !== undefined) {
              report.push(`Line ${i + 1} [REMOVED]: - ${l1}`);
            } else if (l2 !== undefined) {
              report.push(`Line ${i + 1} [ADDED]: + ${l2}`);
            }
          }
          setOutput(report.join('\n'));
        } else if (compareMode === 'word') {
          const diffW = diffWords(input, input2);
          const report: string[] = [];
          diffW.forEach(part => {
            if (part.removed) {
              report.push(`[-${part.value}]`);
            } else if (part.added) {
              report.push(`[+${part.value}]`);
            } else {
              report.push(part.value);
            }
          });
          setOutput(report.join(''));
        } else if (compareMode === 'char') {
          const report: string[] = [];
          report.push(`=== CHARACTER COMPARE REPORT ===`);
          report.push(`Similarity: ${similarity}%\n`);

          let pos = 0;
          for (let idx = 0; idx < diffCh.length; idx++) {
            const current = diffCh[idx];
            const next = diffCh[idx + 1];
            
            if (current.removed && next && next.added) {
              const minLen = Math.min(current.value.length, next.value.length);
              for (let c = 0; c < minLen; c++) {
                report.push(`Position ${pos + c + 1}: Replaced '${current.value[c]}' with '${next.value[c]}'`);
              }
              if (current.value.length > minLen) {
                for (let c = minLen; c < current.value.length; c++) {
                  report.push(`Position ${pos + c + 1}: Removed '${current.value[c]}'`);
                }
              } else if (next.value.length > minLen) {
                for (let c = minLen; c < next.value.length; c++) {
                  report.push(`Position ${pos + minLen + 1}: Added '${next.value[c]}'`);
                }
              }
              pos += current.value.length;
              idx++;
            } else if (current.removed) {
              for (let c = 0; c < current.value.length; c++) {
                report.push(`Position ${pos + c + 1}: Removed '${current.value[c]}'`);
              }
              pos += current.value.length;
            } else if (current.added) {
              for (let c = 0; c < current.value.length; c++) {
                report.push(`Position ${pos + 1}: Added '${current.value[c]}'`);
              }
            } else {
              pos += current.value.length;
            }
          }
          if (report.length === 2) {
            report.push("No character-level differences found.");
          }
          setOutput(report.join('\n'));
        }
      } else if (toolId === 'text-diff') {
        const lines1 = input.split('\n');
        const lines2 = input2.split('\n');
        const diffResult: string[] = [];
        
        const maxLines = Math.max(lines1.length, lines2.length);
        for (let i = 0; i < maxLines; i++) {
          const l1 = lines1[i];
          const l2 = lines2[i];
          if (l1 === l2) {
            diffResult.push(`  ${l1}`);
          } else {
            if (l1 !== undefined) diffResult.push(`- ${l1}`);
            if (l2 !== undefined) diffResult.push(`+ ${l2}`);
          }
        }
        setOutput(diffResult.join('\n'));
      } else if (toolId === 'lorem-ipsum') {
        const loremParagraphs = [
          "Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur.",
          "Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum. Curabitur pretium tincidunt lacus. Nulla gravida orci a odio. Nullam varius, turpis et commodo pharetra, est eros bibendum elit, nec luctus magna felis sollicitudin mauris.",
          "Integer in mauris eu nibh euismod gravida. Duis ac tellus et risus vulputate vehicula. Donec lobortis risus a elit. Etiam tempor. Ut ullamcorper, ligula eu tempor congue, eros est euismod turpis, id tincidunt sapien risus a quam. Maecenas fermentum consequat mi. Donec fermentum. Pellentesque malesuada nulla a mi."
        ];
        const res = [];
        for (let i = 0; i < count; i++) {
          res.push(loremParagraphs[i % loremParagraphs.length]);
        }
        setOutput(res.join('\n\n'));
      } else if (toolId === 'random-text') {
        const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+";
        let res = "";
        for (let i = 0; i < stringLength; i++) {
          res += chars.charAt(Math.floor(Math.random() * chars.length));
        }
        setOutput(res);
      }
    } catch (err: any) {
      setError(err.message || 'Processing failed.');
    }
  };

  const needsSecondInput = toolId === 'text-compare' || toolId === 'text-diff';
  const isInteractive = needsSecondInput || toolId === 'find-replace' || toolId === 'lorem-ipsum' || toolId === 'random-text';

  const handleClearAll = () => {
    setInput('');
    setInput2('');
    setOutput('');
    setCompareSummary(null);
  };

  const content = getTextContent(toolId);

  return (
    <ToolLayout
      utilityId={toolId}
      title={toolName}
      description={toolDescription}
      categoryName="Text Tools"
      categoryPath="/tools/text"
      howToUse={content.howToUse}
      faqs={content.faqs}
    >
      <div className="space-y-6">
        {/* Generators Controls */}
        {loremIpsumControls()}
        {randomTextControls()}
        {findReplaceControls()}

        {/* Text Compare Mode Selection */}
        {toolId === 'text-compare' && (
          <div className="flex items-center justify-between p-4 bg-background rounded-xl border border-border flex-wrap gap-4">
            <div className="flex flex-col gap-1.5 font-sans">
              <label className="text-[12px] font-bold text-ink uppercase tracking-wider">Comparison Mode</label>
              <select 
                value={compareMode} 
                onChange={(e) => setCompareMode(e.target.value as any)}
                className="p-2 border border-border rounded-lg bg-surface text-ink text-sm outline-none w-48 focus:border-primary/80"
              >
                <option value="line">Line Compare</option>
                <option value="word">Word Compare</option>
                <option value="char">Character Compare</option>
              </select>
            </div>
            <Button variant="outline" onClick={handleClearAll}>Clear All Inputs</Button>
          </div>
        )}

        {/* Input Blocks */}
        {toolId !== 'lorem-ipsum' && toolId !== 'random-text' && (
          <div className={`grid grid-cols-1 ${needsSecondInput ? 'md:grid-cols-2' : ''} gap-6`}>
            <TextBox 
              value={input} 
              onChange={setInput} 
              label={needsSecondInput ? "Original Text (Version A)" : "Source Text Input"} 
              error={error} 
            />
            {needsSecondInput && (
              <TextBox 
                value={input2} 
                onChange={setInput2} 
                label="Updated Text (Version B)" 
              />
            )}
          </div>
        )}

        {/* Comparison Trigger */}
        {needsSecondInput && (
          <div className="flex justify-center">
            <Button variant="primary" onClick={handleExecute} className="px-6 py-2.5">
              {toolId === 'text-compare' ? 'Compare Texts' : 'Generate Diff'}
            </Button>
          </div>
        )}

        {/* Comparison Summary (Only for Text Compare) */}
        {toolId === 'text-compare' && compareSummary && (
          <div className="space-y-4 p-5 bg-background border border-border rounded-xl font-sans text-sm">
            <h3 className="text-sm font-bold text-ink uppercase tracking-wider">Comparison Summary</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4">
              <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <span className="text-[11px] font-bold text-slate uppercase block">Text 1 (A)</span>
                <p className="text-[13px] font-semibold text-ink mt-1 font-mono">
                  {compareSummary.lines1} L · {compareSummary.words1} W · {compareSummary.chars1} C
                </p>
              </div>
              <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <span className="text-[11px] font-bold text-slate uppercase block">Text 2 (B)</span>
                <p className="text-[13px] font-semibold text-ink mt-1 font-mono">
                  {compareSummary.lines2} L · {compareSummary.words2} W · {compareSummary.chars2} C
                </p>
              </div>
              <div className="p-3 bg-surface border border-border rounded-lg text-center">
                <span className="text-[11px] font-bold text-slate uppercase block">Line Differences</span>
                <p className="text-[13px] font-semibold text-ink mt-1 font-mono">
                  <span className="text-yellow-600">{compareSummary.changedLines} Chg</span> ·{' '}
                  <span className="text-emerald-600">+{compareSummary.addedLines} Add</span> ·{' '}
                  <span className="text-red-600">-{compareSummary.removedLines} Del</span>
                </p>
              </div>
              <div className="p-3 bg-surface border border-border rounded-lg text-center flex flex-col justify-center items-center">
                <span className="text-[11px] font-bold text-slate uppercase block">Similarity</span>
                <span className="text-base font-bold text-primary mt-0.5">{compareSummary.similarity}%</span>
              </div>
            </div>
          </div>
        )}

        {/* Visual Diff Panel (Only for Text Compare) */}
        {toolId === 'text-compare' && compareSummary && (
          <div className="p-5 bg-background border border-border rounded-xl space-y-3 font-sans">
            <h3 className="text-sm font-bold text-ink uppercase tracking-wider">Visual Difference Results</h3>
            
            {compareMode === 'line' && (
              <div className="space-y-1.5 font-mono text-[13px] border border-border p-4 rounded-lg bg-surface max-h-96 overflow-y-auto">
                {(() => {
                  const l1List = input.split('\n');
                  const l2List = input2.split('\n');
                  const maxLines = Math.max(l1List.length, l2List.length);
                  const elements = [];
                  for (let i = 0; i < maxLines; i++) {
                    const l1 = l1List[i];
                    const l2 = l2List[i];
                    if (l1 === l2) {
                      elements.push(
                        <div key={i} className="text-slate/80 py-0.5 border-b border-border/10">
                          <span className="inline-block w-8 text-slate/50 select-none text-[11px]">{i + 1}</span>
                          <span>{l1}</span>
                        </div>
                      );
                    } else if (l1 !== undefined && l2 !== undefined) {
                      elements.push(
                        <div key={i} className="py-1 border-b border-border/10 space-y-0.5">
                          <div className="bg-yellow-500/10 text-yellow-600 px-2 py-0.5 rounded border-l-4 border-yellow-500">
                            <span className="inline-block w-8 text-yellow-500/50 select-none text-[11px]">{i + 1} [CHANGED]</span>
                            <span className="line-through opacity-65 mr-2">{l1}</span>
                            <span className="font-bold">{l2}</span>
                          </div>
                        </div>
                      );
                    } else if (l1 !== undefined) {
                      elements.push(
                        <div key={i} className="bg-red-500/10 text-red-600 px-2 py-0.5 rounded border-l-4 border-red-500 border-b border-border/10">
                          <span className="inline-block w-8 text-red-500/50 select-none text-[11px]">{i + 1} [REMOVED]</span>
                          <span className="line-through">{l1}</span>
                        </div>
                      );
                    } else if (l2 !== undefined) {
                      elements.push(
                        <div key={i} className="bg-emerald-500/10 text-emerald-600 px-2 py-0.5 rounded border-l-4 border-emerald-500 border-b border-border/10">
                          <span className="inline-block w-8 text-emerald-500/50 select-none text-[11px]">{i + 1} [ADDED]</span>
                          <span className="font-bold">{l2}</span>
                        </div>
                      );
                    }
                  }
                  return elements;
                })()}
              </div>
            )}

            {compareMode === 'word' && (
              <div className="p-4 border border-border rounded-lg bg-surface max-h-96 overflow-y-auto font-mono text-[14px] leading-relaxed select-text">
                {(() => {
                  const diffW = diffWords(input, input2);
                  return diffW.map((part, idx) => {
                    if (part.removed) {
                      return (
                        <span key={idx} className="bg-red-500/15 text-red-600 line-through px-1 mx-0.5 rounded select-all font-semibold">
                          {part.value}
                        </span>
                      );
                    } else if (part.added) {
                      return (
                        <span key={idx} className="bg-emerald-500/15 text-emerald-600 px-1 mx-0.5 rounded font-bold select-all">
                          {part.value}
                        </span>
                      );
                    } else {
                      return <span key={idx} className="text-ink">{part.value}</span>;
                    }
                  });
                })()}
              </div>
            )}

            {compareMode === 'char' && (
              <div className="space-y-1.5 font-mono text-[12px] border border-border p-4 rounded-lg bg-surface max-h-72 overflow-y-auto text-slate">
                {(() => {
                  const diffCh = diffChars(input, input2);
                  const elements = [];
                  let pos = 0;
                  for (let idx = 0; idx < diffCh.length; idx++) {
                    const current = diffCh[idx];
                    const next = diffCh[idx + 1];
                    
                    if (current.removed && next && next.added) {
                      const minLen = Math.min(current.value.length, next.value.length);
                      for (let c = 0; c < minLen; c++) {
                        elements.push(
                          <div key={`${idx}-${c}`} className="py-0.5 border-b border-border/10 flex items-center gap-2">
                            <span className="text-yellow-600 font-bold bg-yellow-500/10 px-1 rounded text-[10px]">CHANGED</span>
                            <span>Pos {pos + c + 1}: Replaced <span className="line-through text-red-500">'{current.value[c]}'</span> with <span className="font-bold text-emerald-600">'{next.value[c]}'</span></span>
                          </div>
                        );
                      }
                      if (current.value.length > minLen) {
                        for (let c = minLen; c < current.value.length; c++) {
                          elements.push(
                            <div key={`${idx}-rem-${c}`} className="py-0.5 border-b border-border/10 flex items-center gap-2">
                              <span className="text-red-600 font-bold bg-red-500/10 px-1 rounded text-[10px]">REMOVED</span>
                              <span>Pos {pos + c + 1}: Removed <span className="line-through">'{current.value[c]}'</span></span>
                            </div>
                          );
                        }
                      } else if (next.value.length > minLen) {
                        for (let c = minLen; c < next.value.length; c++) {
                          elements.push(
                            <div key={`${idx}-add-${c}`} className="py-0.5 border-b border-border/10 flex items-center gap-2">
                              <span className="text-emerald-600 font-bold bg-emerald-500/10 px-1 rounded text-[10px]">ADDED</span>
                              <span>Pos {pos + minLen + 1}: Added <span className="font-bold">'{next.value[c]}'</span></span>
                            </div>
                          );
                        }
                      }
                      pos += current.value.length;
                      idx++;
                    } else if (current.removed) {
                      for (let c = 0; c < current.value.length; c++) {
                        elements.push(
                          <div key={`${idx}-${c}`} className="py-0.5 border-b border-border/10 flex items-center gap-2">
                            <span className="text-red-600 font-bold bg-red-500/10 px-1 rounded text-[10px]">REMOVED</span>
                            <span>Pos {pos + c + 1}: Removed <span className="line-through">'{current.value[c]}'</span></span>
                          </div>
                        );
                      }
                      pos += current.value.length;
                    } else if (current.added) {
                      for (let c = 0; c < current.value.length; c++) {
                        elements.push(
                          <div key={`${idx}-${c}`} className="py-0.5 border-b border-border/10 flex items-center gap-2">
                            <span className="text-emerald-600 font-bold bg-emerald-500/10 px-1 rounded text-[10px]">ADDED</span>
                            <span>Pos {pos + 1}: Added <span className="font-bold">'{current.value[c]}'</span></span>
                          </div>
                        );
                      }
                    } else {
                      pos += current.value.length;
                    }
                  }
                  if (elements.length === 0) {
                    return <div className="text-center py-4 text-slate">No character differences.</div>;
                  }
                  return elements;
                })()}
              </div>
            )}
          </div>
        )}

        {/* Result Block */}
        <ResultBox value={output} downloadFileName={`${toolId}-result.txt`} />
      </div>
    </ToolLayout>
  );

  // Helper renderers
  function loremIpsumControls() {
    if (toolId !== 'lorem-ipsum') return null;
    return (
      <div className="flex items-center gap-4 p-4 bg-background rounded-xl border border-border">
        <div className="flex flex-col gap-1.5 font-sans">
          <label className="text-[12px] font-bold text-ink">Paragraphs:</label>
          <input 
            type="number" 
            min="1" max="50" 
            value={count} 
            onChange={(e) => setCount(Math.max(1, Number(e.target.value)))}
            className="w-24 p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
          />
        </div>
        <Button variant="primary" onClick={handleExecute} className="mt-5">Generate Placeholder</Button>
      </div>
    );
  }

  function randomTextControls() {
    if (toolId !== 'random-text') return null;
    return (
      <div className="flex items-center gap-4 p-4 bg-background rounded-xl border border-border">
        <div className="flex flex-col gap-1.5 font-sans">
          <label className="text-[12px] font-bold text-ink">String Length:</label>
          <input 
            type="number" 
            min="4" max="128" 
            value={stringLength} 
            onChange={(e) => setStringLength(Math.max(4, Number(e.target.value)))}
            className="w-24 p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
          />
        </div>
        <Button variant="primary" onClick={handleExecute} className="mt-5">Generate String</Button>
      </div>
    );
  }

  function findReplaceControls() {
    if (toolId !== 'find-replace') return null;
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 bg-background rounded-xl border border-border">
        <div className="flex flex-col gap-1 font-sans">
          <label className="text-[12px] font-bold text-ink">Find Text:</label>
          <input 
            type="text" 
            value={findStr} 
            onChange={(e) => setFindStr(e.target.value)} 
            placeholder="Find text..." 
            className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
          />
        </div>
        <div className="flex flex-col gap-1 font-sans">
          <label className="text-[12px] font-bold text-ink">Replace With:</label>
          <input 
            type="text" 
            value={replaceStr} 
            onChange={(e) => setReplaceStr(e.target.value)} 
            placeholder="Replace text..." 
            className="p-2 border border-border rounded bg-surface text-ink text-sm outline-none" 
          />
        </div>
        <div className="md:col-span-2 flex justify-end">
          <Button variant="primary" onClick={handleExecute}>Replace All</Button>
        </div>
      </div>
    );
  }
}

"use client";

import React, { useState, useRef, useEffect } from 'react';
import { ShieldCheck, Info } from 'lucide-react';
import { ToolLayout } from '../ToolLayout';
import { WhiteboardCanvas, WhiteboardCanvasRef } from './WhiteboardCanvas';
import { WhiteboardToolbar } from './WhiteboardToolbar';
import { WhiteboardSidebar } from './WhiteboardSidebar';
import { WhiteboardExportPanel } from './WhiteboardExportPanel';
import {
  WhiteboardTool,
  BrushOptions,
  ShapeOptions,
  TextOptions,
  StickyNoteOptions,
  WhiteboardState
} from '@/lib/whiteboard/whiteboardTypes';
import { exportToImage, exportToPDF, exportToSVG } from '@/lib/whiteboard/exportHelpers';
import { saveBoardToStorage, loadBoardFromStorage, hasSavedBoard } from '@/lib/whiteboard/storageHelpers';

export default function OnlineWhiteboardClient() {
  const canvasRef = useRef<WhiteboardCanvasRef>(null);

  // Notifications
  const [error, setError] = useState<string | null>(null);
  const [warning, setWarning] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);

  // Storage status
  const [boardSavedExists, setBoardSavedExists] = useState(false);

  // Whiteboard configuration states
  const [activeTool, setActiveTool] = useState<WhiteboardTool>('select');
  const [zoom, setZoom] = useState(1.0);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  // New Custom whiteboard features
  const [isMaximized, setIsMaximized] = useState(false);
  const [gridType, setGridType] = useState<'none' | 'grid' | 'dots'>('none');
  const [canvasTheme, setCanvasTheme] = useState<'light' | 'dark'>('light');
  const [strokeDash, setStrokeDash] = useState<'solid' | 'dashed' | 'dotted'>('solid');


  // Tool setting state defaults
  const [brush, setBrush] = useState<BrushOptions>({
    color: '#000000',
    width: 5,
    opacity: 1.0
  });

  const [shape, setShape] = useState<ShapeOptions>({
    strokeColor: '#000000',
    fillColor: 'transparent',
    strokeWidth: 3,
    opacity: 1.0
  });

  const [text, setText] = useState<TextOptions>({
    fontFamily: 'Outfit',
    fontSize: 24,
    color: '#000000',
    bold: false,
    italic: false,
    underline: false,
    backgroundColor: 'transparent'
  });

  const [sticky, setSticky] = useState<StickyNoteOptions>({
    color: '#FEF08A', // Yellow bg
    text: '#854D0E'  // Dark brown text
  });

  // Selected active object properties (when user selects something on canvas)
  const [selectedObjectType, setSelectedObjectType] = useState<string | null>(null);
  const [selectedObjectProps, setSelectedObjectProps] = useState<any>(null);

  // Check storage status on mount
  useEffect(() => {
    setBoardSavedExists(hasSavedBoard());
  }, []);

  // Set alerts dismiss timer
  useEffect(() => {
    if (successMsg) {
      const timer = setTimeout(() => setSuccessMsg(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [successMsg]);

  // Escape key and native fullscreen exits maximized mode
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isMaximized) {
        setIsMaximized(false);
        if (document.fullscreenElement) {
          document.exitFullscreen().catch(() => {});
        }
      }
    };
    
    const handleFullscreenChange = () => {
      if (!document.fullscreenElement && isMaximized) {
        setIsMaximized(false);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, [isMaximized]);

  const handleToggleMaximize = () => {
    if (!isMaximized) {
      if (document.documentElement.requestFullscreen) {
        document.documentElement.requestFullscreen().catch(err => {
          console.warn(`Error attempting to enable full-screen mode: ${err.message}`);
        });
      }
      setIsMaximized(true);
    } else {
      if (document.fullscreenElement) {
        document.exitFullscreen().catch(err => {
          console.warn(`Error attempting to exit full-screen mode: ${err.message}`);
        });
      }
      setIsMaximized(false);
    }
  };

  // Spacebar panning shortcut
  const [previousTool, setPreviousTool] = useState<WhiteboardTool | null>(null);
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Don't trigger if user is typing in standard inputs or editing text inside Fabric
      if (
        document.activeElement?.tagName === 'INPUT' ||
        document.activeElement?.tagName === 'TEXTAREA' ||
        (document.activeElement as any)?.isContentEditable
      ) {
        return;
      }

      const canvas = canvasRef.current?.getCanvas();
      if (canvas && canvas.getActiveObject() && (canvas.getActiveObject() as any).isEditing) {
        return;
      }

      if (e.code === 'Space' && activeTool !== 'pan') {
        e.preventDefault();
        if (e.repeat) return; // avoid keydown repeat loop
        setPreviousTool(activeTool);
        setActiveTool('pan');
      }
    };

    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space' && previousTool !== null) {
        e.preventDefault();
        setActiveTool(previousTool);
        setPreviousTool(null);
      }
    };

    const handleBlur = () => {
      if (previousTool !== null) {
        setActiveTool(previousTool);
        setPreviousTool(null);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('blur', handleBlur);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('blur', handleBlur);
    };
  }, [activeTool, previousTool]);


  // Automatic brush/stroke color inversion based on blackboard theme
  useEffect(() => {
    const isDark = canvasTheme === 'dark';
    
    // Invert active brush color if default black/white is selected
    if (brush.color === '#000000' && isDark) {
      setBrush(prev => ({ ...prev, color: '#FFFFFF' }));
    } else if (brush.color === '#FFFFFF' && !isDark) {
      setBrush(prev => ({ ...prev, color: '#000000' }));
    }

    // Invert active shape stroke color if default black/white is selected
    if (shape.strokeColor === '#000000' && isDark) {
      setShape(prev => ({ ...prev, strokeColor: '#FFFFFF' }));
    } else if (shape.strokeColor === '#FFFFFF' && !isDark) {
      setShape(prev => ({ ...prev, strokeColor: '#000000' }));
    }

    // Invert active text color if default black/white is selected
    if (text.color === '#000000' && isDark) {
      setText(prev => ({ ...prev, color: '#FFFFFF' }));
    } else if (text.color === '#FFFFFF' && !isDark) {
      setText(prev => ({ ...prev, color: '#000000' }));
    }
  }, [canvasTheme]);


  // Handle Tool selection changes
  const handleSelectTool = (tool: WhiteboardTool) => {
    setActiveTool(tool);
    // Discard active object selection when changing tools to drawing modes
    if (tool !== 'select') {
      const canvas = canvasRef.current?.getCanvas();
      if (canvas) {
        canvas.discardActiveObject();
        canvas.requestRenderAll();
      }
    }
  };

  // Image insertion handler
  const handleImageUpload = (file: File) => {
    canvasRef.current?.uploadImage(file);
  };

  // Handle modifying a selected object
  const handleChangeSelectedObject = (newProps: any) => {
    const canvas = canvasRef.current?.getCanvas();
    if (!canvas) return;

    const activeObj = canvas.getActiveObject();
    if (!activeObj) return;

    // Check if there is an undo/redo modification trigger inside canvas.
    // To enable proper undo, we manually push current state before making properties changes
    // But we only want to do this if the value actually changes
    let changed = false;
    Object.keys(newProps).forEach(key => {
      if ((activeObj as any)[key] !== newProps[key]) {
        changed = true;
      }
    });

    if (changed) {
      // Direct update
      activeObj.set(newProps);
      activeObj.setCoords();
      canvas.requestRenderAll();

      // Update sidebar props state
      setSelectedObjectProps((prev: any) => ({
        ...prev,
        ...newProps
      }));
    }
  };

  // Delete selected object
  const handleDeleteSelected = () => {
    const canvas = canvasRef.current?.getCanvas();
    if (!canvas) return;

    const activeObj = canvas.getActiveObject();
    if (activeObj) {
      // Simulate delete key press
      const e = new KeyboardEvent('keydown', { key: 'Delete' });
      window.dispatchEvent(e);
    }
  };

  // Local storage save board trigger
  const handleSaveBoard = () => {
    const canvas = canvasRef.current?.getCanvas();
    if (!canvas) return;

    if (canvas.getObjects().length === 0) {
      setError("Cannot save an empty board.");
      return;
    }

    const res = saveBoardToStorage(canvas);
    if (res.success) {
      setSuccessMsg("Whiteboard saved successfully!");
      setBoardSavedExists(true);
      setError(null);
    } else {
      setError(res.error || "Failed to save board locally.");
    }
  };

  // Local storage load board trigger
  const handleLoadBoard = async () => {
    const canvas = canvasRef.current?.getCanvas();
    if (!canvas) return;

    try {
      const res = await loadBoardFromStorage(canvas);
      if (res.success) {
        setSuccessMsg("Whiteboard loaded successfully!");
        setError(null);
      } else {
        setError(res.error || "Failed to load saved board.");
      }
    } catch {
      setError("Failed to load saved board.");
    }
  };

  // Local storage clear saved board
  const handleClearSavedBoard = () => {
    // We already have onClearBoard to wipe the canvas.
    // The toolbar clear handles current board layout.
    // If the user wants to wipe localstorage, we can do it inside the component
    localStorage.removeItem('singularity_whiteboard_save');
    setBoardSavedExists(false);
    setSuccessMsg("Saved board cleared from browser storage.");
  };

  // Export board trigger
  const handleExport = (
    format: 'png' | 'jpg' | 'pdf' | 'svg',
    fileName: string,
    options: { quality: number; pdfOrientation: 'portrait' | 'landscape' }
  ) => {
    const canvas = canvasRef.current?.getCanvas();
    if (!canvas) return;

    try {
      setError(null);
      const exportBgColor = canvasTheme === 'dark' ? '#09090B' : '#FFFFFF';
      if (format === 'png') {
        exportToImage(canvas, 'png', 1, fileName, exportBgColor);
      } else if (format === 'jpg') {
        exportToImage(canvas, 'jpeg', options.quality, fileName, exportBgColor);
      } else if (format === 'pdf') {
        exportToPDF(canvas, options.pdfOrientation, fileName, exportBgColor);
      } else if (format === 'svg') {
        exportToSVG(canvas, fileName);
      }
      setSuccessMsg(`Exported successfully as ${format.toUpperCase()}!`);
    } catch (err: any) {
      if (err.message === 'EMPTY_BOARD') {
        setError("Cannot export an empty board. Please draw or add shapes first.");
      } else {
        setError("Failed to export board. Please try again.");
      }
    }
  };


  // Clear current canvas board
  const handleClearBoard = () => {
    canvasRef.current?.clearCanvas();
    setSuccessMsg("Canvas cleared.");
  };

  const content = (
    <div className={isMaximized 
      ? "fixed inset-0 z-[150] bg-slate-50 dark:bg-zinc-950 flex flex-col p-4 gap-4 w-[100dvw] h-[100dvh] overflow-hidden animate-in fade-in duration-200" 
      : "space-y-6 w-full max-w-7xl mx-auto"
    }>
      {/* Whiteboard Specific Privacy Notice (Required) */}
      {!isMaximized && (
        <div className="flex items-start gap-3 bg-primary/5 border border-primary/10 rounded-xl p-4 text-ink">
          <ShieldCheck className="w-5 h-5 flex-shrink-0 text-primary mt-0.5" />
          <div className="text-[13px] font-sans leading-relaxed">
            <span className="font-semibold text-primary">Privacy Guarantee:</span> Your whiteboard data is created and stored locally in your browser. Nothing is uploaded to any server.
          </div>
        </div>
      )}

      {/* Maximized View Header */}
      {isMaximized && (
        <div className="flex items-center justify-between border-b border-border dark:border-zinc-800 pb-2">
          <div>
            <h2 className="text-sm font-sans font-bold text-ink dark:text-zinc-100">Online Whiteboard (Maximized Workspace)</h2>
            <p className="text-[10px] text-slate dark:text-zinc-400 font-sans">Press <kbd className="bg-background dark:bg-zinc-800 px-1 border dark:border-zinc-700 rounded text-ink dark:text-zinc-300">ESC</kbd> or click the restore button to exit.</p>
          </div>
        </div>
      )}

      {/* Toolbar Component */}
      <WhiteboardToolbar
        activeTool={activeTool}
        onSelectTool={handleSelectTool}
        onImageUpload={handleImageUpload}
        onUndo={() => canvasRef.current?.undo()}
        onRedo={() => canvasRef.current?.redo()}
        canUndo={canUndo}
        canRedo={canRedo}
        zoom={zoom}
        onZoomIn={() => canvasRef.current?.zoomIn()}
        onZoomOut={() => canvasRef.current?.zoomOut()}
        onResetZoom={() => canvasRef.current?.resetZoom()}
        onFitToScreen={() => canvasRef.current?.zoomToFit()}
        onClearBoard={handleClearBoard}
        onSaveBoard={handleSaveBoard}
        onLoadBoard={handleLoadBoard}
        hasSavedBoard={boardSavedExists}
        onClearSavedBoard={handleClearSavedBoard}
        isMaximized={isMaximized}
        onToggleMaximize={handleToggleMaximize}
      />

      {/* Success alert */}
      {successMsg && (
        <div className="p-3 bg-emerald-500/10 border border-emerald-500/20 text-emerald-600 dark:text-emerald-500 text-xs font-sans rounded-xl text-center animate-in fade-in slide-in-from-top-1 duration-150">
          {successMsg}
        </div>
      )}

      {/* Workspace Layout: Canvas in Center, Sidebar & Export Panel on Right */}
      <div className={isMaximized 
        ? "flex flex-col lg:flex-row gap-4 flex-1 min-h-0 overflow-hidden" 
        : "flex flex-col lg:flex-row gap-6"
      }>
        
        {/* Main Canvas Area */}
        <div className="flex-1 min-w-0 h-full flex flex-col">
          <WhiteboardCanvas
            ref={canvasRef}
            activeTool={activeTool}
            brush={brush}
            shape={shape}
            text={text}
            sticky={sticky}
            onZoomChange={setZoom}
            onSelectionChange={(type, props) => {
              setSelectedObjectType(type);
              setSelectedObjectProps(props);
            }}
            onHistoryChange={(undo, redo) => {
              setCanUndo(undo);
              setCanRedo(redo);
            }}
            onWarning={(msg) => setWarning(msg)}
            onError={(msg) => setError(msg)}
            isMaximized={isMaximized}
            gridType={gridType}
            canvasTheme={canvasTheme}
            strokeDash={strokeDash}
            onToolChange={handleSelectTool}
          />
        </div>

        {/* Settings Sidebar and Export Panel */}
        <div className={isMaximized 
          ? "w-full lg:w-72 flex flex-col gap-4 flex-shrink-0 max-h-full overflow-y-auto pr-1 pb-4" 
          : "w-full lg:w-72 flex flex-col gap-6 flex-shrink-0"
        }>
          
          {/* Sidebar properties options */}
          <WhiteboardSidebar
            activeTool={activeTool}
            brush={brush}
            onChangeBrush={(b) => setBrush(prev => ({ ...prev, ...b }))}
            shape={shape}
            onChangeShape={(s) => setShape(prev => ({ ...prev, ...s }))}
            text={text}
            onChangeText={(t) => setText(prev => ({ ...prev, ...t }))}
            sticky={sticky}
            onChangeSticky={(st) => setSticky(prev => ({ ...prev, ...st }))}
            selectedObjectType={selectedObjectType}
            selectedObjectProps={selectedObjectProps}
            onChangeSelectedObject={handleChangeSelectedObject}
            onDeleteSelected={handleDeleteSelected}
            canvasTheme={canvasTheme}
            onChangeCanvasTheme={setCanvasTheme}
            gridType={gridType}
            onChangeGridType={setGridType}
            strokeDash={strokeDash}
            onChangeStrokeDash={setStrokeDash}
          />

          {/* Export options */}
          <WhiteboardExportPanel onExport={handleExport} />

          {/* Storage Info note (Required) */}
          {!isMaximized && (
            <div className="bg-surface border border-border rounded-xl p-4 flex gap-2.5 items-start">
              <Info className="w-4.5 h-4.5 text-slate flex-shrink-0 mt-0.5" />
              <div className="text-[11px] font-sans text-slate leading-normal">
                <p className="font-semibold text-ink mb-1">Local Storage Notice</p>
                Saved whiteboards are stored only in your browser’s local storage. Wiping your browser history or site data will remove saved boards.
              </div>
            </div>
          )}
          
        </div>
      </div>
    </div>
  );

  return (
    <ToolLayout
      howToUse={[
        "Select a drawing tool (brush, shape, text, or sticky note) from the toolbar.",
        "Adjust properties like color, stroke width, and opacity using the sidebar.",
        "Click and drag on the canvas to start drawing or placing elements.",
        "Use the Export panel to save your board as PNG, SVG, or PDF."
      ]}
      faqs={[
        { question: "Is my whiteboard data saved?", answer: "Yes, you can save your board to your local browser storage and reload it later. Clearing your browser data will erase it." },
        { question: "Can I collaborate live with others?", answer: "Currently, this is a local offline-first whiteboard. Live collaboration is not supported to ensure total privacy." }
      ]}
      title="Online Whiteboard"
      description="Draw, write, sketch, add shapes, and export your whiteboard directly in your browser."
      categoryName="Editing Tools"
      categoryHref="/editing"
      error={error}
      warning={warning}
      onClearError={() => setError(null)}
    >
      {content}
    </ToolLayout>
  );
}

import React, { useEffect, useRef, useState, useImperativeHandle, forwardRef } from 'react';
import * as fabric from 'fabric';
import {
  WhiteboardTool,
  BrushOptions,
  ShapeOptions,
  TextOptions,
  StickyNoteOptions
} from '@/lib/whiteboard/whiteboardTypes';
import {
  createRect,
  createCircle,
  createLine,
  createArrow,
  updateArrowPath,
  createTextbox,
  createStickyNote,
  fitToScreen,
  createTriangle,
  getStrokeDashArray
} from '@/lib/whiteboard/whiteboardHelpers';

const getStrokeDashStyle = (dashArray?: number[] | null) => {
  if (!dashArray) return 'solid';
  if (dashArray[0] === 10 || dashArray[0] === 8) return 'dashed';
  if (dashArray[0] === 2) return 'dotted';
  return 'solid';
};

interface WhiteboardCanvasProps {
  activeTool: WhiteboardTool;
  brush: BrushOptions;
  shape: ShapeOptions;
  text: TextOptions;
  sticky: StickyNoteOptions;
  onZoomChange: (zoom: number) => void;
  onSelectionChange: (type: string | null, props: any) => void;
  onHistoryChange: (canUndo: boolean, canRedo: boolean) => void;
  onWarning: (msg: string | null) => void;
  onError: (msg: string | null) => void;
  isMaximized?: boolean;
  gridType?: 'none' | 'grid' | 'dots';
  canvasTheme?: 'light' | 'dark';
  strokeDash?: 'solid' | 'dashed' | 'dotted';
  onToolChange?: (tool: WhiteboardTool) => void;
}


export interface WhiteboardCanvasRef {
  getCanvas: () => fabric.Canvas | null;
  undo: () => void;
  redo: () => void;
  clearCanvas: () => void;
  zoomIn: () => void;
  zoomOut: () => void;
  resetZoom: () => void;
  zoomToFit: () => void;
  uploadImage: (file: File) => void;
}

export const WhiteboardCanvas = forwardRef<WhiteboardCanvasRef, WhiteboardCanvasProps>(({
  activeTool,
  brush,
  shape,
  text,
  sticky,
  onZoomChange,
  onSelectionChange,
  onHistoryChange,
  onWarning,
  onError,
  isMaximized = false,
  gridType = 'none',
  canvasTheme = 'light',
  strokeDash = 'solid',
  onToolChange
}, ref) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricCanvasRef = useRef<fabric.Canvas | null>(null);

  // Drawing state
  const isDrawingShape = useRef(false);
  const shapeStartPointer = useRef<{ x: number; y: number } | null>(null);
  const activeShapeObject = useRef<fabric.Object | null>(null);

  // History stacks
  const undoStack = useRef<string[]>([]);
  const redoStack = useRef<string[]>([]);
  const isHandlingHistory = useRef(false);

  // Track active tool via ref for event handlers
  const activeToolRef = useRef<WhiteboardTool>(activeTool);
  useEffect(() => {
    activeToolRef.current = activeTool;
    updateCanvasInteractions();
  }, [activeTool, brush, shape, text, sticky, strokeDash]);

  const updateGridOffset = () => {
    const canvas = fabricCanvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;
    const zoom = canvas.getZoom();
    const vpt = canvas.viewportTransform;
    if (vpt) {
      const panX = vpt[4];
      const panY = vpt[5];
      container.style.setProperty('--zoom', zoom.toString());
      container.style.setProperty('--pan-x', panX.toString());
      container.style.setProperty('--pan-y', panY.toString());
    }
  };

  // Invert shapes color on theme change
  useEffect(() => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;
    const isDark = canvasTheme === 'dark';
    
    // Set background to transparent so container background shows
    canvas.backgroundColor = 'transparent';

    canvas.getObjects().forEach((obj) => {
      // Invert stroke
      if (obj.stroke === '#000000' && isDark) {
        obj.set({ stroke: '#FFFFFF' });
      } else if (obj.stroke === '#FFFFFF' && !isDark) {
        obj.set({ stroke: '#000000' });
      }

      // Invert fill
      if (obj.fill === '#000000' && isDark) {
        obj.set({ fill: '#FFFFFF' });
      } else if (obj.fill === '#FFFFFF' && !isDark) {
        obj.set({ fill: '#000000' });
      }

      // Text/Textbox fills
      if ((obj as any).fill === '#000000' && isDark) {
        obj.set({ fill: '#FFFFFF' });
      } else if ((obj as any).fill === '#FFFFFF' && !isDark) {
        obj.set({ fill: '#000000' });
      }
    });

    canvas.requestRenderAll();
  }, [canvasTheme]);

  // Handle Undo/Redo tracking helper
  const saveHistoryState = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas || isHandlingHistory.current) return;


    const stateJson = JSON.stringify((canvas as any).toJSON(['isSticky', 'selectable', 'hasControls']));
    
    // Avoid duplicate pushes
    if (undoStack.current.length > 0 && undoStack.current[undoStack.current.length - 1] === stateJson) {
      return;
    }

    undoStack.current.push(stateJson);
    redoStack.current = []; // Clear redo stack on new action
    
    // Limit stack size to 50 to prevent memory pressure
    if (undoStack.current.length > 50) {
      undoStack.current.shift();
    }

    onHistoryChange(undoStack.current.length > 0, redoStack.current.length > 0);
  };

  // Perform Undo
  const handleUndo = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas || undoStack.current.length === 0) return;

    isHandlingHistory.current = true;
    const currentState = JSON.stringify((canvas as any).toJSON(['isSticky', 'selectable', 'hasControls']));
    redoStack.current.push(currentState);

    const prevState = undoStack.current.pop()!;
    
    canvas.loadFromJSON(prevState, () => {
      // Re-initialize properties
      canvas.getObjects().forEach((obj) => {
        obj.set({
          selectable: true,
          hasControls: true
        });
        obj.setCoords();
      });
      canvas.requestRenderAll();
      isHandlingHistory.current = false;
      onHistoryChange(undoStack.current.length > 0, redoStack.current.length > 0);
    });
  };

  // Perform Redo
  const handleRedo = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas || redoStack.current.length === 0) return;

    isHandlingHistory.current = true;
    const currentState = JSON.stringify((canvas as any).toJSON(['isSticky', 'selectable', 'hasControls']));
    undoStack.current.push(currentState);

    const nextState = redoStack.current.pop()!;

    canvas.loadFromJSON(nextState, () => {
      canvas.getObjects().forEach((obj) => {
        obj.set({
          selectable: true,
          hasControls: true
        });
        obj.setCoords();
      });
      canvas.requestRenderAll();
      isHandlingHistory.current = false;
      onHistoryChange(undoStack.current.length > 0, redoStack.current.length > 0);
    });
  };

  // Clear Canvas
  const handleClearCanvas = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;

    if (canvas.getObjects().length === 0) return;

    saveHistoryState();
    canvas.clear();
    canvas.backgroundColor = '#FFFFFF';
    canvas.requestRenderAll();
    saveHistoryState();
  };

  // Image Upload helper
  const handleImageUpload = (file: File) => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;

    // Validate type
    const validTypes = ['image/png', 'image/jpeg', 'image/jpg', 'image/webp'];
    if (!validTypes.includes(file.type)) {
      onError("Unsupported file format. Please upload JPG, PNG, or WEBP.");
      return;
    }

    // Warning for large images (e.g. > 5MB)
    if (file.size > 5 * 1024 * 1024) {
      onWarning("This image is large. It might affect canvas performance.");
    }

    const reader = new FileReader();
    reader.onload = (fEvent) => {
      const data = fEvent.target?.result;
      if (typeof data !== 'string') {
        onError("Failed to read image data.");
        return;
      }

      fabric.Image.fromURL(data, { crossOrigin: 'anonymous' })
        .then((img) => {
          // Scale down image if it is larger than the canvas viewport
          const maxW = canvas.getWidth() * 0.6;
          const maxH = canvas.getHeight() * 0.6;

          let scale = 1;
          if (img.width && img.width > maxW) {
            scale = maxW / img.width;
          }
          if (img.height && img.height * scale > maxH) {
            scale = maxH / img.height;
          }

          img.set({
            left: canvas.getWidth() / 4,
            top: canvas.getHeight() / 4,
            scaleX: scale,
            scaleY: scale,
            selectable: true,
            hasControls: true
          });

          saveHistoryState();
          canvas.add(img);
          canvas.setActiveObject(img);
          canvas.requestRenderAll();
        })
        .catch((err) => {
          console.error("Failed to load image:", err);
          onError("Failed to load image on canvas.");
        });
    };

    reader.onerror = () => {
      onError("Failed to upload image.");
    };

    reader.readAsDataURL(file);
  };

  // Zoom helpers
  const handleZoom = (factor: number) => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;
    let zoom = canvas.getZoom() * factor;
    zoom = Math.max(0.1, Math.min(zoom, 10)); // bounds
    canvas.zoomToPoint(new fabric.Point(canvas.getWidth() / 2, canvas.getHeight() / 2), zoom);
    onZoomChange(zoom);
  };

  const handleResetZoom = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;
    canvas.setZoom(1);
    canvas.absolutePan(new fabric.Point(0, 0));
    onZoomChange(1);
  };

  const handleZoomToFit = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;
    fitToScreen(canvas);
    onZoomChange(canvas.getZoom());
  };

  // Expose methods to parent
  useImperativeHandle(ref, () => ({
    getCanvas: () => fabricCanvasRef.current,
    undo: handleUndo,
    redo: handleRedo,
    clearCanvas: handleClearCanvas,
    zoomIn: () => handleZoom(1.2),
    zoomOut: () => handleZoom(1 / 1.2),
    resetZoom: handleResetZoom,
    zoomToFit: handleZoomToFit,
    uploadImage: handleImageUpload
  }));

  // Initialize Canvas
  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    // Get width and height from container
    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight || 550;

    const canvas = new fabric.Canvas(canvasRef.current, {
      width,
      height,
      backgroundColor: 'transparent',
      selection: true, // allow group selection
      preserveObjectStacking: true // keep overlapping order
    });

    fabricCanvasRef.current = canvas;

    // Initial grid offset setup and listener
    updateGridOffset();
    canvas.on('after:render', updateGridOffset);


    // Track selections
    const updateSelection = () => {
      const activeObj = canvas.getActiveObject();
      if (!activeObj) {
        onSelectionChange(null, null);
        return;
      }

      onSelectionChange(activeObj.type || null, {
        stroke: activeObj.stroke,
        fill: activeObj.fill,
        strokeWidth: activeObj.strokeWidth,
        opacity: activeObj.opacity,
        fontFamily: (activeObj as any).fontFamily,
        fontSize: (activeObj as any).fontSize,
        fontWeight: (activeObj as any).fontWeight,
        fontStyle: (activeObj as any).fontStyle,
        underline: (activeObj as any).underline,
        backgroundColor: activeObj.backgroundColor,
        isSticky: (activeObj as any).isSticky,
        strokeDash: getStrokeDashStyle(activeObj.strokeDashArray)
      });
    };

    canvas.on('selection:created', updateSelection);
    canvas.on('selection:updated', updateSelection);
    canvas.on('selection:cleared', updateSelection);

    // Save history on changes
    canvas.on('object:modified', saveHistoryState);
    canvas.on('object:added', (e) => {
      // Do not log temp shapes or lines being actively dragged
      if (!isDrawingShape.current && !isHandlingHistory.current) {
        saveHistoryState();
      }
    });
    canvas.on('object:removed', () => {
      if (!isHandlingHistory.current) {
        saveHistoryState();
      }
    });

    // Mouse Wheel Zoom
    canvas.on('mouse:wheel', (opt) => {
      const evt = opt.e;
      evt.preventDefault();
      evt.stopPropagation();

      const delta = evt.deltaY;
      let zoom = canvas.getZoom();
      zoom = zoom * (delta > 0 ? 0.95 : 1.05);
      zoom = Math.max(0.1, Math.min(zoom, 10)); // bounds

      canvas.zoomToPoint(new fabric.Point(opt.e.offsetX, opt.e.offsetY), zoom);
      canvas.requestRenderAll();
      onZoomChange(zoom);
    });

    // Drag-to-Pan and Shape Drawing Mouse Events
    let isMouseDown = false;
    let lastX = 0;
    let lastY = 0;

    const getEventCoords = (e: any) => {
      if (e.touches && e.touches.length > 0) {
        return { clientX: e.touches[0].clientX, clientY: e.touches[0].clientY };
      }
      return { clientX: e.clientX || 0, clientY: e.clientY || 0 };
    };

    canvas.on('mouse:down', (opt) => {
      const pointer = canvas.getScenePoint(opt.e);
      const tool = activeToolRef.current;
      isMouseDown = true;

      // Panning Mode
      if (tool === 'pan') {
        const coords = getEventCoords(opt.e);
        lastX = coords.clientX;
        lastY = coords.clientY;
        canvas.selection = false;
        return;
      }

      // Eraser click-to-delete
      if (tool === 'eraser' && opt.target) {
        saveHistoryState();
        canvas.remove(opt.target);
        canvas.discardActiveObject();
        canvas.requestRenderAll();
        return;
      }

      // Drawing Shapes
      if (['rect', 'circle', 'line', 'arrow', 'triangle'].includes(tool)) {
        if (opt.target) return; // Prevent drawing if clicking on existing object
        isDrawingShape.current = true;
        shapeStartPointer.current = pointer;

        let newObj: fabric.Object | null = null;
        const shapeOptions = {
          ...shape,
          strokeDash
        };
        if (tool === 'rect') {
          newObj = createRect(pointer, shapeOptions);
        } else if (tool === 'circle') {
          newObj = createCircle(pointer, shapeOptions);
        } else if (tool === 'line') {
          newObj = createLine(pointer, shapeOptions);
        } else if (tool === 'arrow') {
          newObj = createArrow(pointer, shapeOptions);
        } else if (tool === 'triangle') {
          newObj = createTriangle(pointer, shapeOptions);
        }

        if (newObj) {
          activeShapeObject.current = newObj;
          canvas.add(newObj);
          canvas.setActiveObject(newObj);
          canvas.requestRenderAll();
        }
        return;
      }

      // Drawing Text & Sticky Notes
      if (tool === 'text' || tool === 'sticky') {
        if (opt.target) return; // Prevent creating if clicking on existing object
        saveHistoryState();
        
        let newObj: fabric.Object | null = null;
        if (tool === 'text') {
          newObj = createTextbox(pointer, text);
        } else if (tool === 'sticky') {
          newObj = createStickyNote(pointer, { bg: sticky.color, text: sticky.text });
        }

        if (newObj) {
          canvas.add(newObj);
          canvas.setActiveObject(newObj);
          canvas.requestRenderAll();
          
          if (tool === 'text') {
            (newObj as fabric.Textbox).enterEditing();
            (newObj as fabric.Textbox).selectAll();
          }
          if (onToolChange) onToolChange('select');
        }
      }
    });

    canvas.on('mouse:move', (opt) => {
      if (!isMouseDown) return;
      const pointer = canvas.getScenePoint(opt.e);
      const tool = activeToolRef.current;

      // Pan Movement
      if (tool === 'pan' && canvas.viewportTransform) {
        const coords = getEventCoords(opt.e);
        const vpt = canvas.viewportTransform;
        vpt[4] += coords.clientX - lastX;
        vpt[5] += coords.clientY - lastY;
        canvas.requestRenderAll();
        lastX = coords.clientX;
        lastY = coords.clientY;
        return;
      }

      // Draw Shapes Dragging
      if (isDrawingShape.current && shapeStartPointer.current && activeShapeObject.current) {
        const start = shapeStartPointer.current;
        const activeObj = activeShapeObject.current;
        const dx = pointer.x - start.x;
        const dy = pointer.y - start.y;

        if (tool === 'rect') {
          const rect = activeObj as fabric.Rect;
          rect.set({
            width: Math.abs(dx),
            height: Math.abs(dy),
            left: dx > 0 ? start.x : pointer.x,
            top: dy > 0 ? start.y : pointer.y
          });
        } else if (tool === 'circle') {
          const circle = activeObj as fabric.Circle;
          circle.set({
            radius: Math.max(Math.abs(dx), Math.abs(dy)) / 2,
            left: dx > 0 ? start.x : pointer.x,
            top: dy > 0 ? start.y : pointer.y
          });
        } else if (tool === 'line') {
          const line = activeObj as fabric.Line;
          line.set({
            x2: pointer.x,
            y2: pointer.y
          });
        } else if (tool === 'arrow') {
          const path = activeObj as fabric.Path;
          updateArrowPath(path, start.x, start.y, pointer.x, pointer.y);
        } else if (tool === 'triangle') {
          const triangle = activeObj as fabric.Triangle;
          triangle.set({
            width: Math.abs(dx),
            height: Math.abs(dy),
            left: dx > 0 ? start.x : pointer.x,
            top: dy > 0 ? start.y : pointer.y
          });
        }

        activeObj.setCoords();
        canvas.requestRenderAll();
      }
    });

    canvas.on('mouse:up', () => {
      isMouseDown = false;
      
      if (isDrawingShape.current) {
        isDrawingShape.current = false;
        activeShapeObject.current = null;
        shapeStartPointer.current = null;
        saveHistoryState();
        if (onToolChange) onToolChange('select');
      }
    });

    // Keyboard Del Key Listener
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Delete' || e.key === 'Backspace') {
        // Skip deletion if text editing is active
        const activeObj = canvas.getActiveObject();
        if (activeObj && (activeObj as any).isEditing) return;

        if (activeObj) {
          saveHistoryState();
          
          if (activeObj.type === 'activeSelection') {
            const activeSel = activeObj as fabric.ActiveSelection;
            activeSel.forEachObject((obj) => canvas.remove(obj));
            canvas.discardActiveObject();
          } else {
            canvas.remove(activeObj);
          }
          canvas.requestRenderAll();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);

    // Initial Resize Observer for responsive canvas sizing
    const resizeObserver = new ResizeObserver(() => {
      if (containerRef.current && fabricCanvasRef.current) {
        const w = containerRef.current.clientWidth;
        const h = containerRef.current.clientHeight || 550;
        fabricCanvasRef.current.setDimensions({ width: w, height: h });
        fabricCanvasRef.current.requestRenderAll();
      }
    });
    
    resizeObserver.observe(containerRef.current);

    // Clean up
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      resizeObserver.disconnect();
      canvas.dispose();
      fabricCanvasRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Update Canvas Configuration based on current tool/brush/shapes
  const updateCanvasInteractions = () => {
    const canvas = fabricCanvasRef.current;
    if (!canvas) return;

    const tool = activeTool;

    // Brush/Freehand Drawing Mode Configuration
    if (tool === 'pen' || tool === 'pencil' || tool === 'eraser') {
      canvas.isDrawingMode = true;
      canvas.selection = false;

      // Instantiate standard pencil brush if not present
      if (!canvas.freeDrawingBrush) {
        canvas.freeDrawingBrush = new fabric.PencilBrush(canvas);
      }

      const brushObj = canvas.freeDrawingBrush;
      
      if (tool === 'eraser') {
        // Erase strokes by drawing white lines of the eraser size over other objects
        brushObj.color = '#FFFFFF';
        brushObj.width = brush.width;
        // Optional: reduce opacity for erasing? No, eraser is always solid
        (brushObj as any).opacity = 1;
      } else {
        // Normal Pen/Pencil mode
        brushObj.color = brush.color;
        brushObj.width = brush.width;
        // Custom opacity support
        (brushObj as any).opacity = brush.opacity;
        
        // Slightly tweak drawing options
        brushObj.strokeLineCap = 'round';
        brushObj.strokeLineJoin = 'round';
        
        // Pencils are usually thinner, pen can be thick
        if (tool === 'pencil') {
          // Add small drawing shadow or keep simple
        }
      }
    } else {
      // Non-drawing modes
      canvas.isDrawingMode = false;
      
      if (tool === 'select') {
        canvas.selection = true;
        canvas.hoverCursor = 'move';
        canvas.defaultCursor = 'default';
        
        // Make all objects selectable
        canvas.getObjects().forEach(obj => {
          obj.set({
            selectable: true,
            evented: true,
            lockMovementX: false,
            lockMovementY: false,
            lockScalingX: false,
            lockScalingY: false,
            lockRotation: false
          });
        });
      } else if (tool === 'pan') {
        canvas.selection = false;
        canvas.hoverCursor = 'grab';
        canvas.defaultCursor = 'grab';
        
        // Disable selecting and moving objects when panning
        canvas.getObjects().forEach(obj => {
          obj.set({
            selectable: false,
            evented: false
          });
        });
      } else {
        // Creating text, shapes, or sticky note
        canvas.selection = false;
        canvas.hoverCursor = 'crosshair';
        canvas.defaultCursor = 'crosshair';
        
        // Keep objects selectable even while drawing tool is active, 
        // so that clicking them selects them instead of drawing
        canvas.getObjects().forEach(obj => {
          obj.set({
            selectable: true,
            evented: true
          });
        });
      }
    }

    canvas.requestRenderAll();
  };

  const isDark = canvasTheme === 'dark';
  const themeClasses = isDark ? 'bg-zinc-950 text-white border-zinc-800' : 'bg-white text-black border-border';
  const gridColor = isDark ? 'rgba(255, 255, 255, 0.08)' : 'rgba(0, 0, 0, 0.08)';
  const dotColor = isDark ? 'rgba(255, 255, 255, 0.2)' : 'rgba(0, 0, 0, 0.15)';

  let backgroundStyle: React.CSSProperties = {};
  if (gridType === 'grid') {
    backgroundStyle = {
      '--grid-color': gridColor,
      backgroundSize: `calc(30px * var(--zoom, 1)) calc(30px * var(--zoom, 1))`,
      backgroundPosition: `calc(var(--pan-x, 0) * 1px) calc(var(--pan-y, 0) * 1px)`,
      backgroundImage: `linear-gradient(to right, var(--grid-color) 1px, transparent 1px), linear-gradient(to bottom, var(--grid-color) 1px, transparent 1px)`,
    } as React.CSSProperties;
  } else if (gridType === 'dots') {
    backgroundStyle = {
      '--grid-color': dotColor,
      backgroundSize: `calc(30px * var(--zoom, 1)) calc(30px * var(--zoom, 1))`,
      backgroundPosition: `calc(var(--pan-x, 0) * 1px) calc(var(--pan-y, 0) * 1px)`,
      backgroundImage: `radial-gradient(var(--grid-color) 1px, transparent 1px)`,
    } as React.CSSProperties;
  }

  return (
    <div 
      ref={containerRef} 
      className={`w-full relative border shadow-inner overflow-hidden cursor-crosshair transition-colors duration-200 ${themeClasses} ${
        isMaximized ? 'flex-1 h-full min-h-0' : 'h-[550px] rounded-2xl'
      }`}
      style={backgroundStyle}
    >
      <canvas ref={canvasRef} className="absolute inset-0 block" />
    </div>
  );
});

