          >
            <ZoomIn className="w-4 h-4" />
          </button>
          <button
            onClick={onFitToScreen}
            className="w-8 h-8 rounded-lg flex items-center justify-center cursor-pointer transition-all duration-150 text-slate hover:bg-background hover:text-ink"
            title="Fit to Screen"
          >
            <Maximize2 className="w-4 h-4" />
          </button>
        </div>

        {/* Local Storage Save / Load / Clear Actions */}
        <div className="flex items-center gap-1.5">
          <button
            onClick={onSaveBoard}
            className="h-8 px-2.5 rounded-lg flex items-center gap-1.5 cursor-pointer transition-all duration-150 text-xs font-sans font-medium text-slate hover:bg-background hover:text-ink"
            title="Save board locally in browser"
          >
            <Save className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">Save</span>
          </button>
          
          <button
            onClick={onLoadBoard}
            disabled={!hasSavedBoard}
            className="h-8 px-2.5 rounded-lg flex items-center gap-1.5 cursor-pointer transition-all duration-150 text-xs font-sans font-medium text-slate hover:bg-background hover:text-ink disabled:opacity-30 disabled:pointer-events-none"
            title="Load board from browser storage"
          >
            <FolderOpen className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">Load</span>
          </button>

          <button
            onClick={onClearBoard}
            className="h-8 px-2.5 rounded-lg flex items-center gap-1.5 cursor-pointer transition-all duration-150 text-xs font-sans font-semibold text-red-500 hover:bg-red-500/10 border-r border-border pr-4 mr-1"
            title="Clear all drawings from current canvas"
          >
            <Trash2 className="w-3.5 h-3.5" />
            <span className="hidden sm:inline">Clear</span>
          </button>

          {/* Fullscreen Button */}
          <button
            onClick={onToggleMaximize}
            className={`h-8 px-3 rounded-lg flex items-center gap-1.5 cursor-pointer transition-all duration-150 text-xs font-sans font-semibold ${
              isMaximized 
                ? 'bg-primary text-dark hover:bg-primary/90' 
                : 'bg-zinc-800 text-white hover:bg-zinc-700 dark:bg-white dark:text-zinc-900 dark:hover:bg-zinc-100'
            }`}
            title={isMaximized ? "Exit Fullscreen" : "Enter Fullscreen"}
          >
            {isMaximized ? <Shrink className="w-3.5 h-3.5" /> : <Expand className="w-3.5 h-3.5" />}
            <span className="hidden sm:inline">{isMaximized ? "Exit Fullscreen" : "Fullscreen"}</span>
          </button>
        </div>
      </div>
    </div>
  );
}

"use client"

import React, { useState, useMemo, useCallback } from "react"
import { motion } from "framer-motion"
import Link from "next/link"
import { usePathname } from "next/navigation"
import { LucideIcon, ChevronDown } from "lucide-react"

function cn(...classes: (string | undefined | null | false)[]) {
  return classes.filter(Boolean).join(' ');
}

export interface DropdownItem {
  name: string;
  url: string;
}

export interface NavItem {
  name: string
  url: string
  icon: LucideIcon
  dropdownItems?: DropdownItem[]
}

interface NavBarProps {
  items: NavItem[]
  className?: string
}

export function NavBar({ items, className }: NavBarProps) {
  const pathname = usePathname()
  const [hoveredTab, setHoveredTab] = useState<string | null>(null)
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null)

  // 1. Optimize active route calculation: compute active item name once per render
  const activeItemName = useMemo(() => {
    for (const item of items) {
      if (item.url === '/' && pathname === '/') return item.name;
      if (item.url !== '/' && pathname.startsWith(item.url)) return item.name;
      if (item.dropdownItems?.some(dropItem => pathname.startsWith(dropItem.url))) return item.name;
    }
    return null;
  }, [items, pathname]);

  // 2. Wrap event handlers with useCallback to prevent reference changes
  const handleItemClick = useCallback((e: React.MouseEvent, item: NavItem) => {
    const hasDropdown = item.dropdownItems && item.dropdownItems.length > 0;
    if (hasDropdown) {
      e.preventDefault();
      setActiveDropdown(prev => prev === item.name ? null : item.name);
    } else {
      setActiveDropdown(null);
    }
  }, []);

  const handleMouseEnter = useCallback((itemName: string) => {
    if (typeof window !== 'undefined' && window.matchMedia('(hover: hover)').matches) {
      setHoveredTab(itemName);
      setActiveDropdown(itemName);
    }
  }, []);

  const handleMouseLeave = useCallback(() => {
    if (typeof window !== 'undefined' && window.matchMedia('(hover: hover)').matches) {
      setHoveredTab(null);
      setActiveDropdown(null);
    }
  }, []);

  const handleBackdropClick = useCallback(() => {
    setActiveDropdown(null);
  }, []);

  return (
    <>
      {/* 3. Invisible click-away backdrop to close dropdowns when tapping outside */}
      {activeDropdown && (
        <div 
          className="fixed inset-0 z-40 bg-transparent"
          onClick={handleBackdropClick}
        />
      )}

      <div className={cn("relative z-50", className)}>
        <div className="flex items-center justify-around w-[85vw] sm:w-auto sm:justify-start gap-1 sm:gap-3 bg-surface/80 border border-border backdrop-blur-lg py-1.5 px-2 sm:px-1 rounded-full shadow-lg">
          {items.map((item) => {
            const Icon = item.icon
            const isActive = activeItemName === item.name;
            const hasDropdown = item.dropdownItems && item.dropdownItems.length > 0;

            return (
              <div
                key={item.name}
                className="relative"
                onMouseEnter={() => handleMouseEnter(item.name)}
                onMouseLeave={handleMouseLeave}
              >
                <Link
                  href={item.url}
                  onClick={(e) => handleItemClick(e, item)}
                  className={cn(
                    "relative cursor-pointer text-sm font-medium px-4 md:px-6 py-2 rounded-full transition-colors flex items-center gap-1.5",
                    "text-slate hover:text-primary",
                    isActive && "text-primary",
                  )}
                >
                  <span className="hidden md:inline">{item.name}</span>
                  <span className="md:hidden">
                    <Icon size={18} strokeWidth={2.5} />
                  </span>
                  
                  {hasDropdown && (
                    <ChevronDown className="w-4 h-4 hidden md:block opacity-50" />
                  )}
                  
                  {isActive && (
                    <motion.div
                      layoutId="lamp"
                      className="absolute inset-0 w-full bg-primary/5 rounded-full -z-10"
                      initial={false}
                      transition={{
                        type: "spring",
                        stiffness: 300,
                        damping: 30,
                      }}
                    >
                      <div className="absolute -top-2 left-1/2 -translate-x-1/2 w-8 h-1 bg-primary rounded-t-full">
                        <div className="absolute w-12 h-6 bg-primary/20 rounded-full blur-md -top-2 -left-2" />
                        <div className="absolute w-8 h-6 bg-primary/20 rounded-full blur-md -top-1" />
                        <div className="absolute w-4 h-4 bg-primary/20 rounded-full blur-sm top-0 left-2" />
                      </div>
                    </motion.div>
                  )}
                </Link>
                
                {/* 4. GPU-accelerated CSS transition-based Dropdown Menu */}
                {hasDropdown && (
                  <div
                    className={cn(
                      "absolute left-1/2 -translate-x-1/2 w-48 pt-4 top-full transition-all duration-300 ease-out will-change-transform z-50",
                      activeDropdown === item.name
                        ? "opacity-100 translate-y-0 pointer-events-auto"
                        : "opacity-0 -translate-y-2 pointer-events-none"
                    )}
                  >
                    <div className="bg-surface border border-border rounded-2xl shadow-xl overflow-hidden flex flex-col py-2">
                      {item.dropdownItems!.map((dropItem) => (
                        <Link
                          key={dropItem.name}
                          href={dropItem.url}
                          onClick={handleBackdropClick}
                          className="px-4 py-2.5 text-sm text-slate hover:text-primary hover:bg-primary/5 transition-colors"
                        >
                          {dropItem.name}
                        </Link>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )
          })}
        </div>
      </div>
    </>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react';

export type PomodoroMode = 'pomodoro' | 'short_break' | 'long_break' | 'custom';

export interface Task {
  id: string;
  title: string;
  completed: boolean;
}

export interface PomodoroStats {
  sessionsCompleted: number;
  totalFocusSeconds: number;
  currentStreak: number;
  lastSessionDate?: string;
}

const DEFAULT_TIMES = {
  pomodoro: 25 * 60,
  short_break: 5 * 60,
  long_break: 15 * 60,
  custom: 25 * 60,
};

export function usePomodoroEngine() {
  const [mode, setMode] = useState<PomodoroMode>('pomodoro');
  const [timeLeft, setTimeLeft] = useState(DEFAULT_TIMES.pomodoro);
  const [isRunning, setIsRunning] = useState(false);

  const [tasks, setTasks] = useState<Task[]>([]);
  const [stats, setStats] = useState<PomodoroStats>({
    sessionsCompleted: 0,
    totalFocusSeconds: 0,
    currentStreak: 0,
  });

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  // Load from local storage
  useEffect(() => {
    try {
      const storedStats = localStorage.getItem('singulariti_pomodoro_stats');
      if (storedStats) {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setStats(JSON.parse(storedStats));
      }
      const storedTasks = localStorage.getItem('singulariti_pomodoro_tasks');
      if (storedTasks) {

        setTasks(JSON.parse(storedTasks));
      }
    } catch (e) {
      console.error("Failed to load pomodoro data", e);
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem('singulariti_pomodoro_stats', JSON.stringify(stats));
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('singulariti_pomodoro_tasks', JSON.stringify(tasks));
  }, [tasks]);

  const changeMode = useCallback((newMode: PomodoroMode) => {
    setIsRunning(false);
    setMode(newMode);
    setTimeLeft(DEFAULT_TIMES[newMode]);
  }, []);

  const handleSessionComplete = useCallback(() => {
    if (mode === 'pomodoro' || mode === 'custom') {
      const today = new Date().toDateString();
      setStats(prev => {
        let newStreak = prev.currentStreak;
        if (prev.lastSessionDate !== today) {
          const yesterday = new Date();
          yesterday.setDate(yesterday.getDate() - 1);
          if (prev.lastSessionDate === yesterday.toDateString()) {
            newStreak += 1;
          } else {
            newStreak = 1;
          }
        }
        return {
          ...prev,
          sessionsCompleted: prev.sessionsCompleted + 1,
          totalFocusSeconds: prev.totalFocusSeconds + DEFAULT_TIMES[mode],
          currentStreak: newStreak,
          lastSessionDate: today,
        };
      });
      // Auto-switch to short break
      changeMode('short_break');
    } else {
      // After break, switch to pomodoro
      changeMode('pomodoro');
    }
  }, [mode, changeMode]);

  // Timer logic
  useEffect(() => {
    if (isRunning && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(timerRef.current!);
            setIsRunning(false);
            handleSessionComplete();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (!isRunning && timerRef.current) {
      clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isRunning, timeLeft, handleSessionComplete]);

  const toggleTimer = () => setIsRunning(!isRunning);

  const resetTimer = () => {
    setIsRunning(false);
    setTimeLeft(DEFAULT_TIMES[mode]);
  };

  const setCustomTime = (minutes: number) => {
    DEFAULT_TIMES.custom = minutes * 60;
    changeMode('custom');
  };

  // Task Management
  const addTask = (title: string) => {
    if (!title.trim()) return;
    setTasks(prev => [...prev, { id: Date.now().toString(), title, completed: false }]);
  };

  const toggleTask = (id: string) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  return {
    mode,
    timeLeft,
    isRunning,
    stats,
    tasks,
    totalTime: DEFAULT_TIMES[mode],
    toggleTimer,
    changeMode,
    resetTimer,
    setCustomTime,
    addTask,
    toggleTask,
    deleteTask,
  };
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { generateWords, TypingDifficulty } from '@/lib/typing/words';

export type TypingMode = 'time' | 'words' | 'custom';

export interface TypingState {
  mode: TypingMode;
  timeLimit: number; // in seconds
  wordLimit: number;
  difficulty: TypingDifficulty;
  words: string[];
  currentInput: string;
  wordIndex: number;
  status: 'idle' | 'running' | 'finished';
  startTime: number | null;
  endTime: number | null;
  timeLeft: number;
  correctChars: number;
  incorrectChars: number;
  extraChars: number;
  history: { word: string; input: string; isCorrect: boolean }[];
  keystrokes: number;
}

export function useTypingEngine() {
  const [state, setState] = useState<TypingState>({
    mode: 'time',
    timeLimit: 30,
    wordLimit: 25,
    difficulty: 'easy',
    words: [],
    currentInput: '',
    wordIndex: 0,
    status: 'idle',
    startTime: null,
    endTime: null,
    timeLeft: 30,
    correctChars: 0,
    incorrectChars: 0,
    extraChars: 0,
    history: [],
    keystrokes: 0,
  });

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  // Initialize test
  const initializeTest = useCallback((mode: TypingMode, time: number, words: number, diff: TypingDifficulty) => {
    if (timerRef.current) clearInterval(timerRef.current);

    // For time mode, generate plenty of words. For words mode, exact number.
    const wordCount = mode === 'time' ? 300 : words;
    const generated = generateWords(wordCount, diff);

    setState({
      mode,
      timeLimit: time,
      wordLimit: words,
      difficulty: diff,
      words: generated,
      currentInput: '',
      wordIndex: 0,
      status: 'idle',
      startTime: null,
      endTime: null,
      timeLeft: mode === 'time' ? time : 0,
      correctChars: 0,
      incorrectChars: 0,
      extraChars: 0,
      history: [],
      keystrokes: 0,
    });
  }, []);

  // Set default words on mount
  useEffect(() => {
    // Run once on mount to populate initial words
    // eslint-disable-next-line react-hooks/set-state-in-effect
    initializeTest(state.mode, state.timeLimit, state.wordLimit, state.difficulty);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initializeTest]);

  // Finish test
  const finishTest = useCallback(() => {
    if (timerRef.current) clearInterval(timerRef.current);
    setState(prev => ({
      ...prev,
      status: 'finished',
      endTime: Date.now()
    }));
  }, []);

  // Handle typing input
  const handleInput = useCallback((value: string) => {
    setState(prev => {
      if (prev.status === 'finished') return prev;

      const newState = { ...prev };

      // Start test on first keystroke
      if (prev.status === 'idle') {
        newState.status = 'running';
        newState.startTime = Date.now();

        if (prev.mode === 'time') {
          timerRef.current = setInterval(() => {
            setState(s => {
              if (s.timeLeft <= 1) {
                if (timerRef.current) clearInterval(timerRef.current);
                return { ...s, timeLeft: 0, status: 'finished', endTime: Date.now() };
              }
              return { ...s, timeLeft: s.timeLeft - 1 };
            });
          }, 1000);
        }
      }

      // Check if space was pressed indicating word completion
      if (value.endsWith(' ')) {
        const inputWord = value.trim();
        const targetWord = prev.words[prev.wordIndex];

        // Don't advance if just space was pressed on empty input
        if (inputWord === '' && value === ' ') {
          return newState; // ignore
        }

        const isCorrect = inputWord === targetWord;

        // Calculate characters for this word
        // Iterate through the shorter length, then add extra or incorrect
        let cChars = 0;
        let iChars = 0;
        let eChars = 0;

        for (let i = 0; i < Math.max(inputWord.length, targetWord.length); i++) {
           if (i < targetWord.length && i < inputWord.length) {
             if (inputWord[i] === targetWord[i]) cChars++;
             else iChars++;
           } else if (i >= targetWord.length) {
             eChars++;
           } else if (i >= inputWord.length) {
             // Missing characters at end are not strictly counted until end of test or just counted as incorrect?
             // Usually monkeytype counts missed characters of a word if you hit space early as just not typed, not strictly 'incorrect' unless evaluating full accuracy. We'll count them as incorrect to match error rate calculation.
             iChars++; 
           }
        }

        // Plus 1 correct char for the space itself
        cChars++;

        newState.history = [...prev.history, { word: targetWord, input: inputWord, isCorrect }];
        newState.wordIndex = prev.wordIndex + 1;
        newState.currentInput = '';
        newState.correctChars = prev.correctChars + cChars;
        newState.incorrectChars = prev.incorrectChars + iChars;
        newState.extraChars = prev.extraChars + eChars;
        newState.keystrokes = prev.keystrokes + 1; // space key

        // Check if finished by words mode
        if (prev.mode === 'words' && newState.wordIndex >= prev.wordLimit) {
           newState.status = 'finished';
           newState.endTime = Date.now();
           if (timerRef.current) clearInterval(timerRef.current);
        }

        return newState;
      }

      // Normal character typing
      // If the input was reduced (backspace), we don't recalculate global correctChars immediately, 
      // but we do count keystrokes.
      const isBackspace = value.length < prev.currentInput.length;
      if (!isBackspace) {
        newState.keystrokes += 1;
      }
      newState.currentInput = value;

      // Auto-finish if it's the last word and exactly correct
      if (prev.mode === 'words' && prev.wordIndex === prev.wordLimit - 1) {
        const targetWord = prev.words[prev.wordIndex];
        if (value === targetWord) {
           newState.history = [...prev.history, { word: targetWord, input: value, isCorrect: true }];
           newState.wordIndex = prev.wordIndex + 1;
           newState.correctChars = prev.correctChars + value.length; // No space typed
           newState.status = 'finished';
           newState.endTime = Date.now();
           if (timerRef.current) clearInterval(timerRef.current);
        }
      }

      return newState;
    });
  }, []);

  // Cleanup timer
  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  return {
    state,
    handleInput,
    initializeTest,
    finishTest
  };
}

import { PDFDocument, rgb, degrees, StandardFonts } from 'pdf-lib';
import { encryptPDF } from '@pdfsmaller/pdf-encrypt-lite';
import { dataUrlToArrayBuffer } from '../fileHelpers';
import { readPdfFile } from './readPdfFile';
import { getPdfWatermarkPosition, getCenteredDrawPosition, WatermarkPosition } from './getWatermarkPosition';

function hexToPdfRgb(hex: string) {
  const clean = hex.replace("#", "");

  const r = parseInt(clean.slice(0, 2), 16) / 255;
  const g = parseInt(clean.slice(2, 4), 16) / 255;
  const b = parseInt(clean.slice(4, 6), 16) / 255;

  return rgb(r, g, b);
}

function hexToRgb01(hex: string) {
  const clean = hex.replace("#", "");

  const r = parseInt(clean.substring(0, 2), 16) / 255;
  const g = parseInt(clean.substring(2, 4), 16) / 255;
  const b = parseInt(clean.substring(4, 6), 16) / 255;

  return rgb(r, g, b);
}

// Helper to convert hex colors to normalized RGB values for pdf-lib
function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16) / 255,
    g: parseInt(result[2], 16) / 255,
    b: parseInt(result[3], 16) / 255
  } : { r: 0, g: 0, b: 0 };
}

/**
 * Merge multiple PDF files into one.
 */
export async function mergePDFs(files: File[]): Promise<Uint8Array> {
  const mergedPdf = await PDFDocument.create();

  for (const file of files) {
    const arrayBuffer = await readPdfFile(file);
    const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
    const copiedPages = await mergedPdf.copyPages(pdfDoc, pdfDoc.getPageIndices());
    copiedPages.forEach((page) => mergedPdf.addPage(page));
  }

  return mergedPdf.save();
}

/**
 * Split a PDF file by extracting selected page ranges into a new PDF.
 * Ranges: 1-based indices (e.g. [1, 2, 3, 5, 7, 8])
 */
export async function splitPDF(file: File, pageNumbers: number[]): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  const newPdf = await PDFDocument.create();

  // Convert 1-based page numbers to 0-based indices
  const pageIndices = pageNumbers.map(num => num - 1);
  const copiedPages = await newPdf.copyPages(pdfDoc, pageIndices);
  copiedPages.forEach((page) => newPdf.addPage(page));

  return newPdf.save();
}

/**
 * Rotate specific pages of a PDF.
 * pageRotations maps 1-based page numbers to rotation degrees (e.g., 90, 180, 270)
 */
export async function rotatePDF(
  file: File,
  pageRotations: Record<number, number>
): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  const pages = pdfDoc.getPages();

  Object.entries(pageRotations).forEach(([pageIndexStr, rotation]) => {
    const pageIndex = parseInt(pageIndexStr, 10) - 1;
    if (pageIndex >= 0 && pageIndex < pages.length) {
      const page = pages[pageIndex];
      const currentRotation = page.getRotation().angle;
      page.setRotation(degrees((currentRotation + rotation) % 360));
    }
  });

  return pdfDoc.save();
}

/**
 * Delete specified pages from a PDF.
 * pageNumbersToDelete: 1-based page numbers (e.g., [2, 4])
 */
export async function deletePDFPages(
  file: File,
  pageNumbersToDelete: number[]
): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  
  // Sort descending to avoid index shifting when deleting
  const indicesToDelete = pageNumbersToDelete
    .map(num => num - 1)
    .sort((a, b) => b - a);

  indicesToDelete.forEach(index => {
    if (index >= 0 && index < pdfDoc.getPageCount()) {
      pdfDoc.removePage(index);
    }
  });

  return pdfDoc.save();
}

/**
 * Rearranges PDF pages into a custom order.
 * newOrder: Array of 0-based indices representing the new page positions
 */
export async function rearrangePDFPages(
  file: File,
  newOrder: number[]
): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const srcDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  const newPdf = await PDFDocument.create();

  const copiedPages = await newPdf.copyPages(srcDoc, newOrder);
  copiedPages.forEach((page) => newPdf.addPage(page));

  return newPdf.save();
}

/**
 * Extracts specific pages from a PDF.
 * pageNumbersToExtract: 1-based page numbers
 */
export async function extractPDFPages(
  file: File,
  pageNumbersToExtract: number[]
): Promise<Uint8Array> {
  return splitPDF(file, pageNumbersToExtract);
}

/**
 * Image-to-PDF Conversion Settings
 */
export interface ImageToPDFSettings {
  pageSize: 'A4' | 'Letter' | 'fit';
  orientation: 'portrait' | 'landscape';
  margin: number; // in points
}

/**
 * Convert multiple image files into a single PDF.
 */
export async function imagesToPDF(
  files: File[],
  settings: ImageToPDFSettings
): Promise<Uint8Array> {
  const pdfDoc = await PDFDocument.create();

  // Page Dimensions in Points (1 inch = 72 points)
  const sizes = {
    A4: { width: 595.27, height: 841.89 },
    Letter: { width: 612.0, height: 792.0 }
  };

  for (const file of files) {
    const arrayBuffer = await file.arrayBuffer();
    let image;
    
    if (file.type === 'image/png' || file.name.toLowerCase().endsWith('.png')) {
      image = await pdfDoc.embedPng(arrayBuffer);
    } else if (
      file.type === 'image/jpeg' || 
      file.type === 'image/jpg' || 
      file.name.toLowerCase().endsWith('.jpg') || 
      file.name.toLowerCase().endsWith('.jpeg')
    ) {
      image = await pdfDoc.embedJpg(arrayBuffer);
    } else {
      // Fallback: try embedding PNG first, then JPG if failed
      try {
        image = await pdfDoc.embedPng(arrayBuffer);
      } catch {
        image = await pdfDoc.embedJpg(arrayBuffer);
      }
    }

    let pageWidth = sizes.A4.width;
    let pageHeight = sizes.A4.height;

    if (settings.pageSize === 'fit') {
      pageWidth = image.width + settings.margin * 2;
      pageHeight = image.height + settings.margin * 2;
    } else {
      const selectedSize = sizes[settings.pageSize] || sizes.A4;
      if (settings.orientation === 'landscape') {
        pageWidth = selectedSize.height;
        pageHeight = selectedSize.width;
      } else {
        pageWidth = selectedSize.width;
        pageHeight = selectedSize.height;
      }
    }

    const page = pdfDoc.addPage([pageWidth, pageHeight]);

    // Calculate dimensions to maintain aspect ratio
    const contentWidth = pageWidth - settings.margin * 2;
    const contentHeight = pageHeight - settings.margin * 2;
    
    const imgRatio = image.width / image.height;
    const pageRatio = contentWidth / contentHeight;

    let drawWidth = contentWidth;
    let drawHeight = contentHeight;

    if (imgRatio > pageRatio) {
      drawHeight = contentWidth / imgRatio;
    } else {
      drawWidth = contentHeight * imgRatio;
    }

    // Center the image
    const x = settings.margin + (contentWidth - drawWidth) / 2;
    const y = settings.margin + (contentHeight - drawHeight) / 2;

    page.drawImage(image, {
      x,
      y,
      width: drawWidth,
      height: drawHeight
    });
  }

  return pdfDoc.save();
}

/**
 * Basic browser-side structural compression.
 */
export async function compressPDF(file: File): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  
  // Re-serialization with object streams enabled removes unreferenced objects,
  // compresses cross-reference tables and standard streams
  return pdfDoc.save({ useObjectStreams: true });
}

/**
 * Draws a signature image onto a specific PDF page.
 * signatureDataUrl: Data URL string of signature image (PNG/JPG)
 * position: coordinates and dimensions relative to page (0 to 1 scaling, or absolute points)
 */
export async function signPDF(
  arrayBuffer: ArrayBuffer,
  pageIndex: number,
  signatureDataUrl: string,
  posX: number,
  posY: number,
  sigWidth: number,
  sigHeight: number,
  sigRotation: number
): Promise<Uint8Array> {
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  const page = pdfDoc.getPage(pageIndex);
  const { width: pdfW, height: pdfH } = page.getSize();

  // Draw signature (signatureDataUrl is a PNG base64 data URI)
  const imageBytes = dataUrlToArrayBuffer(signatureDataUrl);
  const sigImage = signatureDataUrl.startsWith('data:image/png')
    ? await pdfDoc.embedPng(imageBytes)
    : await pdfDoc.embedJpg(imageBytes);

  const scaleX = (posX / 100) * pdfW;
  const scaleY = (posY / 100) * pdfH;
  const drawWidth = (sigWidth / 100) * pdfW;
  const drawHeight = (sigHeight / 100) * pdfH;

  // Convert HTML canvas center coordinates to PDF bottom-left coordinates
  page.drawImage(sigImage, {
    x: scaleX - drawWidth / 2,
    y: pdfH - scaleY - drawHeight / 2,
    width: drawWidth,
    height: drawHeight,
    rotate: degrees(-sigRotation)
  });

  return pdfDoc.save();
}

/**
 * Watermark Settings
 */
export interface WatermarkOptions {
  type: 'text' | 'image';
  text?: string;
  imageFile?: File; // For image watermarks
  color?: string; // Hex color string, e.g. '#FF0000'
  opacity?: number; // 0 to 1
  rotation?: number; // degrees
  xPercent: number; // Top-left visual x percentage (0 to 1)
  yPercent: number; // Top-left visual y percentage (0 to 1)
  positionPreset: WatermarkPosition;
  fontSize?: number; // Exact text font size
  imageSize?: number; // Image scale percentage (e.g. 40 for 40%)
  imageAspectRatio?: number | null;
  fontSizePercent?: number; // Text font size percent (0 to 1)
  imageWidthPercent?: number; // Image width percent (0 to 1)
  imageHeightPercent?: number; // Image height percent (0 to 1)
  applyToAll: boolean;
  selectedPages?: number[]; // 1-based page numbers
  previewPageWidth?: number;
  previewPageHeight?: number;
}

/**
 * Add a text or image watermark to a PDF.
 */
export async function addWatermarkToPDF(
  file: File,
  options: WatermarkOptions
): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
  const pageCount = pdfDoc.getPageCount();

  const pagesToWatermark: number[] = [];
  if (options.applyToAll) {
    for (let i = 1; i <= pageCount; i++) pagesToWatermark.push(i);
  } else if (options.selectedPages) {
    pagesToWatermark.push(...options.selectedPages);
  }

  // Load font or embed image
  let helveticaFont;
  let embeddedImage: any;

  if (options.type === 'text') {
    helveticaFont = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
  } else if (options.type === 'image' && options.imageFile) {
    const imgBuffer = await options.imageFile.arrayBuffer();
    if (
      options.imageFile.type === 'image/png' || 
      options.imageFile.name.toLowerCase().endsWith('.png')
    ) {
      embeddedImage = await pdfDoc.embedPng(imgBuffer);
    } else {
      embeddedImage = await pdfDoc.embedJpg(imgBuffer);
    }
  }

  for (const pageNum of pagesToWatermark) {
    const pageIndex = pageNum - 1;
    if (pageIndex < 0 || pageIndex >= pageCount) continue;

    const page = pdfDoc.getPage(pageIndex);
    const { width: pageWidth, height: pageHeight } = page.getSize();
    const rotationAngle = page.getRotation().angle;
    
    const isRotated90or270 = rotationAngle === 90 || rotationAngle === 270;
    const effectiveWidth = isRotated90or270 ? pageHeight : pageWidth;
    const effectiveHeight = isRotated90or270 ? pageWidth : pageHeight;

    let opacity = options.opacity ?? 0.2;
    if (opacity > 1) {
      opacity = opacity / 100;
    }

    if (options.type === 'text' && options.text && helveticaFont) {
      const text = options.text;
      const rgbColor = hexToPdfRgb(options.color ?? '#FF0000');

      const fontSize = options.fontSize ?? 48;
      const watermarkWidth = helveticaFont.widthOfTextAtSize(text, fontSize);
      const watermarkHeight = fontSize;

      const basePos = getPdfWatermarkPosition({
        pageWidth: effectiveWidth,
        pageHeight: effectiveHeight,
        itemWidth: watermarkWidth,
        itemHeight: watermarkHeight,
        position: options.positionPreset,
        margin: 40,
        xPercent: options.xPercent,
        yPercent: options.yPercent,
      });

      const centerX = basePos.x + watermarkWidth / 2;
      const centerY = basePos.y + watermarkHeight / 2;

      const userRotation = options.rotation ?? 0;
      
      const drawPos = getCenteredDrawPosition({
        centerX,
        centerY,
        itemWidth: watermarkWidth,
        itemHeight: watermarkHeight,
        rotation: -userRotation,
      });

      let drawX = drawPos.x;
      let drawY = drawPos.y;
      let drawRotation = -userRotation;

      if (rotationAngle === 90) {
        drawX = pageWidth - drawPos.y;
        drawY = drawPos.x;
        drawRotation = -userRotation - 90;
      } else if (rotationAngle === 180) {
        drawX = pageWidth - drawPos.x;
        drawY = pageHeight - drawPos.y;
        drawRotation = -userRotation - 180;
      } else if (rotationAngle === 270) {
        drawX = drawPos.y;
        drawY = pageHeight - drawPos.x;
        drawRotation = -userRotation - 270;
      }

      page.drawText(text, {
        x: drawX,
        y: drawY,
        size: fontSize,
        font: helveticaFont,
        color: rgbColor,
        opacity,
        rotate: degrees(drawRotation)
      });
    } else if (options.type === 'image' && embeddedImage) {
      const imageSize = options.imageSize ?? 40;
      const imageAspectRatio = options.imageAspectRatio ?? 1;

      const watermarkWidth = (imageSize / 100) * effectiveWidth;
      const watermarkHeight = imageAspectRatio ? watermarkWidth / imageAspectRatio : watermarkWidth;

      const basePos = getPdfWatermarkPosition({
        pageWidth: effectiveWidth,
        pageHeight: effectiveHeight,
        itemWidth: watermarkWidth,
        itemHeight: watermarkHeight,
        position: options.positionPreset,
        margin: 40,
        xPercent: options.xPercent,
        yPercent: options.yPercent,
      });

      const centerX = basePos.x + watermarkWidth / 2;
      const centerY = basePos.y + watermarkHeight / 2;

      const userRotation = options.rotation ?? 0;

      const drawPos = getCenteredDrawPosition({
        centerX,
        centerY,
        itemWidth: watermarkWidth,
        itemHeight: watermarkHeight,
        rotation: -userRotation,
      });

      let drawX = drawPos.x;
      let drawY = drawPos.y;
      let drawRotation = -userRotation;

      if (rotationAngle === 90) {
        drawX = pageWidth - drawPos.y;
        drawY = drawPos.x;
        drawRotation = -userRotation - 90;
      } else if (rotationAngle === 180) {
        drawX = pageWidth - drawPos.x;
        drawY = pageHeight - drawPos.y;
        drawRotation = -userRotation - 180;
      } else if (rotationAngle === 270) {
        drawX = drawPos.y;
        drawY = pageHeight - drawPos.x;
        drawRotation = -userRotation - 270;
      }

      page.drawImage(embeddedImage, {
        x: drawX,
        y: drawY,
        width: watermarkWidth,
        height: watermarkHeight,
        opacity,
        rotate: degrees(drawRotation)
      });
    }
  }

  return pdfDoc.save();
}

/**
 * Extracted PDF Metadata Structure
 */
export interface PDFMetadata {
  fileName: string;
  fileSize: number;
  totalPages: number;
  title?: string;
  author?: string;
  subject?: string;
  keywords?: string;
  creator?: string;
  producer?: string;
  creationDate?: string;
  modificationDate?: string;
}

/**
 * Retrieve metadata from a PDF file.
 */
export async function viewPDFMetadata(file: File): Promise<PDFMetadata> {
  const arrayBuffer = await file.arrayBuffer();
  const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true });
  
  const title = pdfDoc.getTitle();
  const author = pdfDoc.getAuthor();
  const subject = pdfDoc.getSubject();
  const keywords = pdfDoc.getKeywords();
  const creator = pdfDoc.getCreator();
  const producer = pdfDoc.getProducer();
  const creationDate = pdfDoc.getCreationDate()?.toLocaleString();
  const modificationDate = pdfDoc.getModificationDate()?.toLocaleString();
  const totalPages = pdfDoc.getPageCount();

  return {
    fileName: file.name,
    fileSize: file.size,
    totalPages,
    title,
    author,
    subject,
    keywords,
    creator,
    producer,
    creationDate,
    modificationDate
  };
}

/**
 * Get page counts for a list of PDF files.
 */
export async function countPDFPages(
  files: File[]
): Promise<{ counts: { fileName: string; pages: number }[]; total: number }> {
  const counts: { fileName: string; pages: number }[] = [];
  let total = 0;

  for (const file of files) {
    const arrayBuffer = await readPdfFile(file);
    const pdfDoc = await PDFDocument.load(arrayBuffer, { ignoreEncryption: true, updateMetadata: false });
    const pageCount = pdfDoc.getPageCount();
    counts.push({ fileName: file.name, pages: pageCount });
    total += pageCount;
  }

  return { counts, total };
}

/**
 * Encrypt and password protect a PDF file using RC4 128-bit encryption.
 * Supports standard browser-based encryption without server dependencies.
 */
export async function protectPDFDocument(file: File, password: string): Promise<Uint8Array> {
  const arrayBuffer = await readPdfFile(file);
  const pdfBytes = new Uint8Array(arrayBuffer);
  
  // The encryptPDF function returns a Uint8Array
  const encryptedBytes = await encryptPDF(pdfBytes, password);
  return encryptedBytes;
}
